#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = std::numeric_limits<long long>::max();
    int min_idx = -1;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long operations = 0;
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile, add min_val as many times as possible
        // The current pile has a[i] candies. We want a[i] + x * min_val <= k
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, x = floor((k - a[i]) / min_val)
        if (a[i] < k) { // Only add if there's room
            operations += (k - a[i]) / min_val;
        }
    }
    std::cout << operations << std::endl;
}

