int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int num_ones = counts['n']; // 'n' is unique to "one"
    int num_zeros = counts['z']; // 'z' is unique to "zero"

    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // To maximize the binary number, we should put all '1's first, then all '0's.
    // The number of '1's is determined by the count of 'n' (from "one").
    // The number of '0's is determined by the count of 'z' (from "zero").

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
