#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n chairs such that all chosen chairs are
        // multiples of 2, and also multiples of 3.
        // This means all chosen chairs are multiples of 6.
        // If a and b are multiples of 6, then gcd(a, b) >= 6, so gcd(a, b) != 1.
        // Also, if we pick chairs that are multiples of 6, say 6k, 6(k+1), ..., 6(k+n-1),
        // then it's unlikely for one to divide another unless k is very small.
        //
        // A simpler strategy that works:
        // Pick numbers from 2n+2 up to 4n, but only even numbers.
        // The numbers are 2n+2, 2n+4, ..., 4n.
        // There are (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n such numbers.
        // All these numbers are even, so gcd(a,b) >= 2. Thus gcd(a,b) != 1.
        //
        // Now check divisibility: a divides b or b divides a.
        // Let a and b be two chosen numbers, 2n+2 <= a < b <= 4n.
        // If a divides b, then b = k * a for some integer k.
        // Since a < b, k must be >= 2.
        // So, b >= 2 * a.
        // But a >= 2n+2, so 2a >= 2(2n+2) = 4n+4.
        // This means b >= 4n+4.
        // However, all chosen numbers are <= 4n.
        // So, b cannot be >= 4n+4.
        // Therefore, a cannot divide b.
        // This strategy works.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 + 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

