#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need to perform the 'y sticks for 1 coal' trade k times.
        // This requires k * y sticks.
        // So, total sticks needed for coal and crafting = (k * y) + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks using the first trade.
        // The first trade: 1 stick -> x sticks. Net gain = x - 1 sticks.
        // Each such trade costs 1 stick.

        // Number of trades to get enough sticks:
        // Let N be the number of times we use the '1 stick for x sticks' trade.
        // We start with 1 stick.
        // After N trades, we will have 1 + N * (x - 1) sticks.
        // We need 1 + N * (x - 1) >= total_sticks_required.
        // N * (x - 1) >= total_sticks_required - 1
        // N >= (total_sticks_required - 1) / (x - 1)
        // Since N must be an integer, N = ceil((total_sticks_required - 1) / (x - 1))

        long long sticks_to_generate = total_sticks_required - 1;
        long long trades_for_sticks = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Total trades = trades for sticks + trades for coal
        // Trades for coal = k (since each coal trade gives 1 coal and we need k coal)
        long long total_trades = trades_for_sticks + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream>
