    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::set<int> claimed_rows;
    std::set<int> claimed_cols;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                claimed_rows.insert(i);
                claimed_cols.insert(j);
            }
        }
    }

    int available_rows = n - claimed_rows.size();
    int available_cols = m - claimed_cols.size();

    int num_moves = std::min(available_rows, available_cols);

    if (num_moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

