        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_days_count = 0;
        // Initialize min_price_suffix with the last day's price.
        // This variable will store the minimum price encountered
        // from the current position to the end of the array.
        int min_price_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day 'i', we compare its price 'a[i]' with the
        // minimum price found in days 'i+1' through 'n-1'.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_price_suffix) {
                // If the current day's price is greater than the minimum
                // price found later, then this day's price is "bad".
                bad_days_count++;
            } else {
                // If the current day's price is not greater than the minimum
                // price found later, it means this price is either equal to
                // or less than the minimum. In this case, this price itself
                // becomes a new candidate for the minimum price in the suffix.
                min_price_suffix = a[i];
            }
        }

        std::cout << bad_days_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is 0 (which means all a[i][j] for j!=i were 0).
    // This can only happen if n=2 and a[0][1]=0, which is not possible
    // since permutation values are 1 to n.
    // The problem guarantees a solution exists.
    // If max_val_for_i is 0, it means p[i] must be n.
    // This happens if p[i] is the largest element (n) and all other p[j] are smaller.
    // In that case, min(p[i], p[j]) = p[j].
    // If p[i] = n, then for all j != i, a[i][j] = min(n, p[j]) = p[j].
    // So max(a[i][j]) = max(p[j] for j!=i).
    // If p[i] is n, then max(p[j] for j!=i) must be n-1.
    // So p[i] would be n-1 by the current logic. This is incorrect.
    // The only case where max_val_for_i is not p[i] is when p[i] is n.
    // In that case, for all j != i, p[j] < n, so a[i][j] = p[j].
    // Thus, max(a[i][j] for j != i) = max(p[j] for j != i) = n-1.
    // So if p[i] is n, our current logic would assign p[i] = n-1.
    // We need to find if any element was assigned n-1, but should be n.
    // This happens if n is not present in the values assigned to p.

    bool n_found_in_p = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found_in_p = true;
            break;
        }
    }

    if (!n_found_in_p) {
        // If n is not found, it means one of the elements that should be n
        // was assigned n-1. We need to find which one.
        // The element that should be n is the one whose max_val_for_i was n-1,
        // and all other elements p[j] are less than n-1.
        // Or, more simply, if n is not in p, then one of the p[i] values
        // must be n-1, and that p[i] should actually be n.
        // Since the problem guarantees a solution, there will be exactly one such case.
        // We can just find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is 0 or greater, it means the frog is at cell last_r_pos.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // the distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - last_r_pos.
                // Example: last_r_pos = -1 (at 0), current 'R' at index 0 (cell 1). Distance is 1 - (-1) = 2.
                // Example: last_r_pos = 0 (at cell 1), current 'R' at index 2 (cell 3). Distance is 3 - 1 = 2.
                max_dist = std::max(max_dist, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' (or 0)
        // to the target cell n+1.
        // The distance from the last 'R' (at index last_r_pos, which is cell last_r_pos+1)
        // to cell n+1 is (n+1) - (last_r_pos + 1) + 1.
        // If last_r_pos is -1, it means no 'R' was found, so the jump is from 0 to n+1.
        // Distance is (n+1) - 0 = n+1.
        // This is covered by (s.length() + 1) - (last_r_pos + 1) + 1.
        // Example: s.length() = 7, last_r_pos = 6 (cell 7). Distance is (7+1) - (6+1) + 1 = 8 - 7 + 1 = 2.
        // Example: s.length() = 1, last_r_pos = -1 (cell 0). Distance is (1+1) - (-1+1) + 1 = 2 - 0 + 1 = 3.
        // Wait, the formula for distance is simpler.
        // If last_r_pos is -1, current position is 0. Target is n+1. Distance is (n+1) - 0 = n+1.
        // If last_r_pos is P (cell P+1), current position is P+1. Target is n+1. Distance is (n+1) - (P+1).
        // The previous logic was: max_dist = std::max(max_dist, (current_cell_idx) - (prev_cell_idx) + 1);
        // For the final jump: current_cell_idx = n+1. prev_cell_idx = last_r_pos + 1 (if last_r_pos != -1), else 0.
        // So, if last_r_pos == -1, prev_cell_idx = 0.
        // If last_r_pos != -1, prev_cell_idx = last_r_pos + 1.
        // This can be written as (last_r_pos == -1 ? 0 : last_r_pos + 1).
        // So, max_dist = std::max(max_dist, (s.length() + 1) - (last_r_pos == -1 ? 0 : last_r_pos + 1) + 1);
        // Let's simplify:
        // The distance between two consecutive 'R's (or 0 and first 'R', or last 'R' and n+1)
        // is the number of cells between them, plus one (to include the destination cell).
        // For example, from cell A to cell B, the distance is B - A.
        // If we are at cell `prev_pos` and want to jump to cell `curr_pos`, the required `d` is `curr_pos - prev_pos`.
        // We need to find the maximum such `curr_pos - prev_pos`.
        // Let `prev_r_cell` be the cell number of the previous 'R' or 0.
        // Initially, `prev_r_cell = 0`.
        // When we see 'R' at index `i`, it's cell `i+1`.
        // The distance is `(i+1) - prev_r_cell`.
        // Update `prev_r_cell = i+1`.
        // After loop, the final jump is from `prev_r_cell` to `n+1`. Distance is `(n+1) - prev_r_cell`.

        int prev_r_cell = 0;
        int current_max_d = 0;
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                int current_cell = i + 1;
                current_max_d = std::max(current_max_d, current_cell - prev_r_cell);
                prev_r_cell = current_cell;
            }
        }
        // Final jump from the last 'R' (or 0 if no 'R's) to n+1
        current_max_d = std::max(current_max_d, (int)s.length() + 1 - prev_r_cell);

        std::cout << current_max_d << "\n";
    }
    return 0;
}

