        // $C_1$ must have $k_1$ elements, $C_2$ must have $k_2$ elements, $k_1, k_2$ odd.
        //
        // Consider $C_1 = \{a_0, a_1, \dots, a_{n-2}, a_{n-1}\}$ and $C_2 =

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    bool possible = true;

    // Determine p_i for indices where q_i > q_{i-1}
    // These p_i values are fixed to q_i
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n || used_elements.count(p[0])) {
        possible = false;
    } else {
        used_elements.insert(p[0]);
    }

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_elements.count(p[i])) {
                possible = false;
                break;
            }
            used_elements.insert(p[i]);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Fill in remaining p_i values
    // These are indices where q_i == q_{i-1}
    // For these, p_i must be < q_i and not yet used.
    // We should use the largest available unused numbers that are less than q_i.
    // To do this efficiently, we can collect all unused numbers and assign them greedily.

    std::vector<int> unused_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_elements.find(i) == used_elements.end()) {
            unused_numbers.push_back(i);
        }
    }
    std::reverse(unused_numbers.begin(), unused_numbers.end()); // Largest first

    int unused_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            if (unused_idx >= unused_numbers.size()) { // Not enough unused numbers
                possible = false;
                break;
            }
            int current_val = unused_numbers[unused_idx];
            if (current_val >= q[i]) { // p_i must be < q_i
                possible = false;
                break;
            }
            p[i] = current_val;
            unused_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

