#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    std::string result = "";
    if (horizontal_moves == 0 && vertical_moves == 0) {
        // No moves possible
    } else if (horizontal_moves == 0) {
        // Only vertical moves possible, must be U then D or D then U
        // To be valid, it must be exactly "UD" or "DU"
        // If vertical_moves > 0, we can form "UD" or "DU"
        result = "UD";
    } else if (vertical_moves == 0) {
        // Only horizontal moves possible, must be L then R or R then L
        // To be valid, it must be exactly "LR" or "RL"
        // If horizontal_moves > 0, we can form "LR" or "RL"
        result = "LR";
    } else {
        // Both horizontal and vertical moves are possible
        // Construct path: U...UD...DL...LR...R
        // Or U...UL...LR...RD...D
        // The problem states "rearrange the remaining instructions as you wish"
        // A valid path can be formed by moving U, then L, then R, then D.
        // Or U, then D, then L, then R.
        // The simplest valid path that uses all available pairs is:
        // U...U (vertical_moves times)
        // L...L (horizontal_moves times)
        // R...R (horizontal_moves times)
        // D...D (vertical_moves times)
        // This path is not valid because it revisits (0,1) if vertical_moves > 1
        // and (1,0) if horizontal_moves > 1.

        // The valid path structure must be:
        // Go up (U), then right (R), then down (D), then left (L)
        // Or up (U), then left (L), then down (D), then right (R)
        // Or any combination that doesn't revisit cells.
        // The simplest valid path that uses all available pairs is:
        // U...U (vertical_moves times)
        // L...L (horizontal_moves times)
        // D...D (vertical_moves times)
        // R...R (horizontal_moves times)
        // This path is also invalid.

        // The only way to use multiple pairs of U/D and L/R is to form a rectangle.
        // For example, U R D L. This visits (0,1), (1,1), (1,0), (0,0). Valid.
        // If we have multiple U's, R's, D's, L's, say 2 of each:
        // U U R R D D L L.
        // (0,0) -> (0,1) -> (0,2) -> (1,2) -> (2,2) -> (2,1) -> (2,0) -> (1,0) -> (0,0).
        // This path is valid. It forms a rectangle.
        // So, we can use `vertical_moves` 'U's, `vertical_moves` 'D's,
        // `horizontal_moves` 'L's, and `horizontal_moves` 'R's.
        // The total length will be 2 * vertical_moves + 2 * horizontal_moves.

        for (int i = 0; i < vertical_moves; ++i) result += 'U';
        for (int i = 0; i < horizontal_moves; ++i) result += 'L';
        for (int i = 0; i < vertical_moves; ++i) result += 'D';
        for (int i = 0; i < horizontal_moves; ++i) result += 'R';
    }

    std::cout << result.length() << "\n";
    std::cout << result << "\n";
}

