        // The number of points available to form a pair (x_j, x_k) with x_i
        // is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m is m * (m - 1) / 2.

        // Ensure m is non-negative. If right_ptr - 1 <= i, then m <= 0.
        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array of odd length n, median is at n/2

    // First, ensure the median element itself is s
    operations += std::abs(a[median_idx] - s);

    // Then, ensure elements to the left of median are <= s
    // If a[i] > s, we must decrease it to s. Cost is a[i] - s.
    // If a[i] <= s, no change is needed for the median property.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Finally, ensure elements to the right of median are >= s
    // If a[i] < s, we must increase it to s. Cost is s - a[i].
    // If a[i] >= s, no change is needed for the median property.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

