#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The problem asks for the rearranged A' values, not their original indices.
    // We need to store the A values that correspond to the original B indices.
    std::vector<long long> result_a_prime(m);

    // To maximize sum F(A'_i, B_i), we pair largest A with largest B,
    // second largest A with second largest B, and so on.
    // Since A is sorted ascending, a_elements[i].value is the (i+1)-th smallest A.
    // Since B is sorted ascending, b_elements[i].value is the (i+1)-th smallest B.
    // We want to pair a_elements[i].value with b_elements[i].value.
    // The original index of b_elements[i] is b_elements[i].original_index.
    // So, result_a_prime[b_elements[i].original_index] should be a_elements[i].value.
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

