// Function to check if a prefix of length `len` is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_prefix[len - 1] != len) return false; // Max element must be equal to length
    // Check for duplicates using frequency array or bitset if needed, but max_prefix check is usually enough
    // if elements are 1 to len.
    // The precomputed `is_perm_prefix` array handles this.
    return true;
}

// Function to check if a suffix of length `len` is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_suffix[n - len] != len) return false; // Max element must be equal to length
    // The precomputed `is_perm_suffix` array handles this.
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max_prefix[i] = max(a[0]...a[i])
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
    }

    // Precompute max_suffix[i] = max(a[i]...a[n-1])
    std::vector<int> max_suffix(n);
    max_suffix[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute `is_perm_prefix[i]` = true if a[0...i] is a permutation of length i+1
    std::vector<bool> is_perm_prefix(n + 1, false); // is_perm_prefix[len]
    std::vector<bool> seen_prefix(n + 1, false); // Using n+1 for 1-based indexing
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > i + 1 || seen_prefix[val]) { // val > current length or duplicate
            possible_prefix = false;
        }
        seen_prefix[val] = true;
        current_max_prefix = std::max(current_max_prefix, val);
        if (possible_prefix && current_max_prefix == i + 1) {
            is_perm_prefix[i + 1] = true;
        }
    }

    // Precompute `is_perm_suffix[i]` = true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> is_perm_suffix(n + 1, false); // is_perm_suffix[len]
    std::vector<bool> seen_suffix(n + 1, false); // Using n+1 for 1-based indexing
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        int val = a[i];
        if (val > len || seen_suffix[val]) { // val > current length or duplicate
            possible_suffix = false;
        }
        seen_suffix[val] = true;
        current_max_suffix = std::max(current_max_suffix, val);
        if (possible_suffix && current_max_suffix == len) {
            is_perm_suffix[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_perm_prefix[l1] && is_perm_suffix[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

