char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaker works here.
        // R, P, S is a common order for RPS.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }

        // If all counts are 0 (empty string, though constraints say n >= 1),
        // or if there's a tie and we need a specific tie-breaker,
        // the current logic picks one. For example, if R=1, P=1, S=1,
        // it will pick S due to the order of if statements.
        // However, the problem implies n >= 1, so at least one char exists.
        // The specific tie-breaker doesn't matter for correctness, as any
        // most frequent character will yield the same maximum average.

        char optimal_response = get_winning_move(most_frequent_char);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << optimal_response;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Handle friends with w_i = 1 first.
    // These friends contribute 2 * (largest available number) to happiness.
    // Assign the largest available numbers to them.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // Break and handle them in the next loop.
            break;
        }
    }

    // Handle friends with w_i > 1.
    // These friends contribute (largest available number) + (smallest available number) to happiness.
    // To maximize sum of happiness:
    // - Assign the largest remaining numbers as max_val for each friend.
    // - Assign the smallest remaining numbers as min_val for each friend.
    // The friends with larger w_i values will "consume" more small numbers.
    // To maximize the sum of minimums, we want to use the largest possible small numbers.
    // So, friends with larger w_i should get the smallest available numbers.
    // Since w is sorted ascending, we iterate from smallest w_i to largest w_i.
    // The smallest w_i (that are > 1) will get the largest available minimums.
    // The largest w_i will get the smallest available minimums.
    // The largest available numbers (for max_val) are assigned from a_ptr_right downwards.
    // The smallest available numbers (for min_val) are assigned from a_ptr_left upwards.

    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;
            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w[i]-1 smallest numbers for this friend
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 (at most 3) such that
    // (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)

    // Strategy: Append two elements.
    // Let the two elements be X and Y.
    // We want (current_sum + X + Y) = 2 * (current_xor_sum ^ X ^ Y)
    // A simple choice for X and Y is to make current_xor_sum ^ X ^ Y = current_xor_sum.
    // This happens if X ^ Y = 0, i.e., X = Y.
    // Let X = Y = current_xor_sum.
    // Then the new XOR sum is current_xor_sum ^ current_xor_sum ^ current_xor_sum = current_xor_sum.
    // The new sum is current_sum + current_xor_sum + current_xor_sum = current_sum + 2 * current_xor_sum.
    // The condition becomes: current_sum + 2 * current_xor_sum = 2 * current_xor_sum.
    // This simplifies to current_sum = 0. This is not generally true.

    // Let's try to make the final XOR sum equal to current_xor_sum.
    // This means we need to append elements whose XOR sum is 0.
    // For example, append X and X.
    // New sum: current_sum + 2X
    // New XOR sum: current_xor_sum ^ X ^ X = current_xor_sum
    // Condition: current_sum + 2X = 2 * current_xor_sum
    // 2X = 2 * current_xor_sum - current_sum
    // X = current_xor_sum - current_sum / 2
    // This requires current_sum to be even, and current_xor_sum - current_sum / 2 to be non-negative.
    // This strategy is not guaranteed to work because current_sum might be odd, or X might be negative.

    // A guaranteed strategy (always works with at most 2 elements):
    // Let the current XOR sum be X_curr and current sum be S_curr.
    // We want to append two numbers, say A and B.
    // New XOR sum: X_new = X_curr ^ A ^ B
    // New sum: S_new = S_curr + A + B
    // We need S_new = 2 * X_new.

    // Let's try to make X_new = X_curr. This means A ^ B = 0, so A = B.
    // Then S_curr + 2A = 2 * X_curr.
    // 2A = 2 * X_curr - S_curr.
    // This requires (2 * X_curr - S_curr) to be non-negative and even.
    // If S_curr is odd, then (2 * X_curr - S_curr) is odd, so A cannot be an integer.
    // If S_curr is even, then (2 * X_curr - S_curr) is even. Let A = X_curr - S_curr / 2.
    // If A >= 0, this works. We append A, A.

    // What if S_curr is odd?
    // We need to append at least one number to make the sum even.
    // Let's append X_curr.
    // New sum: S_curr + X_curr
    // New XOR sum: X_curr ^ X_curr = 0
    // Now we have a new array with sum S' = S_curr + X_curr and XOR sum X' = 0.
    // We need to append more elements to make S' = 2 * X'.
    // Since X' = 0, we need S' = 0.
    // This means S_curr + X_curr = 0. This is not generally true.

    // Let's use the strategy from a common competitive programming trick:
    // Append X_curr.
    // The new XOR sum becomes X_curr ^ X_curr = 0.
    // The new sum becomes S_curr + X_curr.
    // Now we have an array with sum S' = S_curr + X_curr and XOR sum X' = 0.
    // We need to append one more element, say Z, such that:
    // (S' + Z) = 2 * (X' ^ Z)
    // (S_curr + X_curr + Z) = 2 * (0 ^ Z)
    // (S_curr + X_curr + Z) = 2 * Z
    // S_curr + X_curr = Z
    // So, we append Z = S_curr + X_curr.
    // The elements to append are X_curr and (S_curr + X_curr).
    // This uses 2 elements.
    // Both X_curr and S_curr + X_curr are non-negative since all initial a_i are non-negative.
    // This strategy always works.

    // Let's verify this strategy:
    // Initial: sum = S_curr, xor_sum = X_curr
    // Append X_curr:
    //   New sum = S_curr + X_curr
    //   New xor_sum = X_curr ^ X_curr = 0
    // Append (S_curr + X_curr):
    //   Final sum = (S_curr + X_curr) + (S_curr + X_curr) = 2 * (S_curr + X_curr)
    //   Final xor_sum = 0 ^ (S_curr + X_curr) = S_curr + X_curr
    // Check condition: Final sum = 2 * Final xor_sum
    //   2 * (S_curr + X_curr) = 2 * (S_curr + X_curr)
    // This is always true.

    // So, we append 2 elements: X_curr and (S_curr + X_curr).
    // The problem states "at most 3 elements". This strategy uses 2.
    // The problem also says "If an array is good already you are allowed to not append elements."
    // But we don't have to minimize. So we can always append 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

