    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    long long current_score = 0;
    int wins = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            wins++;
            if (i > 0 && s[i-1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }

    if (k == 0) {
        std::cout << current_score << std::endl;
        return;
    }

    if (wins == 0) { // All L's
        if (k >= 1) {
            std::cout << std::min((long long)n, k) * 2 - 1 << std::endl;
        } else { // k=0, handled above
            std::cout << 0 << std::endl;
        }
        return;
    }

    // If we reach here, there's at least one 'W' initially.
    // We want to convert 'L's to 'W's.
    // Each 'L' converted to 'W' costs 1 k.
    // If it's an isolated 'L' (L W L), converting it to 'W' (W W L) gives +1 point.
    // If it's an 'L' between two 'W's (W L W), converting it to 'W' (W W W) gives +2 points.
    // If it's an 'L' at the start/end (L W... or ...W L), converting it to 'W' gives +1 point.

    // Strategy:
    // 1. Convert 'L's to 'W's that are between two 'W's (W L W -> W W W). These give +2 points.
    //    These are the most efficient conversions.
    // 2. Convert 'L's to 'W's at the ends of the string or adjacent to a single 'W'. These give +1 point.

    std::vector<int> gaps;
    int first_W = -1, last_W = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_W == -1) first_W = i;
            last_W = i;
        }
    }

    // Fill gaps between W's
    if (first_W != -1) { // If there's at least one W
        int current_L_count = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_L_count++;
            } else { // s[i] == 'W'
                if (current_L_count > 0) {
                    gaps.push_back(current_L_count);
                }
                current_L_count = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += gap_len * 2 + 1; // Each L becomes W, connects two Ws, adds 2 points. The first L in the gap connects, adds 1+2*(gap_len-1) + 2 = 2*gap_len+1
                                                  // No, it's simpler: each L converted adds 2 points, except the first one in a block of Ls that connects two Ws.
                                                  // W L L L W -> W W W W W.
                                                  // The original score for W...W is 1+2*(num_W-1).
                                                  // If we fill a gap of `g` L's, we add `g` W's.
