            if (n % 2 != 0) { // N is odd
                // Opponent takes 1
                n -= 1;
            } else { // N is even
                // Opponent takes N/2
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

// The simplified logic is correct.
// The `opponent_coins` variable is not actually needed, as we only need Chanek's coins.
// The total coins are N, so Chanek's coins + Opponent's coins = initial N.
// But the game state changes, so it's not simply initial N.
// We need to track Chanek's coins explicitly.

// Final check on constraints: N up to 10^18, so long long is necessary.
// T up to 10^5. The loop `while (n > 0)` runs at most log N times (if always N/2) or N times (if always -1).
// But it's a mix. If N is odd, it becomes even. If N is even, it becomes N/2.
// The number of steps is roughly log N.
// For N=10^18, log2(10^18) is about 60

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available number and the largest available number
    // from the range [1, k+1].
    // For example, if k=2, range is [1, 3].
    // p[0] = 1 (left)
    // p[1] = 3 (right) -> diff = |1-3|=2
    // p[2] = 2 (left)  -> diff = |3-2|=1
    // This generates differences 2, 1.
    // For k=3, range is [1, 4].
    // p[0] = 1 (left)
    // p[1] = 4 (right) -> diff = |1-4|=3
    // p[2] = 2 (left)  -> diff = |4-2|=2
    // p[3] = 3 (right) -> diff = |2-3|=1
    // This generates differences 3, 2, 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left++;
        } else {
            p[i] = right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // Append them in increasing order to ensure the differences are 1.
    // This does not introduce new distinct differences if k >= 1.
    // If k=1, the first part is p[0]=1, p[1]=2. Remaining are 3,4,...,n.
    // p becomes 1, 2, 3, 4, ..., n. All differences are 1.
    // If k > 1, the last difference generated in the first loop was 1.
    // For example, if k=2, p[0]=1, p[1]=3, p[2]=2.
    // The last element is p[2]=2.
    // Remaining numbers are 4, 5, ..., n.
    // Append 4, 5, ..., n.
    // p becomes 1, 3, 2, 4, 5, ..., n.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1, ...
    // The new differences are 1 or 2, which are already in the set {1, 2}.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

