#include <algorithm>
#include <cmath>
#include <map>

long long get_prime_factor_power(long long n, long long p) {
    if (p == 0 || p == 1) return 0; // Should not happen with prime factors
    long long count = 0;
    while (n > 0 && n % p == 0) {
        count++;
        n /= p;
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting number is no longer divisible by q.

        // Find prime factors of q
        std::map<long long, long long> q_prime_factors;
        long long temp_q = q;
        for (long long i = 2; i * i <= temp_q; ++i) {
            if (temp_q % i == 0) {
                while (temp_q % i == 0) {
                    q_prime_factors[i]++;
                    temp_q /= i;
                }
            }
        }
        if (temp_q > 1) {
            q_prime_factors[temp_q]++;
        }

        long long max_x = 0;

        // For each prime factor f of q, we try to remove enough factors of f from p
        // such that p / (f^k) is no longer divisible by q.
        // We want to maximize p / (f^k), so we remove the minimum necessary factors.
        for (auto const& [f, q_power] : q_prime_factors) {
            long long p_val = p;
            long long current_p_power_of_f = 0;
            while (p_val > 0 && p_val % f == 0) {
                current_p_power_of_f++;
                p_val /= f;
            }

            // If p has fewer factors of f than q, then p is not divisible by q, which contradicts the initial check.
            // So p_power_of_f must be >= q_power.
            // We need to reduce the power of f in p such that it's less than q_power.
            // The smallest number of factors of f to remove is (p_power_of_f - q_power + 1).
            // This means we divide p by f^(p_power_of_f - q_power + 1).

            long long num_factors_to_remove = current_p_power_of_f - q_power + 1;
            long long divisor_for_f = 1;
            for(int i = 0; i < num_factors_to_remove; ++i) {
                divisor_for_f *= f;
            }

            max_x = std::max(max_x, p / divisor_for_f);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int correct_sequence_length = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            correct_sequence_length = 1;
            for (int j = 1; j < m; ++j) {
                if (chain[j] == chain[j - 1] + 1) {
                    correct_sequence_length++;
                } else {
                    break; // Sequence broken
                }
            }
        }
    }

    // Total operations = (n - 1) put operations + (n - k) take out operations
    // This is the total number of nesting changes.
    // (n - 1) is the number of required nestings in the final chain.
    // (n - k) is the number of existing nestings in the initial configuration.
    // The total number of operations is the sum of operations to break existing
    // incorrect nestings and operations to form new correct nestings.
    // Each "take out" operation costs 1.
    // Each "put in" operation costs 1.

    // The number of matryoshkas that are already in their correct place
    // and form a continuous sequence starting from 1.
    // These matryoshkas (1, 2, ..., correct_sequence_length) do not need to be touched.
    // They are already nested correctly.
    // So, we don't need to take them out, and we don't need to put them in.

    // Number of matryoshkas that are NOT part of the initial correct sequence 1->2->...->L
    // These are n - correct_sequence_length matryoshkas.
    // Each of these must be taken out of whatever they are in (if anything)
    // and then put into their correct place.
    // So, for each of these, we need 2 operations: 1 take out, 1 put in.
    // Total operations for these: 2 * (n - correct_sequence_length).

    // However, the problem statement implies that "take out" operations are only
    // for matryoshkas directly contained in an unnested matryoshka.
    // And "put in" operations are for a single matryoshka into another single matryoshka.
    // This means to move a matryoshka `x` from `x -> y -> z` to `x -> w`,
    // we first need to take `y` out of `z`, then `x` out of `y`.
    // This is equivalent to disassembling all chains into individual matryoshkas,
    // then reassembling them.

    // Let's re-evaluate based on the operations:
    // To get `a` out of `b` where `a` is in `b`, `b` is not nested: 1 op.
    // To put `a` in `b` where `a` is not nested, `b` is not nested and contains nothing: 1 op.

    // The total number of matryoshkas is `n`.
    // The number of chains is `k`.
    // The number of existing nesting relationships is `n - k`.
    // To disassemble all chains into individual matryoshkas:
    // We need to perform `n - k` "take out" operations.
    // For example, if we have `1 -> 2 -> 3`, we take `2` out of `3` (1 op), then `1` out of `2` (1 op).
    // This costs `m_i - 1` operations for each chain `i`. Summing over all chains, this is `n - k` operations.

    // After disassembling, we have `n` individual matryoshkas.
    // To assemble `1 -> 2 -> ... -> n`:
    // We need to perform `n - 1` "put in" operations.
    // Put 1 in 2, then put 2 in 3, ..., put n-1 in n.
    // This costs `n - 1` operations.

    // So, a naive approach would be `(n - k) + (n - 1)` operations.
    // This is `2n - k - 1`.

    // However, we can save operations if some part of the chain `1 -> 2 -> ... -> n`
    // already exists in the initial configuration.
    // Specifically, if we have `1 -> 2 -> ... -> L` as a prefix of one of the initial chains,
    // these `L` matryoshkas are already correctly nested relative to each other.
    // We don't need to take them out of each other, nor put them into each other.

    // The `correct_sequence_length` is `L`.
    // These `L` matryoshkas (1, 2, ..., L) are already in their final relative positions.
    // They form a single unit `1 -> 2 -> ... -> L`.
    // The number of internal nesting operations saved for this segment is `L - 1`.
    // So, we save `L - 1` "take out" operations and `L - 1` "put in" operations.
    // Total saved operations: `2 * (L - 1)`.

    // The total number of operations is:
    // (Total operations if everything was disassembled and reassembled)
    // - (Operations saved due to the existing correct prefix)
    // = ( (n - k) + (n - 1) ) - (2 * (correct_sequence_length - 1))

    // Let's verify this.
    // Operations to take out:
    // Total existing nestings: `n - k`.
    // Nestings within the correct prefix `1 -> ... -> L`: `L - 1`.
    // These `L - 1` nestings do not need to be broken.
    // So, "take out" operations needed: `(n - k) - (L - 1)`.

    // Operations to put in:
    // Total required nestings: `n - 1`.
    // Nestings within the correct prefix `1 -> ... -> L`: `L - 1`.
    // These `L - 1` nestings do not need to be created.
    // So, "put in" operations needed: `(n - 1) - (L - 1)`.

    // Total operations = `((n - k) - (L - 1)) + ((n - 1) - (L - 1))`
    // = `n - k - L + 1 + n - 1 - L + 1`
    // = `2n - k - 2L + 1`

    // Let's check the formula `( (n - k) + (n - 1) ) - (2 * (correct_sequence_length - 1))`
    // = `n - k + n - 1 - 2 * L + 2`
    // = `2n - k - 2L + 1`.
    // The formulas match.

    // Example 1: n=3, k=2. Chains: 2 1 2; 1 3.
    // correct_sequence_length = 2 (for 1->2).
    // Total ops = (2*3 - 2 - 2*2 + 1) = 6 - 2 - 4 + 1 = 1. Correct.

    // Example 2: n=7, k=3. Chains: 3 1 3 7; 2 2 5; 2 4 6.
    // correct_sequence_length = 1 (only 1 is present, but 1->2 is not).
    // Total ops = (2*7 - 3 - 2*1 + 1) = 14 - 3 - 2 + 1 = 10. Correct.

    total_operations = (long long)2 * n - k - 2 * correct_sequence_length + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

