void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string coloring(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;

        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot) {
                coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > pivot) {
                coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == pivot
                // Try to assign to S1 first, if it maintains sorted order
                if (!s1_digits.empty() && s1_digits.back() > d[i]) {
                    // Cannot assign to S1, must assign to S2
                    coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    // Can assign to S1
                    coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Check if S2 is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Check if max(S1) <= min(S2)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_pivot = false;
            }
        }

        if (possible_pivot) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

