void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each position modulo k

    // Step 1: Propagate constraints from existing '0's and '1's
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int rem = i % k;
            if (fixed_chars[rem] == '?') {
                fixed_chars[rem] = s[i];
            } else if (fixed_chars[rem] != s[i]) {
                // Conflict: s[i] contradicts a previously determined character for this remainder
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count '0's, '1's, and '?'s among the fixed_chars
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else {
            count_q++;
        }
    }

    // Step 3: Check if it's possible to satisfy k/2 zeros and k/2 ones
    // We need k/2 zeros and k/2 ones in total for the first k characters (and thus all k-length substrings)
    // If count0 already exceeds k/2, it's impossible.
    // If count1 already exceeds k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // We have count_q '?'s remaining.
    // We need (k/2 - count0) more zeros and (k/2 - count1) more ones.
    // The sum of these needed counts must be equal to count_q.
    // (k/2 - count0) + (k/2 - count1) = k - count0 - count1.
    // Since count0 + count1 + count_q = k, we have k - count0 - count1 = count_q.
    // So, if count0 <= k/2 and count1 <= k/2, it's always possible to fill the '?'s
    // to meet the k/2 requirement for the first k characters.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

