#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Sum of k for 1 <= k <= a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r for 1 <= r < b: (b - 1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The sum is sum_{k=1 to a} sum_{r=1 to b-1} (r * (k * b + 1))
    // = sum_{k=1 to a} sum_{r=1 to b-1} (r * k * b + r)
    // = sum_{k=1 to a} (k * b * sum_{r=1 to b-1} r + sum_{r=1 to b-1} r)
    // = sum_{k=1 to a} ((k * b + 1) * sum_{r=1 to b-1} r)
    // = (sum_{r=1 to b-1} r) * sum_{k=1 to a} (k * b + 1)
    // = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + sum_{k=1 to a} 1)
    // = (sum_r) * (b * sum_k + a)

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long term_a = a % MOD;
    long long inner_sum = (term_b_sum_k + term_a) % MOD;

    long long total_sum = (sum_r * inner_sum) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        if (dq.empty()) {
            L[i] = i + 1;
        } else {
            L[i] = i - dq.back();
        }
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        if (dq.empty()) {
            R[i] = n - i;
        } else {
            R[i] = dq.back() - i;
        }
        dq.push_back(i);
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min({h[i], L[i], R[i]}));
    }

    std::cout << max_k << std::endl;

    return 0;
}

