        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(i + k, n);

        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
