int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    } else {
        // Operation 1: For elements a[0] to a[n-2], make them divisible by n.
        // This is done by adding a multiple of n to each a[i] such that a[i] % n == 0.
        // The segment is [1, n-1], length is n-1.
        // We need to add a multiple of (n-1).
        // Let's use the segment [1, n-1] to make a[0]...a[n-2] divisible by n.
        // For each a[i] (0 <= i < n-1), we want to add x_i such that (a[i] + x_i) % n == 0.
        // This means x_i % n == (-a[i]) % n.
        // We also need x_i to be a multiple of (n-1).
        // So, x_i = k * (n-1) for some integer k.
        // We need k * (n-1) % n == (-a[i]) % n.
        // Since (n-1) % n == -1 % n, this becomes k * (-1) % n == (-a[i]) % n.
        // So, -k % n == (-a[i]) % n, which implies k % n == a[i] % n.
        // We can choose k = a[i] % n. If a[i] % n is negative, add n to make it positive.
        // So, k = (a[i] % n + n) % n.
        // Then x_i = ((a[i] % n + n) % n) * (n-1).
        // This x_i is a multiple of (n-1) and (a[i] + x_i) will be divisible by n.

        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // a[i] % n, ensuring positive
            long long add_val = remainder * (n - 1);
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val; // Update a[i]
        }
        std::cout << "\n";

        // At this point, a[0], ..., a[n-2] are all divisible by n.
        // a[n-1] is unchanged.

        // Operation 2: For the last element a[n-1], make it divisible by n.
        // Segment is [n, n], length is 1.
        // We need to add a multiple of 1.
        // Add -a[n-1] to a[n-1].
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0; // Update a[n-1]

        // At this point, a[0], ..., a[n-2] are divisible by n, and a[n-1] is 0.

        // Operation 3: For all elements a[0] to a[n-1], make them zero.
        // Segment is [1, n], length is n.
        // For each a[i], we know it's divisible by n (a[n-1] is 0, others were made divisible by n).
        // We need to add x_i such that (a[i] + x_i) == 0.
        // So x_i = -a[i].
        // Since a[i] is divisible by n, -a[i] is also divisible by n.
        // So we can just add -a[i] to each element.
        std::cout << 1 << " " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

