int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val0 = 0;
    int current_val1023 = 1023; // 0b1111111111

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val0 &= x;
            current_val1023 &= x;
        } else if (op_char == '|') {
            current_val0 |= x;
            current_val1023 |= x;
        } else if (op_char == '^') {
            current_val0 ^= x;
            current_val1023 ^= x;
        }
    }

    int final_and_mask = 1023; // All bits set
    int final_or_mask = 0;     // All bits clear
    int final_xor_mask = 0;    // All bits clear

    for (int j = 0; j < 10; ++j) {
        int bit_val0 = (current_val0 >> j) & 1;
        int bit_val1023 = (current_val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) {
            // Input bit 0 -> 0, Input bit 1 -> 0
            // This means the output bit is always 0, regardless of input.
            // So, we must AND with 0 for this bit.
            final_and_mask &= ~(1 << j);
        } else if (bit_val0 == 1 && bit_val1023 == 1) {
            // Input bit 0 -> 1, Input bit 1 -> 1
            // This means the output bit is always 1, regardless of input.
            // So, we must OR with 1 for this bit.
            final_or_mask |= (1 << j);
        } else if (bit_val0 == 0 && bit_val1023 == 1) {
            // Input bit 0 -> 0, Input bit 1 -> 1
            // This means the output bit is the same as the input bit.
            // No change needed for this bit in AND/OR/XOR masks.
        } else { // bit_val0 == 1 && bit_val1023 == 0
            // Input bit 0 -> 1, Input bit 1 -> 0
            // This means the output bit is the inverse of the input bit.
            // So, we must XOR with 1 for this bit.
            final_xor_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

