void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_balance = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance_L[k] = balance of jars a[k]...a[n-1]
    // This is equivalent to balance of jars a[0]...a[n-1] minus balance of jars a[0]...a[k-1]
    // Let's use balance_L[k] = balance of jars a[0]...a[k-1]
    // So, if we keep jars from index k to n-1, the balance is initial_balance_left - balance_L[k]
    // where initial_balance_left is balance of a[0]...a[n-1]

    // Let's define balance_L[k] as the balance of jars a[0]...a[k-1]
    // and balance_R[k] as the balance of jars a[k]...a[2n-1]
    // We are interested in the balance of remaining jars.
    // If we remove i jars from left and j jars from right:
    // Remaining jars are a[i]...a[n-1] and a[n]...a[2n-1-j]
    // The number of jars removed is i+j.
    // The balance of remaining jars is (balance of a[0]...a[2n-1]) - (balance of a[0]...a[i-1]) - (balance of a[2n-j]...a[2n-1])
    // Let's define prefix_balance[k] = balance of jars a[0]...a[k-1]
    // Let's define suffix_balance[k] = balance of jars a[k]...a[2n-1]
    // Note that suffix_balance[k] = initial_balance - prefix_balance[k]

    // We need to find min(i+j) such that
    // initial_balance - (balance of a[0]...a[i-1]) - (balance of a[2n-j]...a[2n-1]) == 0
    // This means (balance of a[0]...a[i-1]) + (balance of a[2n-j]...a[2n-1]) == initial_balance

    // Let's precompute balances for segments starting from the left and ending at the right.
    // `left_balances[k]` will store the balance of jars `a[0]...a[k-1]`
    // `right_balances[k]` will store the balance of jars `a[k]...a[2n-1]`

    // Balances for segments removed from the left:
    // `bal_left_removed[k]` = balance of jars `a[0]...a[k-1]` (i.e., `k` jars removed from left)
    // `k` ranges from `0` to `n`.
    // `bal_left_removed[0]` = 0 (no jars removed)
    // `bal_left_removed[k]` = `bal_left_removed[k-1]` + (a[k-1]==1 ? 1 : -1) for `k > 0`
    std::vector<int> bal_left_removed(n + 1);
    bal_left_removed[0] = 0;
    for (int k = 1; k <= n; ++k) {
        bal_left_removed[k] = bal_left_removed[k - 1] + (a[k - 1] == 1 ? 1 : -1);
    }

    // Balances for segments removed from the right:
    // `bal_right_removed[k]` = balance of jars `a[2n-k]...a[2n-1]` (i.e., `k` jars removed from right)
    // `k` ranges from `0` to `n`.
    // `bal_right_removed[0]` = 0 (no jars removed)
    // `bal_right_removed[k]` = `bal_right_removed[k-1]` + (a[2n-k]==1 ? 1 : -1) for `k > 0`
    std::vector<int> bal_right_removed(n + 1);
    bal_right_removed[0] = 0;
    for (int k = 1; k <= n; ++k) {
        bal_right_removed[k] = bal_right_removed[k - 1] + (a[2 * n - k] == 1 ? 1 : -1);
    }

    // We need to find min(i+j) such that
    // initial_balance - bal_left_removed[i] - bal_right_removed[j] == 0
    // This is equivalent to bal_left_removed[i] + bal_right_removed[j] == initial_balance

    // Store the minimum number of jars removed from the right (j) for each possible balance `bal_right_removed[j]`
    // `min_j_for_balance[balance_value]` = minimum `j` that results in `balance_value`
    std::map<int, int> min_j_for_balance;
    for (int j = 0; j <= n; ++j) {
        int current_balance = bal_right_removed[j];
        if (min_j_for_balance.find(current_balance) == min_j_for_balance.end()) {
            min_j_for_balance[current_balance] = j;
        } else {
            min_j_for_balance[current_balance] = std::min(min_j_for_balance[current_balance], j);
        }
    }

    int min_total_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible `i` (jars removed from left)
    for (int i = 0; i <= n; ++i) {
        int target_right_balance = initial_balance - bal_left_removed[i];
        if (min_j_for_balance.count(target_right_balance)) {
            int j = min_j_for_balance[target_right_balance];
            min_total_removed = std::min(min_total_removed, i + j);
        }
    }

    std::cout << min_total_removed << std::endl;
}

