}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
        // This is achieved by making the blocks of '0's as equal in length as possible.
        // We have n-m zeros to distribute among m+1 blocks (separated by '1's or at ends).

        long long num_zeros = n - m;

        // If m=n, there are no zeros, so no substrings of all '0's.
        // This case is handled by num_zeros = 0, which results in zero_substrings = 0.

        // Number of blocks of zeros is m+1.
        // Distribute num_zeros as evenly as possible into m+1 blocks.
        // Let k be the base length of each block.
        // Let r be the number of blocks that get an extra zero.

        long long k = num_zeros / (m + 1); // Base length for each block
        long long r = num_zeros % (m + 1); // Number of blocks with length k+1

        // r blocks will have length k+1
        // (m+1 - r) blocks will have length k

        long long zero_substrings = 0;

        // Contribution from blocks of length k+1
        if (k + 1 > 0) { // Only count if block length is positive
            zero_substrings += r * ((k + 1) * (k + 2) / 2);
        }

        // Contribution from blocks of length k
        if (k > 0) { // Only count if block length is positive
            zero_substrings += (m + 1 - r) * (k * (k + 1) / 2);
        }

        long long max_f_s = total_substrings - zero_substrings;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

const long long INF = 1e18; // A sufficiently large value for infinity

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently "active"

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added back

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // Consider k as an intermediate vertex for all pairs (i, j)
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] != INF && dist[k][j] != INF) {
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // After adding k and updating paths through k,
        // update paths between all *currently active* vertices
        // using k as an intermediate.
        // This is the standard Floyd-Warshall triple loop, but restricted to active vertices.
        // The previous loop already updated dist[i][j] using k as an intermediate.
        // Now we need to ensure all pairs of active vertices consider all other active vertices
        // (including k) as intermediates.
        // The order of loops matters for correctness.
        // The standard Floyd-Warshall is: for k, for i, for j.
        // Here, k is the *newly added* vertex.
        // So, we first update paths involving k as an endpoint or intermediate.
        // Then, we iterate over all active vertices to sum up shortest paths.
        // The `dist` matrix now contains shortest paths considering all vertices
        // that have been marked `active` so far.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then increment by d to ensure separation

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // Since X can be up to 10^9, X+1 can be up to 10^9+1.
        // log2(10^9) is approx 29.89. So k can be at most 29.
        // We can iterate k from 29 down to 1.
        for (int i = 29; i >= 1; --i) { // Max k is 29 for X=2^30-1
            if ((1LL << i) - 1 <= X) {
                k = i;
                break;
            }
        }

        if (k == 0) { // This means X is 0, or X is 1. If X is 1, k should be 1.
                      // If X is 1, (1LL << 1) - 1 = 1, so k=1.
                      // This branch should not be reached if X >= 1.
            break;
        }

        // Add k elements of current_val to the array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        X -= ((1LL << k) - 1);

        // Increment current_val by d + 1 to ensure that any subsequence
        // containing elements from previous groups and this group will have
        // max - min >= d.
        // The smallest element in the new group is current_val + d + 1.
        // The largest element in the previous group is current_val.
        // (current_val + d + 1) - current_val = d + 1 >= d.
        // This ensures that subsequences spanning across these groups are removed.
        current_val += (d + 1);
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a_initial(n, 0); // We can initialize a_initial to 0
    std::vector<long long> current_a(n);

    // Step 1: Determine upper bounds for a_initial[i]
    // For each type 2 query (l, r, m), we know that for all j in [l, r],
    // a_initial[j] + sum_of_d_affecting_j_before_this_query <= m.
    // This means a_initial[j] <= m - sum_of_d_affecting_j_before_this_query.
    // We want to find the tightest upper bound for each a_initial[j].
    // Initialize a_initial[j] to a very large value (effectively infinity).
    // Then, for each type 2 query, update a_initial[j] = min(a_initial[j], m - sum_of_d_affecting_j).

    std::vector<long long> current_delta(n, 0); // sum of d values applied so far
    std::vector<long long> max_val_at_idx(n, std::numeric_limits<long long>::max());

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // op.type == 2
            for (int j = op.l; j <= op.r; ++j) {
                max_val_at_idx[j] = std::min(max_val_at_idx[j], op.val - current_delta[j]);
            }
        }
    }

    // The reconstructed initial array is max_val_at_idx.
    // Let's call it `b` to avoid confusion with `a_initial` which was initialized to 0.
    // `b[i]` is the maximum possible value for `a_initial[i]` that satisfies all `a_initial[i] + delta[i] <= m` constraints.
    // If a solution exists, this `b` array is a valid initial array.
    // We need to verify if this `b` array satisfies all `max(a_initial[j] + delta[j]) == m` constraints.
    // Specifically, for each type 2 query (l, r, m), we must have:
    // 1. max_{j=l}^{r} (b[j] + delta[j]) == m
    // 2. b[j] + delta[j] <= m for all j in [l, r] (this is guaranteed by construction of b)

    // Reset current_delta for verification
    std::fill(current_delta.begin(), current_delta.end(), 0);

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // op.type == 2
            long long current_max = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                current_max = std::max(current_max, max_val_at_idx[j] + current_delta[j]);
            }
            if (current_max != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << max_val_at_idx[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v; // cry volume in office
    long long d; // cry volume in hall
    long long p; // confidence
    bool in_line; // true if still in line
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left the line
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child goes to doctor, no longer in line

        long long current_v_reduction = children[i].v;
        long long d_chain_reaction_sum = 0; // Sum of d values from children leaving due to chain reaction

        // Apply reductions to children after the current one
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply reduction from the child currently being treated
            if (current_v_reduction > 0) {
                children[j].p -= current_v_reduction;
                current_v_reduction = std::max(0LL, current_v_reduction - 1);
            }

            // Apply reduction from children who left due to chain reaction
            children[j].p -= d_chain_reaction_sum;

            // Check if child j's confidence dropped below zero
            if (children[j].p < 0) {
                d_chain_reaction_sum += children[j].d;
                children[j].in_line = false; // Child j leaves the line
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m for simpler logic, as the problem is symmetric
        if (n > m) {
            std::swap(n, m);
        }

        // Case 1: k < m (or k < n, since n <= m)
        // It's impossible to reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move changes a coordinate by at most 1.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= m
        // We can always reach (n, m) in k moves.
        // The strategy is to make min(n, m) diagonal moves to reach (n, n) or (m, m),
        // then make axial moves to reach the target, and then pair up remaining moves.

        // Calculate the maximum number of diagonal moves possible.
        // We want to make as many diagonal moves as possible.
        // The maximum number of diagonal moves is limited by the smaller coordinate, n.
        // After n diagonal moves, we reach (n, n).
        // Remaining moves: k - n.
        // Remaining distance to cover: m - n (along y-axis).
        // These m - n moves must be axial moves.
        // After these m - n axial moves, we are at (n, m).
        // Total moves used so far: n + (m - n) = m.
        // Remaining moves: k - m.

        // Now we are at (n, m) and have k - m moves left.
        // Each pair of moves (e.g., (x,y) -> (x+1,y) -> (x,y)) or (x,y) -> (x+1,y+1) -> (x,y)
        // can be used to consume 2 moves without changing the final position.
        // We want to maximize diagonal moves.
        // If we have an even number of moves left (k - m is even), we can use pairs of diagonal moves
        // like (x,y) -> (x+1,y+1) -> (x,y) or (x,y) -> (x+1,y-1) -> (x,y).
        // Each such pair adds 2 diagonal moves.
        // So, if (k - m) is even, we can add (k - m) diagonal moves.
        // Total diagonal moves = n + (k - m).

        // If we have an odd number of moves left (k - m is odd), we cannot use pairs of diagonal moves
        // to consume all remaining moves and end up at (n,m) while maximizing diagonal moves.
        // Consider the parity of the coordinates.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // Each move changes the parity of (x+y) by 0 or 1.
        // (x1, y1) -> (x2, y2)
        // (x2+y2) - (x1+y1) = (x2-x1) + (y2-y1)
        // For a diagonal move, (x2-x1) and (y2-y1) are both non-zero.
        // (x2-x1) is +/- 1, (y2-y1) is +/- 1.
        // So (x2-x1) + (y2-y1) can be -2, 0, 2. Parity of (x+y) does not change.
        // For an axial move, one of (x2-x1) or (y2-y1) is zero, the other is +/- 1.
        // So (x2-x1) + (y2-y1) can be -1, 1. Parity of (x+y) changes.

        // Starting at (0,0), sum is 0 (even).
        // Target (n,m), sum is n+m.
        // If k moves are made, the parity of (n+m) must be the same as the parity of k.
        // (n+m) % 2 == k % 2.
        // If (n+m) % 2 != k % 2, it's impossible.
        // This is because each axial move flips the parity of (x+y), and each diagonal move preserves it.
        // So, the parity of (x+y) after k moves is (initial_parity_of_x_plus_y + number_of_axial_moves) % 2.
        // (0 + A) % 2 = (n+m) % 2. So A % 2 = (n+m) % 2.
        // Also, k = D + A. So A = k - D.
        // (k - D) % 2 = (n+m) % 2.

        // Let's check the parity condition:
        if ((n + m) % 2 != k % 2) {
            // If parities don't match, we need to adjust the number of axial moves.
            // This means we cannot achieve the maximum diagonal moves calculated above.
            // If (k - m) is odd, and (n+m) % 2 != k % 2, then (n+m) % 2 == (k-1) % 2.
            // This means we need to make one more axial move than the "ideal" (k-m) even case.
            // Or, equivalently, we need to make one less diagonal move.
            // The maximum number of diagonal moves would be n + (k - m) - 2.
            // Why -2? Because if we have an odd number of moves left (k-m), we can't use them all as diagonal pairs.
            // We must use at least one axial move.
            // If (k-m) is odd, we can use (k-m-1) diagonal moves (as pairs) and 1 axial move.
            // This would result in n + (k-m-1) diagonal moves.
            // However, this might not satisfy the parity condition.
            // The parity condition (n+m)%2 == k%2 is crucial.
            // If (n+m)%2 != k%2, it means we need to change the parity of the total number of axial moves.
            // This requires changing the number of axial moves by an odd number.
            // The most efficient way to do this is to convert two diagonal moves into two axial moves,
            // or one diagonal move into one axial move and one axial move into one diagonal move.
            // The simplest way to change the parity of axial moves is to change two diagonal moves into two axial moves.
            // For example, instead of (x,y)->(x+1,y+1)->(x,y), we do (x,y)->(x+1,y)->(x,y+1)->(x,y).
            // This reduces diagonal moves by 2.
            // So, if (n+m)%2 != k%2, the maximum diagonal moves is n + (k - m) - 2.
            std::cout << k - 2 << "\n"; // This is equivalent to n + (k-m) - 2, since n=m in this case.
                                        // No, this is not correct.
                                        // If (n+m)%2 != k%2, it means we need to make an odd number of axial moves.
                                        // The base strategy gives n diagonal moves and m-n axial moves to reach (n,m).
                                        // Total moves used: m. Remaining moves: k-m.
                                        // If (k-m) is even, we add (k-m) diagonal moves. Total D = n + (k-m).
                                        // Total A = (m-n).
                                        // Parity of A = (m-n)%2.
                                        // Parity of k = (n + (k-m) + (m-n)) % 2 = (k)%2.
                                        // Parity of (n+m) = (n+m)%2.
                                        // We need (m-n)%2 == (n+m)%2.
                                        // This simplifies to (m-n) == (n+m) (mod 2)
                                        // -2n == 0 (mod 2), which is always true.
                                        // So the parity condition (n+m)%2 == k%2 is the only one that matters.

                                        // If (n+m)%2 != k%2, we must reduce the number of diagonal moves by 1,
                                        // and increase axial moves by 1, or vice versa.
                                        // The simplest way to change the parity of the total number of axial moves
                                        // (which is equivalent to changing the parity of k - D)
                                        // is to convert two diagonal moves into two axial moves.
                                        // This reduces the diagonal count by 2.
                                        // So, the answer is k - 2.
            std::cout << k - 2 << "\n";
        } else {
            // If parities match, we can achieve the maximum possible diagonal moves.
            // This is n (to reach (n,n)) + (k-m) (remaining moves, used as diagonal pairs).
            std::cout << k << "\n"; // This is equivalent to n + (k-m) when n=m.
                                    // No, this is not correct.
                                    // The maximum number of diagonal moves is k if k and (n+m) have the same parity.
                                    // This is because we can always make k diagonal moves if n=m=k.
                                    // If n=m, we can reach (n,n) in n diagonal moves.
                                    // We have k-n moves left. If k-n is even, we can use (k-n)/2 pairs of diagonal moves
                                    // like (x,y)->(x+1,y+1)->(x,y) to consume all moves.
                                    // Total diagonal moves = n + (k-n) = k.
                                    // If k-n is odd, we can't use all as diagonal pairs.
                                    // We need to use at least one axial move.
                                    // This means we use (k-n-1)/2 pairs of diagonal moves and one axial move.
                                    // Total diagonal moves = n + (k-n-1) = k-1.
                                    // But this is only if n=m.

                                    // Let's re-evaluate the general case:
                                    // Max diagonal moves is k.
                                    // This is possible if we can reach (n,m) in k moves using only diagonal moves.
                                    // This requires n=m and k=n.
                                    // If n != m, we must use at least |n-m| axial moves.
                                    // So, the number of axial moves A >= |n-m|.
                                    // The number of diagonal moves D <= k - |n-m|.
                                    // We want to maximize D. So we try to set D = k - |n-m|.
                                    // This means A = |n-m|.
                                    // With this, we have D diagonal moves and A axial moves.
                                    // The parity condition is (n+m)%2 == k%2.
                                    // If (n+m)%2 == k%2, then we can achieve k - |n-m| diagonal moves.
                                    // This is because we use |n-m| axial moves to cover the difference,
