#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a1 = elements[0].value;
    long long a2 = elements[1].value;
    long long an_1 = elements[n - 2].value;
    long long an = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s).
    // min_f = a1 + a2
    // max_f = an_1 + an
    // Goodness = (an_1 + an) - (a1 + a2)
    long long goodness_all_same = (an_1 + an) - (a1 + a2);
    std::vector<int> partition_all_same(n, 1); // All in subsequence 1

    // Case 2: Partition such that a1 is in one subsequence and an is in another.
    // This implies a1 and an are in different subsequences.
    // The minimum possible sum is a1 + a2.
    // The maximum possible sum is an_1 + an.
    //
    // If a1 and a2 are in the same subsequence: min_f = a1 + a2
    // If a1 and a2 are in different subsequences: min_f = a1 + a2 + h
    //
    // If an_1 and an are in the same subsequence: max_f = an_1 + an
    // If an_1 and an are in different subsequences: max_f = an_1 + an + h
    //
    // Consider a partition where a1 is in subseq 1, and all others are in subseq 2.
    // This means a1 is different from a2, ..., an.
    // And a2, ..., an are all same.
    //
    // min_f:
    //   - a1 + a2 + h (a1 and a2 are different)
    //   - a2 + a3 (if n >= 3, a2 and a3 are same)
    //   So, min_f = min(a1 + a2 + h, a2 + a3 (if n>=3))
    //   Actually, the minimum possible sum involving a1 is a1+a2. Since they are different, it's a1+a2+h.
    //   The minimum possible sum not involving a1 is a2+a3 (if n>=3).
    //   So, min_f = a1 + a2 + h. (This is because a1 is separated from all others, so a1+a_k+h is always present.
    //   The smallest of these is a1+a2+h. If n>=3, a2+a3 is also present and is smaller than a1+a2+h if h is large enough.
    //   So, min_f = min(a1 + a2 + h, a2 + a3 (if n>=3)).
    //   If n=2, min_f = a1+a2+h.
    //
    // max_f:
    //   - an_1 + an (an_1 and an are same)
    //   - a1 + an + h (a1 and an are different)
    //   So, max_f = max(an_1 + an, a1 + an + h)
    //
    // Goodness = max_f - min_f

    long long min_f_diff_a1_an;
    long long max_f_diff_a1_an;

    // Partition: elements[0] (a1) in subseq 1, elements[1]...elements[n-1] in subseq 2.
    // Pairs:
    // 1. (a1, a_k) for k > 0: f = a1 + a_k + h. Smallest is a1 + a2 + h.
    // 2. (a_k, a_j) for k,j > 0: f = a_k + a_j. Smallest is a2 + a3 (if n >= 3). Largest is an_1 + an.

    if (n == 2) {
        min_f_diff_a1_an = a1 + a2 + h;
        max_f_diff_a1_an = a1 + a2 + h;
    } else { // n >= 3
        min_f_diff_a1_an = std::min(a1 + a2 + h, a2 + elements[2].value);
        max_f_diff_a1_an = std::max(a1 + an + h, an_1 + an);
    }

    long long goodness_diff_a1_an = max_f_diff_a1_an - min_f_diff_a1_an;
    std::vector<int> partition_diff_a1_an(n);
    partition_diff_a1_an[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_diff_a1_an[elements[i].original_index] = 2;
    }

    // Compare the two strategies
    if (goodness_all_same <= goodness_diff_a1_an) {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_diff_a1_an << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_diff_a1_an[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

