        // Pieces: p1 = s[0], p2 = s.substr(1, n-2), p3 = s[n-1].
        // Since s is a palindrome, s[0] == s[n-1].
        // We can reorder to p3 + p2 + p1. This would be s[n-1] + s.substr(1, n-2) + s[0].
        // Since s[n-1] == s[0], this is just s.
        //
        // The key insight for k=2 is that if s is not composed of a single repeated character,
        // then s.substr(0, n-1) (i.e., s without its last character) is not a palindrome.
        // Let s_prefix = s.substr(0, n-1).
        // If s_prefix is a palindrome, then s must be of the form "aaaa...a".
        // (e.g., "aba", s_prefix="ab", not palindrome. "aaa", s_prefix="aa", palindrome.)
        // If s_prefix is not a palindrome, then we can cut s into s_prefix and s[n-1].
        // This is a k=1 cut. We already checked k=1.
        //
        // The problem is asking for minimum k. If k=1 doesn't work, and it's not impossible, then k=2.
        // The condition for "Impossible" is that all characters in the string are the same.
        // If s = "aaaa", then s_prime must be "aaaa".
        // If s = "ababa", s_prime = "baaba" (k=1, cut "a|baba", swap to "babaa", not palindrome).
        // s = "ababa", cut "ab|aba", swap to "abaab", not palindrome.
        // s = "ababa", cut "aba|ba", swap to "baaba", palindrome, != s. So k=1.
        //
        // The logic for "Impossible" is: if all characters in `s` are the same, then any reordering of its substrings will result in `s` itself.
        // Example: `s = "qqqq"`. `n=4`.
        // `s[0] = 'q'`, `s[1] = 'q'`. `all_same_char_in_half` is true. Output "Impossible". Correct.
        // Example: `s = "nolon"`. `n=5`.
        // `s[0] = 'n'`, `s[1] = 'o'`. `all_same_char_in_half` is false.
        // k=1 check:
        // "n|olon" -> "olonn" (not palindrome)
        // "no|lon" -> "lonno" (not palindrome)
        // "nol|on" -> "onnol" (not palindrome)
        // "nolo|n" -> "nnolo" (not palindrome)
        // None of these work. So k=1 is not the answer.
        // Since `all_same_char_in_half` is false, the output should be 2. Correct.
        //
        // Example: `s = "otto"`. `n=4`.
        // `s[0] = 'o'`, `s[1] = 't'`. `all_same_char_in_half` is false.
        // k=1 check:
        // "o|tto" -> "ttoo" (not palindrome)
        // "ot|to" -> "toot" (palindrome, != s). Output 1. Correct.
        //
        // Example: `s = "kinnikkinnik"`. `n=12`.
        // `s[0] = 'k'`, `s[1] = 'i'`. `all_same_char_in_half` is false.
        // k=1 check:
        // Cut at `i=9`: `s1 = "kinnikkin"`, `s2 = "nik"`.
        // `s_prime = s2 + s1 = "nikkinnikkin"`.
        // `s_prime` is a palindrome. `s_prime != s`. Output 1. Correct.

        // The logic seems to be:
        // 1. Try k=1. If a solution is found, print 1.
        // 2. If no k=1 solution, check if all characters in the string are the same.
        //    (This is equivalent to checking if all characters in the first half are the same,
        //     because the string is a palindrome).
        //    If they are, print "Impossible".
        // 3. Otherwise (no k=1 solution, but not all characters are the same), print 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_dist(n, 0); // left_dist[i] = distance to nearest 0 on the left (inclusive)
    std::vector<int> right_dist(n, 0); // right_dist[i] = distance to nearest 1 on the right (inclusive)

    // Calculate left_dist
    int last_zero = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            last_zero = i;
        }
        left_dist[i] = (last_zero == -1) ? n + 1 : (i - last_zero);
    }

    // Calculate right_dist
    int last_one = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one = i;
        }
        right_dist[i] = (last_one == n) ? n + 1 : (last_one - i);
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0, it can only change to 1 if it's part of 101 pattern
            // It will change to 1 if it's part of 1...0...1 pattern where 0 is "closer" to 1s
            // This means left_dist[i] (dist to 0 on left) and right_dist[i] (dist to 1 on right) are not relevant for changing 0 to 1.
            // Instead, we need to find the distance to the nearest 1 on the left and nearest 1 on the right.
            // Let's re-evaluate the logic for 0s and 1s.
            // A 0 at index i changes to 1 if a[i-1]=1 and a[i+1]=1.
            // A 1 at index i changes to 0 if a[i-1]=0 and a[i+1]=0.
            // The problem is about propagation of 0s and 1s.
            // A 0 at index `i` will eventually become 1 if it's "closer" to a 1 on its left AND a 1 on its right than to a 0 on its left AND a 0 on its right.
            // Specifically, if `dist_to_left_1[i] < dist_to_left_0[i]` AND `dist_to_right_1[i] < dist_to_right_0[i]`.
            // This is equivalent to `left_dist[i] > right_dist[i]` for a 0 to become 1.
            // No, this is not correct.
            // A 0 at index `i` will become 1 if `a[i-1]=1` and `a[i+1]=1`.
            // A 1 at index `i` will become 0 if `a[i-1]=0` and `a[i+1]=0`.
            // The key insight is that a block of identical values `...X X X...` will remain `X` in the middle.
            // A pattern `0 1 0` becomes `0 0 0`. A pattern `1 0 1` becomes `1 1 1`.
            // This means 0s expand into 1s, and 1s expand into 0s.
            // The "median" operation effectively propagates the dominant value from the neighbors.
            // A 0 at `i` will become 1 if it's surrounded by 1s.
            // A 1 at `i` will become 0 if it's surrounded by 0s.
            // The distance `k` for a cell `i` to change is `min(dist_to_nearest_opposite_on_left, dist_to_nearest_opposite_on_right)`.
            // For a 0 at `i`, it needs `k` steps to become 1 if `a[i-k]=1` and `a[i+k]=1` and all in between are 0s.
            // This is `min(distance to nearest 1 on left, distance to nearest 1 on right)`.
            // For a 1 at `i`, it needs `k` steps to become 0 if `a[i-k]=0` and `a[i+k]=0` and all in between are 1s.
            // This is `min(distance to nearest 0 on left, distance to nearest 0 on right)`.

            // Let's re-calculate distances to nearest 0 and 1 for each position.
            // dist_to_left_0[i]: distance from i to nearest 0 on its left (inclusive)
            // dist_to_left_1[i]: distance from i to nearest 1 on its left (inclusive)
            // dist_to_right_0[i]: distance from i to nearest 0 on its right (inclusive)
            // dist_to_right_1[i]: distance from i to nearest 1 on its right (inclusive)

            // Initialize with large values
            std::vector<int> dist_to_left_0(n, n + 1);
            std::vector<int> dist_to_left_1(n, n + 1);
            std::vector<int> dist_to_right_0(n, n + 1);
            std::vector<int> dist_to_right_1(n, n + 1);

            // Fill left distances
            for (int j = 0; j < n; ++j) {
                if (a[j] == 0) {
                    dist_to_left_0[j] = 0;
                    dist_to_left_1[j] = (j > 0) ? dist_to_left_1[j - 1] + 1 : n + 1;
                } else { // a[j] == 1
                    dist_to_left_1[j] = 0;
                    dist_to_left_0[j] = (j > 0) ? dist_to_left_0[j - 1] + 1 : n + 1;
                }
            }

            // Fill right distances
            for (int j = n - 1; j >= 0; --j) {
                if (a[j] == 0) {
                    dist_to_right_0[j] = 0;
                    dist_to_right_1[j] = (j < n - 1) ? dist_to_right_1[j + 1] + 1 : n + 1;
                } else { // a[j] == 1
                    dist_to_right_1[j] = 0;
                    dist_to_right_0[j] = (j < n - 1) ? dist_to_right_0[j + 1] + 1 : n + 1;
                }
            }

            for (int j = 1; j < n - 1; ++j) {
                if (a[j] == 0) {
                    // A 0 at j will become 1 if it's "closer" to 1s than 0s.
                    // Specifically, if dist_to_left_1[j] < dist_to_left_0[j] AND dist_to_right_1[j] < dist_to_right_0[j]
                    // The number of steps for a 0 to become 1 is min(dist_to_left_1[j], dist_to_right_1[j]).
                    // This is because a 0 at `j` will flip to 1 if `a[j-1]=1` and `a[j+1]=1`.
                    // This means the "wave" of 1s from left and right meets at `j`.
                    // The time it takes is `min(dist_to_left_1[j], dist_to_right_1[j])`.
                    int k_val = std::min(dist_to_left_1[j], dist_to_right_1[j]);
                    if (k_val != n + 1) { // If there are 1s on both sides
                        max_k = std::max(max_k, k_val);
                        if (dist_to_left_1[j] < dist_to_right_1[j]) {
                            final_a[j] = 1; // It will eventually become 1
                        } else if (dist_to_right_1[j] < dist_to_left_1[j]) {
                            final_a[j] = 1; // It will eventually become 1
                        } else { // dist_to_left_1[j] == dist_to_right_1[j]
                            // It's equidistant to 1s on both sides. It will become 1.
                            final_a[j] = 1;
                        }
                    }
                } else { // a[j] == 1
                    // A 1 at j will become 0 if it's "closer" to 0s than 1s.
                    // The number of steps for a 1 to become 0 is min(dist_to_left_0[j], dist_to_right_0[j]).
                    int k_val = std::min(dist_to_left_0[j], dist_to_right_0[j]);
                    if (k_val != n + 1) { // If there are 0s on both sides
                        max_k = std::max(max_k, k_val);
                        if (dist_to_left_0[j] < dist_to_right_0[j]) {
                            final_a[j] = 0; // It will eventually become 0
                        } else if (dist_to_right_0[j] < dist_to_left_0[j]) {
                            final_a[j] = 0; // It will eventually become 0
                        } else { // dist_to_left_0[j] == dist_to_right_0[j]
                            // It's equidistant to 0s on both sides. It will become 0.
                            final_a[j] = 0;
                        }
                    }
                }
            }

            // The logic for final_a is simpler:
            // If a[j] is 0: it becomes 1 if dist_to_left_1[j] == dist_to_right_1[j] AND this distance is less than dist_to_left_0[j] and dist_to_right_0[j]
            // No, this is not right.
            // The rule is: a[i] becomes 0 if a[i-1]=0 and a[i+1]=0.
            // a[i] becomes 1 if a[i-1]=1 and a[i+1]=1.
            // If a[i-1] != a[i+1], then a[i] remains unchanged.
            // This means a stable sequence must not have `0 X 0` or `1 X 1` patterns.
            // So, a stable sequence must be of the form `00...0011...11` or `11...1100...00` or all 0s or all 1s.
            // The final state of `a[i]` depends on `min(dist_to_left_0[i], dist_to_left_1[i])` and `min(dist_to_right_0[i], dist_to_right_1[i])`.
            // Let `d0_L = dist_to_left_0[i]`, `d1_L = dist_to_left_1[i]`.
            // Let `d0_R = dist_to_right_0[i]`, `d1_R = dist_to_right_1[i]`.
            // If `a[i] == 0`:
            //   It will become 1 if it's "closer" to 1s than 0s.
            //   This means `min(d1_L, d1_R) < min(d0_L, d0_R)`.
            //   The time taken is `min(d1_L, d1_R)`.
            // If `a[i] == 1`:
            //   It will become 0 if it's "closer" to 0s than 1s.
            //   This means `min(d0_L, d0_R) < min(d1_L, d1_R)`.
            //   The time taken is `min(d0_L, d0_R)`.
            // If `min(d0_L, d0_R) == min(d1_L, d1_R)`:
            //   The element `a[i]` will remain its original value.
            //   The time taken is `min(d0_L, d0_R)`.

            // Let's re-calculate max_k and final_a based on this.
            max_k = 0;
            for (int j = 1; j < n - 1; ++j) {
                int d0_L = dist_to_left_0[j];
                int d1_L = dist_to_left_1[j];
                int d0_R = dist_to_right_0[j];
                int d1_R = dist_to_right_1[j];

                int time_to_0 = std::min(d0_L, d0_R);
                int time_to_1 = std::min(d1_L, d1_R);

                if (time_to_0 == n + 1 && time_to_1 == n + 1) {
                    // This should not happen for j in [1, n-2] unless n is very small.
                    // It means no 0s or no 1s exist in the sequence.
                    // But the initial sequence has at least one 0 and one 1 for this to be interesting.
                    // If all are 0s or all are 1s, max_k is 0.
                    // If n=3, a={0,0,0} -> max_k=0.
                    // If n=3, a={0,1,0} -> d0_L=1, d1_L=0, d0_R=1, d1_R=0 for j=1.
                    // time_to_0 = min(1,1)=1. time_to_1 = min(0,0)=0.
                    // time_to_1 < time_to_0, so final_a[1] becomes 1. This is wrong.
                    // 010 -> 000.
                    // The rule is: if a[i-1] == a[i+1], then b[i] = a[i-1].
                    // If a[i-1] != a[i+1], then b[i] = a[i].
                    // This means a 0 surrounded by 1s becomes 1. A 1 surrounded by 0s becomes 0.
                    // Otherwise, it stays.
                    // The "time" for a cell to change is the minimum distance to a pair of identical neighbors.
                    // For a[j], if a[j-k]=X and a[j+k]=X, and all in between are not X, then it takes k steps for a[j] to become X.
                    // This is `min(dist_to_left_X[j], dist_to_right_X[j])`.
                    // So, if `a[j] == 0`: it becomes 1 if `min(dist_to_left_1[j], dist_to_right_1[j]) < min(dist_to_left_0[j], dist_to_right_0[j])`.
                    // If `a[j] == 1`: it becomes 0 if `min(dist_to_left_0[j], dist_to_right_0[j]) < min(dist_to_left_1[j], dist_to_right_1[j])`.
                    // If `min(dist_to_left_0[j], dist_to_right_0[j]) == min(dist_to_left_1[j], dist_to_right_1[j])`: it stays `a[j]`.
                    // The `max_k` is the maximum of these minimum distances.

                    // Let's re-evaluate for 010 -> 000.
                    // a = {0,1,0}. n=3.
                    // j=1. a[1]=1.
                    // dist_to_left_0 = {0,1,0}
                    // dist_to_left_1 = {n+1,0,1}
                    // dist_to_right_0 = {0,1,0}
                    // dist_to_right_1 = {1,0,n+1}
                    // For j=1:
                    // d0_L = dist_to_left_0[1] = 1
                    // d1_L = dist_to_left_1[1] = 0
                    // d0_R = dist_to_right_0[1] = 1
                    // d1_R = dist_to_right_1[1] = 0
                    // time_to_0 = min(d0_L, d0_R) = min(1,1) = 1
                    // time_to_1 = min(d1_L, d1_R) = min(0,0) = 0
                    // Here, time_to_1 < time_to_0. So, if a[1] was 0, it would become 1.
                    // But a[1] is 1. So it should become 0.
                    // The rule is: if `time_to_0 < time_to_1`, then `final_a[j] = 0`.
                    // If `time_to_1 < time_to_0`, then `final_a[j] = 1`.
                    // If `time_to_0 == time_to_1`, then `final_a[j] = a[j]`.
                    // This is the correct logic for the final state.
                    // The `max_k` is `max(max_k, min(time_to_0, time_to_1))`.

                    // For 010, j=1, a[1]=1:
                    // time_to_0 = 1
                    // time_to_1 = 0
                    // time_to_1 < time_to_0, so final_a[1] = 1. This is wrong. 010 -> 000.
                    // The problem is that `dist_to_left_1[1]` is 0 because `a[1]` itself is 1.
                    // We need distances to *other* elements.
                    // Let's redefine distances:
                    // `dist_to_left_0[i]` = distance to nearest 0 on left, *excluding* `a[i]`.
                    // `dist_to_right_0[i]` = distance to nearest 0 on right, *excluding* `a[i]`.
                    // This is equivalent to `dist_to_left_0[i-1]+1` if `a[i-1]` is not 0.
                    // This is getting complicated.

                    // Let's use the simpler observation:
                    // A sequence stabilizes to `0...01...1` or `1...10...0` or all 0s or all 1s.
                    // The "boundary" between 0s and 1s (or 1s and 0s) moves.
                    // A `0` at `i` will become `1` if it's part of a `1...0...1` pattern.
                    // A `1` at `i` will become `0` if it's part of a `0...1...0` pattern.
                    // The number of steps for `a[i]` to change is `k` if `a[i-k]` and `a[i+k]` are the same and opposite of `a[i]`.
                    // Example: `000111`. `a[2]=0`. `a[3]=1`.
                    // `000111` -> `001111` (k=1 for a[2])
                    // `001111` -> stable.
                    // `max_k` is the maximum `k` over all `i` that change.
                    // `k` for `a[i]` is `min(dist_to_left_opposite[i], dist_to_right_opposite[i])`.
                    // `dist_to_left_opposite[i]` is the distance to the nearest element `X` on the left of `i` such that `X != a[i]`.
                    // `dist_to_right_opposite[i]` is the distance to the nearest element `X` on the right of `i` such that `X != a[i]`.

                    // Let's re-calculate `dist_to_left_opposite` and `dist_to_right_opposite`.
                    std::vector<int> dist_to_left_opposite(n, n + 1);
                    std::vector<int> dist_to_right_opposite(n, n + 1);

                    // Fill left opposite distances
                    for (int j = 0; j < n; ++j) {
                        if (j > 0) {
                            if (a[j] != a[j - 1]) {
                                dist_to_left_opposite[j] = 1;
                            } else {
                                dist_to_left_opposite[j] = dist_to_left_opposite[j - 1] + 1;
                            }
                        }
                    }

                    // Fill right opposite distances
                    for (int j = n - 1; j >= 0; --j) {
                        if (j < n - 1) {
                            if (a[j] != a[j + 1]) {
                                dist_to_right_opposite[j] = 1;
                            } else {
                                dist_to_right_opposite[j] = dist_to_right_opposite[j + 1] + 1;
                            }
                        }
                    }

                    max_k = 0;
                    for (int j = 1; j < n - 1; ++j) {
                        int k_val = std::min(dist_to_left_opposite[j], dist_to_right_opposite[j]);
                        if (k_val != n + 1) { // If there's an opposite on both sides
                            max_k = std::max(max_k, k_val);
                            if (dist_to_left_opposite[j] < dist_to_right_opposite[j]) {
                                final_a[j] = a[j - dist_to_left_opposite[j]]; // It becomes the value of the closer opposite
                            } else if (dist_to_right_opposite[j] < dist_to_left_opposite[j]) {
                                final_a[j] = a[j + dist_to_right_opposite[j]]; // It becomes the value of the closer opposite
                            } else { // Equidistant
                                // It remains its original value.
                                // Example: 00100. a[2]=1. dist_L_opp=2 (to 0 at 0), dist_R_opp=2 (to 0 at 4).
                                // It should become 0.
                                // The rule is: if `dist_to_left_opposite[j] == dist_to_right_opposite[j]`,
                                // then `final_a[j]` becomes the value of the opposite.
                                // This is because `a[j-k]` and `a[j+k]` are the same and opposite of `a[j]`.
                                // So `final_a[j]` becomes `a[j-k]`.
                                final_a[j] = a[j - dist_to_left_opposite[j]];
                            }
                        }
                    }

                    // The `max_k` is the maximum of `ceil(k_val / 2.0)`.
                    // No, it's just `k_val`.
                    // Example: 01010 -> 00100 -> 00000
                    // n=5, a={0,1,0,1,0}
                    // j=1, a[1]=1. dist_L_opp[1]=1 (to 0 at 0). dist_R_opp[1]=1 (to 0 at 2). k_val=1. max_k=1. final_a[1]=0.
                    // j=2, a[2]=0. dist_L_opp[2]=1 (to 1 at 1). dist_R_opp[2]=1 (to 1 at 3). k_val=1. max_k=1. final_a[2]=1.
                    // j=3, a[3]=1. dist_L_opp[3]=1 (to 0 at 2). dist_R_opp[3]=1 (to 0 at 4). k_val=1. max_k=1. final_a[3]=0.
                    // After 1 step: 00100.
                    // Now, for 00100:
                    // j=1, a[1]=0. dist_L_opp[1]=2 (to 1 at 2). dist_R_opp[1]=1 (to 1 at 2). k_val=1. max_k=1. final_a[1]=1.
                    // This is wrong. 00100 -> 00000.
                    // The `k_val` is the number of steps.
                    // The `max_k` is the maximum number of steps any element needs to stabilize.
                    // The final value of `a[j]` is determined by which value (0 or 1) is "closer" to it.
                    // If `a[j]` is closer to a 0 on its left/right than to a 1 on its left/right, it becomes 0.
                    // If `a[j]` is closer to a 1 on its left/right than to a 0 on its left/right, it becomes 1.
                    // If it's equidistant, it keeps its original value.
                    // The "distance" here is `min(dist_to_left_X[j], dist_to_right_X[j])`.

                    // Let's use the `dist_to_left_0`, `dist_to_left_1`, `dist_to_right_0`, `dist_to_right_1` from before.
                    // These are distances to the nearest 0/1 *including* the current element.
                    // So `dist_to_left_0[j]` is 0 if `a[j]==0`.
                    // This is the correct definition for finding the "closest" value.

                    max_k = 0;
                    for (int j = 1; j < n - 1; ++j) {
                        int d0_L = dist_to_left_0[j];
                        int d1_L = dist_to_left_1[j];
                        int d0_R = dist_to_right_0[j];
                        int d1_R = dist_to_right_1[j];

                        int time_to_0 = std::min(d0_L, d0_R);
