    // The counts of 'n' and 'z' directly give us the number of '1's and '0's respectively.

    bool first_digit = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }

    std::cout << std::endl;

