int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required for k torches:
        // k sticks for crafting + k * y sticks for k coal
        // Total sticks = k * (y + 1)
        long long total_sticks_needed = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using the stick trade.
        // Each stick trade (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick trades = ceil((total_sticks_needed - 1) / (x - 1))
        // Using integer division: (A + B - 1) / B for ceil(A / B)
        long long stick_trades = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // Number of coal trades is simply k, as each trade gives 1 coal.
        long long coal_trades = k;

        // Total trades = stick_trades + coal_trades
        long long total_trades = stick_trades + coal_trades;

        std::cout << total_trades << "\n";
    }
    return 0;
}

