void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Re-evaluate has_pos_one and has_neg_one for elements *before* current index
    // For index 0, these are already correctly set based on a[0]
    // For index 1, has_pos_one means a[0]==1, has_neg_one means a[0]==-1
    // For index k, has_pos_one means there is some a[i]==1 for i < k
    // For index k, has_neg_one means there is some a[i]==-1 for i < k

    // We need to track if a 1 or -1 has appeared *before* the current index `i`.
    // Let's re-initialize and track this iteratively.
    has_pos_one = (a[0] == 1);
    has_neg_one = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element.
        // The current a[i] value (which is -1, 0, or 1) contributes to future has_pos_one/has_neg_one.
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

