    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or from 0 if no 'R's) to the target n+1.
        // The length of the string is s.length(). The target cell is s.length() + 1.
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

