#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int last_diff_01 = -1; // Index of the last '0' in a that needs to be '1' in b
    int last_diff_10 = -1; // Index of the last '1' in a that needs to be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (last_diff_10 != -1) { // Found a '1' in a that needs to be '0' in b
                    // We can swap a[last_diff_10] ('1') with a[i] ('0')
                    // This fixes both positions. Cost is |i - last_diff_10|.
                    cost += (i - last_diff_10);
                    last_diff_10 = -1; // This '10' mismatch is resolved
                } else {
                    // No '10' mismatch to pair with. Store this '01' mismatch.
                    last_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (last_diff_01 != -1) { // Found a '0' in a that needs to be '1' in b
                    // We can swap a[last_diff_01] ('0') with a[i] ('1')
                    // This fixes both positions. Cost is |i - last_diff_01|.
                    cost += (i - last_diff_01);
                    last_diff_01 = -1; // This '01' mismatch is resolved
                } else {
                    // No '01' mismatch to pair with. Store this '10' mismatch.
                    last_diff_10 = i;
                }
            }
        }
    }

    // Any remaining 'last_diff_01' or 'last_diff_10' means an unmatched mismatch.
    // These must be fixed by flipping. Each flip costs 1.
    if (last_diff_01 != -1) {
        cost += 1;
    }
    if (last_diff_10 != -1) {
        cost += 1;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two points from the range [i+1, right_ptr-1].
        // Let k be the number of points in this range: (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // These are the points x[i+1], x[i+2], ..., x[right_ptr-1].
        // The number of points available to choose from (excluding x[i]) is (right_ptr - 1) - i.
        // Let m = (right_ptr - 1) - i.
        // If m < 2, we cannot choose two distinct points, so we add 0.
        // Otherwise, we can choose C(m, 2) ways.
        // C(m, 2) = m * (m - 1) / 2.

        long long m = (long long)(right_ptr - 1) - i;

        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For odd n, this is the middle index

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // If a[i] > s, it must be decreased to s.
    // If a[i] <= s, it's already fine.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // If a[i] < s, it must be increased to s.
    // If a[i] >= s, it's already fine.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means if A is sorted ascending and B is sorted ascending,
    // A'[b_elements[i].original_index] = a_elements[i].value
    // This effectively pairs a_elements[0] with b_elements[0], a_elements[1] with b_elements[1], etc.
    // Since F(n, k) = k / (n + 1), we want to maximize sum(k_i / (n_i + 1)).
    // To maximize sum(k_i / (n_i + 1)), we should pair larger k_i with smaller (n_i + 1)
    // and smaller k_i with larger (n_i + 1).
    // This means pairing larger B_i with smaller A_i, and smaller B_i with larger A_i.
    //
    // Let's re-evaluate the pairing.
    // We have sorted A: a_0 <= a_1 <= ... <= a_{m-1}
    // We have sorted B: b_0 <= b_1 <= ... <= b_{m-1}
    //
    // The sum is sum(b_i / (a'_i + 1)).
    // To maximize this sum, we want to pair the largest b_i with the smallest (a'_i + 1),
    // and the smallest b_i with the largest (a'_i + 1).
    // This means pairing b_elements[m-1] with a_elements[0],
    // b_elements[m-2] with a_elements[1], and so on.
    // In general, b_elements[m-1-i] should be paired with a_elements[i].
    //
    // The output array `result_a_prime` needs to be constructed such that
    // `result_a_prime[original_index_of_b_elements[m-1-i]] = a_elements[i].value`.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_elements[m-1-i] is the (i+1)-th largest B value.
        // a_elements[i] is the (i+1)-th smallest A value.
        // We pair the (i+1)-th largest B value with the (i+1)-th smallest A value.
        // The original index of this B value is b_elements[m-1-i].original_index.
        // This is where the A value a_elements[i].value should go.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

