// Function to check if a prefix is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_prefix, const std::vector<bool>& distinct_prefix) {
    if (len == 0) return false; // Permutations must have non-zero length
    return distinct_prefix[len - 1] && max_prefix[len - 1] == len;
}

// Function to check if a suffix is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix, const std::vector<bool>& distinct_suffix) {
    if (len == 0) return false; // Permutations must have non-zero length
    return distinct_suffix[n - len] && max_suffix[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_prefix(n);
    std::vector<bool> distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n-1, but for safety use n+1
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_prefix[i] = current_max_prefix;
        distinct_prefix[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_suffix(n);
    std::vector<bool> distinct_suffix(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_suffix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            current_distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_suffix[i] = current_max_suffix;
        distinct_suffix[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_permutation_prefix(l1, a, max_prefix, distinct_prefix) &&
            is_permutation_suffix(l2, n, a, max_suffix, distinct_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

