        // So max_{j!=i} min(p[i], p[j]) will be at least p[i].
        // In fact, it will be exactly p[i] because for any p[j] > p[i], min(p[i], p[j]) = p[i].
        // And for any p[j] < p[i], min(p[i], p[j]) = p[j] < p[i].
        // So the maximum value in row i (excluding a[i][i]) is p[i] if p[i] < N.
        // If p[i] = N, the maximum value is N-1.
        // To distinguish these two cases, we can check if max_val_in_row is N-1.
        // If it is N-1, then p[i] must be N. Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from C's stdio and disables flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Create a vector to store prices.
        // Using a vector is flexible and efficient enough given N constraints.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        int bad_prices_count = 0;
        // Initialize min_price_suffix with a very large value.
        // Since prices a_i are up to 10^6, 10^6 + 1 is a safe initial maximum.
        int min_price_suffix = 1000001; 

        // Iterate from right to left (from the second to last day to the first day).
        // The last day (index n-1) can never have a bad price because there are no later days.
        // So, we start checking from index n-2 down to 0.
        for (int i = n - 1; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price found
            // in the suffix to its right (min_price_suffix), then a[i] is a bad price.
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_price_suffix, it means a[i] is
                // either equal to or smaller than all prices to its right.
                // In this case, a[i] itself becomes the new minimum for the suffix
                // starting from this position.
                min_price_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the count for the current test case
    }

    return 0; // Indicate successful execution
}

