#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int first_W = -1;
        int last_W = -1;
        int win_count = 0;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
                if (i > 0 && s[i-1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (win_count == 0) { // All L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change one L to W. Score becomes 1.
                // If k > 0, we can change one L to W.
                // If n > 1 and k > 1, we can change two Ls to Ws, score 1+2=3.
                // If n > 1 and k >= n, we can change all to Ws, score 1 + 2*(n-1).
                // The maximum score is 1 + 2*(min(k, n)-1) if min(k,n) > 0.
                // If k >= n, all become Ws, score is 1 + 2*(n-1).
                // If k < n, we can make k Ws.
                // If k=1, score is 1.
                // If k > 1, we can make k Ws in a row. Score is 1 + 2*(k-1).
                std::cout << 1 + std::max(0, 2 * (std::min(k, n) - 1)) << "\n";
            }
            continue;
        }

        // If there are some W's initially
        // We want to fill gaps between W's and extend W's at ends.
        // Filling gaps is more efficient as it converts L-W to W-W (1 point to 2 points)
        // and L-L-W to L-W-W (0 points to 2 points).
        // Extending W's at ends converts L to W (0 points to 1 point)
        // and L-W to W-W (0 points to 2 points).

        std::vector<int> gaps;
        int current_gap = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                initial_score += 2 * gap_len; // Each L in gap becomes W, connecting two Ws.
                                              // Each L in gap was 0, now 2. Net +2.
                                              // Example: W L L W -> W W W W.
                                              // L1: 0->2 (+2). L2: 0->2 (+2). Total +4.
                                              // This is correct because W L W gives 1+1=2. W W W gives 1+2+2=5. Diff 3.
                                              // My logic: W L W. L is 0. Change L to W. W W W.
                                              // The W before L was 1. Now it's 2. (+1).
                                              // The L becomes W. It's preceded by W, so it's 2. (+2).
                                              // The W after L was 1. Now it's 2. (+1).
                                              // Total +4.
                                              // No, this is wrong.
                                              // W L W. Score 1+1=2.
                                              // Change L to W. W W W. Score 1+2+2=5.
                                              // Net increase is 3.
                                              // The L becomes W. It's preceded by W, so it gets 2 points.
                                              // The W after L was getting 1 point (because L was before it). Now it gets 2 points (because W is before it).
                                              // So, for each L in a gap, it adds 2 points.
                                              // And the W *after* the gap, if it was getting 1 point, now gets 2 points.
                                              // This means for a gap of length `g`, we add `2*g` points, AND 1 point for the W after the gap.
                                              // The initial score calculation already accounts for the W after the gap getting 1 point.
                                              // If we fill the gap, that W now gets 2 points. So it's an additional 1 point.
                                              // So, for a gap of length `g`, we add `2*g + 1` points.
                                              // Let's re-evaluate.
                                              // W L W. Score 1+1=2.
                                              // Change L to W. W W W. Score 1+2+2=5.
                                              // Increase = 3.
                                              // My current logic: initial_score += 2 * gap_len. Here gap_len=1. So initial_score += 2. Total 2+2=4. Incorrect.
                                              // The L becomes W. It gets 2 points.
                                              // The W after the L was getting 1 point. Now it gets 2 points. So +1.
                                              // Total increase for one L in a gap: 2 (for the L itself) + 1 (for the next W) = 3.
                                              // For a gap of length `g`: W L...L W.
                                              // The `g` L's become W's. Each gets 2 points. So `2*g` points.
                                              // The W after the gap was getting 1 point. Now it gets 2 points. So +1 point.
                                              // Total increase: `2*g + 1`.
                                              // This is correct.
                                              // Example: W L L W. Score 1+1=2.
                                              // Change L L to W W. W W W W. Score 1+2+2+2=7.
                                              // Increase = 5.
                                              // My formula: 2*g + 1 = 2*2 + 1 = 5. Correct.
                initial_score += (2 * gap_len + 1);
            } else {
                initial_score += 2 * k; // We can only change k L's. Each L becomes W, preceded by W.
                                        // Each L was 0, now 2. Net +2.
                                        // We can't fill the whole gap, so the W after the gap still gets 1 point.
                k = 0;
                break;
            }
        }

        // After filling gaps, use remaining k to extend W's at ends.
        // Extend right side
        if (k > 0 && last_W != -1 && last_W < n - 1) {
            int right_L_count = n - 1 - last_W;
            int changes_on_right = std::min(k, right_L_count);
            initial_score += 2 * changes_on_right; // Each L becomes W, preceded by W. Net +2.
            k -= changes_on_right;
        }

        // Extend left side
        if (k > 0 && first_W != -1 && first_W > 0) {
            int left_L_count = first_W;
            int changes_on_left = std::min(k, left_L_count);
            // The first W was getting 1 point. If we extend left, it still gets 1 point.
            // The new W's on the left:
            // The one adjacent to first_W gets 2 points.
            // Others get 2 points.
            // The first new W (at the very beginning) gets 1 point.
            // This is equivalent to:
            // If we change `c` L's on the left:
            // The first L becomes W, gets 1 point.
            // The next `c-1` L's become W's, each gets 2 points.
            // Total: 1 + 2*(c-1) = 2*c - 1.
            // This is the score added by these `c` changes.
            initial_score += (2 * changes_on_left - 1);
            k -= changes_on_left;
        }

        std::cout << initial_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w to handle w_i=1 first, then w_i>1

    long long total_happiness = 0;

    // First, handle friends who get w_i = 1 integer.
    // They should get the largest available integers, as their happiness is 2 * integer.
    // These are the k largest integers from 'a'.
    int a_ptr_large = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_large];
            a_ptr_large--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here and handle them in the next loop.
            break;
        }
    }

    // Now, handle friends who get w_i > 1 integers.
    // For these friends, happiness is max_val + min_val.
    // To maximize this, they should get the largest remaining available integers as their max_val.
    // The smallest available integers should be used as their min_val.
    // The w_i values are sorted, so w[0] is the smallest w_i > 1.
    // We iterate through w from smallest w_i to largest w_i (excluding w_i=1 already handled).

    int a_ptr_small = 0; // Pointer for the smallest available integers
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // The largest remaining integer for this friend's max_val
            total_happiness += a[a_ptr_large];
            a_ptr_large--;

            // The smallest available integer for this friend's min_val
            // This friend needs w[i] integers. One is the max_val (a[a_ptr_large+1]),
            // one is the min_val (a[a_ptr_small]), and w[i]-2 integers in between.
            // We use the smallest available a[a_ptr_small] for min_val.
            // Then we skip w[i]-2 integers from the small end.
            total_happiness += a[a_ptr_small];
            a_ptr_small += (w[i] - 1); // Move pointer past the w[i]-1 smallest integers used
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We want S' = 2 * X'
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to achieve the condition with at most 3 elements.
    // Let's try to append two elements first.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2)
    // A simple choice for b1 and b2 that often works is b1 = X and b2 = S + X.
    // Let's verify this.
    // If we append X and S+X:
    // New sum S' = S + X + (S + X) = 2S + 2X
    // New XOR sum X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // Is S' = 2 * X'?
    // Is 2S + 2X = 2 * (S + X)?
    // Yes, this is true.
    // So, we can always append X and S+X.
    // The problem states that appended elements can be up to 10^18.
    // S can be up to 10^5 * 10^9 = 10^14.
    // X can be up to 2^30 - 1 (approx 10^9).
    // S+X can be up to 10^14 + 10^9, which fits in long long.
    // This strategy uses 2 elements.

    // Output 2 elements:
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

