void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> final_s(n, '?');
    bool possible = true;

    // Step 1: Propagate known characters based on s[i] == s[i+k] property
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (final_s[i] == '?') {
                final_s[i] = s[i];
            } else if (final_s[i] != s[i]) {
                possible = false;
                break;
            }
        }
        if (final_s[i] != '?') {
            // Propagate forward
            for (int j = i + k; j < n; j += k) {
                if (final_s[j] == '?') {
                    final_s[j] = final_s[i];
                } else if (final_s[j] != final_s[i]) {
                    possible = false;
                    break;
                }
            }
            if (!possible) break;
            // Propagate backward
            for (int j = i - k; j >= 0; j -= k) {
                if (final_s[j] == '?') {
                    final_s[j] = final_s[i];
                } else if (final_s[j] != final_s[i]) {
                    possible = false;
                    break;
                }
            }
            if (!possible) break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check consistency with original string s
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?' && final_s[i] != '?' && s[i] != final_s[i]) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 3: Check the first k characters for balance
    int count0 = 0;
    int count1 = 0;
    int countQ = 0;

    for (int i = 0; i < k; ++i) {
        if (final_s[i] == '0') {
            count0++;
        } else if (final_s[i] == '1') {
            count1++;
        } else { // final_s[i] == '?'
            countQ++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    } else {
        // We need (k/2 - count0) more zeros and (k/2 - count1) more ones.
        // The remaining '?' must be able to fill these.
        // The total number of '?' is countQ.
        // (k/2 - count0) + (k/2 - count1) = k - (count0 + count1)
        // This must be equal to countQ.
        // Since count0 + count1 + countQ = k, this condition is always met if count0 <= k/2 and count1 <= k/2.
        // So, if count0 <= k/2 and count1 <= k/2, we can always fill the '?'s in the first k positions
        // to make it k/2 zeros and k/2 ones.
        // The specific values for '?' don't matter beyond the first k positions,
        // as long as the first k positions can be balanced.
        // The propagation logic ensures that if final_s[i] is determined, then final_s[i+k], final_s[i+2k] etc.
        // are also determined to be the same character.
        // If final_s[i] is '?', then final_s[i+k], final_s[i+2k] etc. are also '?'.
        // So, if we assign a '?' in final_s[i] to '0' or '1', all final_s[i+m*k] will also be assigned that same character.
        // This means the balance of the first k characters determines the balance of all k-length substrings.
        // If the first k characters can be balanced, then all subsequent k-length substrings will also be balanced.
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

