#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the m+1 potential blocks
        // created by the m ones (or m-1 ones if we consider ones as separators).
        // The optimal configuration places ones such that the blocks of zeros are as short as possible.
        // This means distributing the 'num_zeros' zeros into 'm+1' potential segments.
        // However, the 'm' ones act as separators. If we have 'm' ones, they divide the string into 'm+1'
        // possible segments where zeros can be placed.
        // For example, 10101 has 3 ones and 2 zeros. The zeros are in 2 segments.
        // 01010 has 2 ones and 3 zeros. The zeros are in 3 segments.
        // The key insight is that to minimize zero-only substrings, we want to make the blocks of zeros
        // as small as possible. This means distributing the 'num_zeros' zeros as evenly as possible
        // into 'm+1' segments (before the first '1', between '1's, and after the last '1').
        // The 'm' ones effectively create 'm+1' "slots" for zeros.
        // For example, _ 1 _ 1 _ ... _ 1 _
        // The number of zeros is `num_zeros`.
        // We distribute these `num_zeros` into `m+1` slots.
        // This is equivalent to distributing `num_zeros` items into `m+1` bins.
        // Some bins will have `k` zeros, and some will have `k+1` zeros.
        // Let `k = num_zeros / (m + 1)` be the base number of zeros in each segment.
        // Let `r = num_zeros % (m + 1)` be the number of segments that get an additional zero.
        // So, `r` segments will have `k+1` zeros, and `(m+1) - r` segments will have `k` zeros.

        // However, this is not quite right. The problem is about minimizing the number of zero-only substrings.
        // This is achieved by making the blocks of zeros as short as possible.
        // The 'm' ones divide the 'n' positions into 'm' ones and 'n-m' zeros.
        // The 'm' ones effectively create 'm-1' internal gaps and 2 external gaps (before first '1', after last '1').
        // The total number of '0's is `num_zeros`.
        // We want to distribute these `num_zeros` into `m+1` "slots" (before the first '1', between any two '1's, after the last '1').
        // The number of '0's in each slot should be as equal as possible.
        // Let `q = num_zeros / (m + 1)` be the quotient.
        // Let `rem = num_zeros % (m + 1)` be the remainder.
        // So, `rem` slots will have `q + 1` zeros, and `(m + 1) - rem` slots will have `q` zeros.

        // The number of substrings consisting only of zeros from a block of `k` zeros is `k * (k + 1) / 2`.
        // So, the total number of zero-only substrings is:
        // `rem * ((q + 1) * (q + 2) / 2)`  (for segments with q+1 zeros)
        // `+ ((m + 1) - rem) * (q * (q + 1) / 2)` (for segments with q zeros)

        // This is the correct approach for minimizing zero-only substrings.
        // Let `k` be the number of blocks of zeros.
        // If `m > 0`, the `m` ones divide the string into at most `m+1` blocks of zeros.
        // For example, "01010" (n=5, m=2). Zeros: 3. Blocks: 3. (0, 0, 0).
        // q = 3 / (2+1) = 1. rem = 0. All 3 blocks have 1 zero.
        // 3 * (1 * 2 / 2) = 3.
        // Total substrings = 5*6/2 = 15. f(s) = 15 - 3 = 12. Matches example.

        // Example: n=3, m=1. Zeros: 2. Blocks: 1+1=2.
        // q = 2 / 2 = 1. rem = 0. All 2 blocks have 1 zero.
        // 2 * (1 * 2 / 2) = 2.
        // Total substrings = 3*4/2 = 6. f(s) = 6 - 2 = 4. Matches example.

        // Example: n=3, m=2. Zeros: 1. Blocks: 2+1=3.
        // q = 1 / 3 = 0. rem = 1.
        // 1 block has 1 zero. 2 blocks have 0 zeros.
        // 1 * (1 * 2 / 2) + 2 * (0 * 1 / 2) = 1.
        // Total substrings = 3*4/2 = 6. f(s) = 6 - 1 = 5. Matches example.

        long long q = num_zeros / (m + 1);
        long long rem = num_zeros % (m + 1);

        long long zero_substrings_count = 0;
        // Segments with q+1 zeros
        zero_substrings_count += rem * ((q + 1) * (q + 2) / 2);
        // Segments with q zeros
        zero_substrings_count += ((m + 1) - rem) * (q * (q + 1) / 2);

        long long max_f_s = total_substrings - zero_substrings_count;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit
    // For each bit position j (0 to 9):
    // bit_state[j][0] = result if input bit j is 0
    // bit_state[j][1] = result if input bit j is 1
    // Initially, if input bit j is 0, output bit j is 0. If input bit j is 1, output bit j is 1.
    // So, bit_state[j][0] = 0, bit_state[j][1] = 1
    std::vector<std::vector<int>> bit_state(10, std::vector<int>(2));
    for (int j = 0; j < 10; ++j) {
        bit_state[j][0] = 0; // If input bit j is 0, current output bit j is 0
        bit_state[j][1] = 1; // If input bit j is 1, current output bit j is 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_val = (val >> j) & 1; // j-th bit of the constant 'val'

            if (op_char == '&') {
                bit_state[j][0] &= bit_val;
                bit_state[j][1] &= bit_val;
            } else if (op_char == '|') {
                bit_state[j][0] |= bit_val;
                bit_state[j][1] |= bit_val;
            } else { // op_char == '^'
                bit_state[j][0] ^= bit_val;
                bit_state[j][1] ^= bit_val;
            }
        }
    }

    // Now, bit_state[j][0] is the final j-th bit if input j-th bit was 0.
    // And bit_state[j][1] is the final j-th bit if input j-th bit was 1.

    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_output
    // Or a shorter sequence.

    // Let's determine the values for the three potential operations:
    // 1. AND mask (A): If a bit j is forced to 0 regardless of input (bit_state[j][0]=0, bit_state[j][1]=0),
    //    then A must have 0 at bit j. Otherwise, A can have 1 at bit j.
    //    So, A_j = bit_state[j][1] (if bit_state[j][0] == 0, then A_j must be 0. If bit_state[j][0] == 1, this case is impossible for AND mask)
    //    More simply, A_j = 1 if bit_state[j][0] == 0 and bit_state[j][1] == 1 (pass-through)
    //    A_j = 0 if bit_state[j][0] == 0 and bit_state[j][1] == 0 (force to 0)
    //    A_j = 0 if bit_state[j][0] == 1 and bit_state[j][1] == 1 (force to 1, handled by OR)
    //    A_j = 0 if bit_state[j][0] == 1 and bit_state[j][1] == 0 (flip, handled by XOR)
    //    This is equivalent to A_j = bit_state[j][1] if bit_state[j][0] == 0, else 0.
    //    This is equivalent to A_j = bit_state[j][1] (if bit_state[j][0] == 0)
    //    A_j = 1 if the bit is passed through (0->0, 1->1)
    //    A_j = 0 if the bit is forced to 0 (0->0, 1->0)
    //    A_j = 0 if the bit is forced to 1 (0->1, 1->1)
    //    A_j = 0 if the bit is flipped (0->1, 1->0)
    //    So, A_j = 1 only if (bit_state[j][0] == 0 && bit_state[j][1] == 1)
    //    Otherwise A_j = 0.
    int and_val = 0;
    for (int j = 0; j < 10; ++j) {
        if (bit_state[j][0] == 0 && bit_state[j][1] == 1) {
            and_val |= (1 << j);
        }
    }

    // 2. OR mask (B): If a bit j is forced to 1 regardless of input (bit_state[j][0]=1, bit_state[j][1]=1),
    //    then B must have 1 at bit j. Otherwise, B can have 0 at bit j.
    //    So, B_j = 1 if (bit_state[j][0] == 1 && bit_state[j][1] == 1)
    //    Otherwise B_j = 0.
    int or_val = 0;
    for (int j = 0; j < 10; ++j) {
        if (bit_state[j][0] == 1 && bit_state[j][1] == 1) {
            or_val |= (1 << j);
        }
    }

    // 3. XOR mask (C): If a bit j is flipped (0->1, 1->0), then C must have 1 at bit j.
    //    This happens if (bit_state[j][0] == 1 && bit_state[j][1] == 0)
    //    Or if (bit_state[j][0] == 0 && bit_state[j][1] == 1) but after AND and OR, it's 0->0, 1->1.
    //    Let's consider the state after applying AND and OR.
    //    For an input bit x_j:
    //    (x_j & and_val_j) | or_val_j
    //    If x_j = 0: (0 & and_val_j) | or_val_j = 0 | or_val_j = or_val_j
    //    If x_j = 1: (1 & and_val_j) | or_val_j = and_val_j | or_val_j
    //
    //    We need:
    //    (0 & and_val_j | or_val_j) ^ xor_val_j = bit_state[j][0]
    //    (1 & and_val_j | or_val_j) ^ xor_val_j = bit_state[j][1]
    //
    //    So, or_val_j ^ xor_val_j = bit_state[j][0]
    //    (and_val_j | or_val_j) ^ xor_val_j = bit_state[j][1]
    //
    //    From the first equation: xor_val_j = or_val_j ^ bit_state[j][0]
    //    Let's verify this with the second equation:
    //    (and_val_j | or_val_j) ^ (or_val_j ^ bit_state[j][0])
    //    We know:
    //    If bit_state[j][0] == 0 && bit_state[j][1] == 0: and_val_j=0, or_val_j=0. xor_val_j = 0^0=0. (0|0)^0 = 0. Correct.
    //    If bit_state[j][0] == 0 && bit_state[j][1] == 1: and_val_j=1, or_val_j=0. xor_val_j = 0^0=0. (1|0)^0 = 1. Correct.
    //    If bit_state[j][0] == 1 && bit_state[j][1] == 0: and_val_j=0, or_val_j=0. xor_val_j = 0^1=1. (0|0)^1 = 1. Correct.
    //    If bit_state[j][0] == 1 && bit_state[j][1] == 1: and_val_j=0, or_val_j=1. xor_val_j = 1^1=0. (0|1)^0 = 1. Correct.
    //
    //    So, xor_val_j = or_val_j ^ bit_state[j][0] is the correct way to determine the XOR mask.
    int xor_val = 0;
    for (int j = 0; j < 10; ++j) {
        int current_bit_after_and_or_for_0 = ((0 & ((and_val >> j) & 1)) | ((or_val >> j) & 1));
        if (current_bit_after_and_or_for_0 != bit_state[j][0]) {
            xor_val |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (and_val != 1023) { // If not all bits are 1, then AND operation is meaningful
        result_ops.push_back({'&', and_val});
    }
    if (or_val != 0) { // If not all bits are 0, then OR operation is meaningful
        result_ops.push_back({'|', or_val});
    }
    if (xor_val != 0) { // If not all bits are 0, then XOR operation is meaningful
        result_ops.push_back({'^', xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n < 3) { // Should not happen based on constraints (n >= 3)
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2) ? 1 : 0;
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Constraints say n >= 3, but good to be robust
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the first 0-1 transition from left
    int first_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            first_one_idx = i;
            break;
        }
    }

    // Find the last 1-0 transition from right
    int last_zero_idx = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            last_zero_idx = i;
            break;
        }
    }

    if (first_one_idx == -1 || last_zero_idx == -1 || first_one_idx > last_zero_idx) {
        // Sequence is all 0s or all 1s, or already stable (e.g., 000111)
        // In these cases, the sequence is already stable.
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate max_k
    int max_k = 0;
    int current_len = 0;
    for (int i = first_one_idx; i <= last_zero_idx; ++i) {
        if (a[i] == 0) {
            current_len++;
        } else {
            max_k = std::max(max_k, (current_len + 1) / 2);
            current_len = 0;
        }
    }
    max_k = std::max(max_k, (current_len + 1) / 2); // For the last segment of zeros

    // Apply smoothing max_k times
    std::vector<int> current_seq = a;
    for (int k = 0; k < max_k; ++k) {
        current_seq = apply_median_smoothing(current_seq);
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> adj_matrix(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> adj_matrix[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Initially no vertices are active

    // Process in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // Floyd-Warshall step: d[i][j] = min(d[i][j], d[i][k] + d[k][j])
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active vertices
                if (adj_matrix[i][k] + adj_matrix[k][j] < adj_matrix[i][j]) {
                    adj_matrix[i][j] = adj_matrix[i][k] + adj_matrix[k][j];
                }
            }
        }

        // After adding vertex k and updating paths through it,
        // we need to re-check all pairs of currently active vertices
        // for paths that might now be shorter due to other active vertices.
        // This is essentially running Floyd-Warshall on the subgraph of active vertices.
        // The previous loop only updated paths using k as an intermediate.
        // We need to ensure all active vertices are considered as intermediates.
        // Since we are adding vertices one by one, and the adj_matrix stores
        // the current shortest paths considering all *previously added* vertices,
        // the standard Floyd-Warshall triple loop structure is needed.
        // The `k` in the Floyd-Warshall algorithm is the intermediate vertex.
        // Here, `k_fw` iterates through all currently active vertices.
        for (int k_fw = 0; k_fw < n; ++k_fw) {
            if (!active_vertices[k_fw]) continue;
            for (int i = 0; i < n; ++i) {
                if (!active_vertices[i]) continue;
                for (int j = 0; j < n; ++j) {
                    if (!active_vertices[j]) continue;
                    if (adj_matrix[i][k_fw] + adj_matrix[k_fw][j] < adj_matrix[i][j]) {
                        adj_matrix[i][j] = adj_matrix[i][k_fw] + adj_matrix[k_fw][j];
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                // We need sum of d(v,u) for v != u.
                // The problem statement implies v != u, but d(v,v) is 0 anyway.
                // So summing all d(v,u) for active v,u is fine.
                current_sum += adj_matrix[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, k=0 (2^0-1=0, but we need 1 element)
            k = 0;
        } else {
            k = std::floor(std::log2(X + 1));
        }

        // If 2^k - 1 is exactly X, we can use k elements.
        // If 2^k - 1 < X, we use k elements and then process the remainder.
        // If 2^k - 1 > X, it means k was too large. This happens if X+1 is not a power of 2.
        // In this case, we need to find the largest k such that 2^k - 1 <= X.
        // The floor(log2(X+1)) already gives this k.
        // For example, if X=10, X+1=11, log2(11) approx 3.45, floor is 3.
        // 2^3-1 = 7. We use 3 elements. X becomes 10-7=3.
        // Next, X=3, X+1=4, log2(4)=2, floor is 2.
        // 2^2-1 = 3. We use 2 elements. X becomes 3-3=0.
        // Total elements: 3 + 2 = 5.
        // This strategy works.

        long long num_elements_for_k = k + 1; // We add k+1 elements to the array
                                             // The first k elements will be 'current_val'
                                             // The (k+1)-th element will be 'current_val + d'
                                             // This creates 2^k subsequences of 'current_val'
                                             // and 1 subsequence of 'current_val + d'
                                             // Total 2^k subsequences.
                                             // The number of subsequences formed by k identical elements is 2^k-1.
                                             // The number of subsequences formed by k identical elements and one distinct element is 2^k.
                                             // Let's re-evaluate.
                                             // If we add 'k' identical elements, say 'A', we get 2^k-1 subsequences.
                                             // If we add 'k' identical elements 'A' and one element 'B' such that B-A >= d,
                                             // then the subsequences containing both A and B are removed.
                                             // The remaining subsequences are those containing only A's (2^k-1) and those containing only B (1).
                                             // Total 2^k.
                                             // So, if we want to add 2^k subsequences, we can add k identical elements and one element far away.
                                             // The number of elements to add is k+1.
                                             // The number of subsequences contributed is 2^k.

        // The number of subsequences we want to contribute is X.
        // We want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=10, k=floor(log2(10))=3. 2^3=8.
        // We add 3 identical elements (current_val) and one element (current_val + d).
        // This contributes 2^3 = 8 subsequences.
        // X becomes 10-8=2.
        // Next, X=2, k=floor(log2(2))=1. 2^1=2.
        // We add 1 identical element (current_val') and one element (current_val' + d).
        // This contributes 2^1 = 2 subsequences.
        // X becomes 2-2=0.
        // This strategy seems correct.

        // Let's refine k: we want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=1, k=0. 2^0=1.
        // If X=10, k=3. 2^3=8.
        // If X=4, k=2. 2^2=4.

        long long current_k = 0;
        if (X > 0) { // log2(0) is undefined, log2(1) is 0
            current_k = std::floor(std::log2(X));
        }

        // Add current_k identical elements of value `current_val`
        for (int i = 0; i < current_k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the contributed subsequences
        X -= (1LL << current_k);

        // Prepare for the next block of elements
        // The next block of elements must be sufficiently far from the current block
        // to ensure that subsequences mixing elements from different blocks are removed.
        // We add d to current_val, then add 1 to ensure it's strictly greater than current_val + d - 1.
        // This ensures that current_val_next - current_val >= d.
        current_val += d + 1;

        // Check for overflow
        if (current_val >= 1000000000000000000LL) { // 10^18
            // This case should ideally not be reached if X is within limits and d is positive.
            // The maximum number of elements is 10^4.
            // Max current_val would be roughly 1 + (10^4) * (10^9 + 1) which is too large.
            // However, the number of distinct values is at most 60 (log2(10^9)).
            // So current_val will be 1 + 60 * (d+1).
            // 1 + 60 * (10^9 + 1) is approx 6 * 10^10, which is < 10^18.
            // So overflow for current_val is not an issue.
        }
    }

    // The problem states that the number of elements in the output array should not be more than 10^4.
    // The maximum value of X is 10^9.
    // The maximum k is floor(log2(10^9)) = 29.
    // In the worst case, X is a sum of powers of 2.
    // E.g., X = 2^29 + 2^28 + ... + 2^0. This would be 30 blocks.
    // Each block adds at most 29 elements.
    // So, total elements would be at most 30 * 29 = 870.
    // This is well within the 10^4 limit.

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
