    // s[i...j] contains the pattern. If no such j exists, dp[i] = n.
    // This means for a given l (0-indexed), any r (0-indexed) such that l <= r < dp[l]
    // will form a valid substring s[l...r] that does NOT contain the pattern.
    // The number of such r's is dp[l] - l.

    // Initialize dp array. dp[i] = n means no pattern starting at or after i.
    std::vector<int> dp(n + 1, n); 

    // Iterate backwards from n-1 down to 0
    for (int i = n - 1; i >= 0; --i) {
