            // Thus, 't' is not enough.
            return false;
        }

        // Advance p_idx to cover all tracks reachable by current_h
        while (p_idx < m && p[p_idx] <= right_reach) {
            p_idx++;
        }
    }
    // All target tracks are covered if p_idx reached the end of p
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance: (max_p - min_h) or (max_h - min_p)
    // A safe upper bound is the maximum possible coordinate value.
    // 10^10 is the max coordinate, so 2 * 10^10 is a safe upper bound for distance.
    long long high = 20000000000LL; 
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f values are of the form a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-2].value + a[n-1].value + h.
    // This happens if a[0] and a[1] are in the same group, and a[n-2] and a[n-1] are in different groups.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in the same group.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in different groups.
    // The minimum f value will be min(a[0].value + a[1].value, a[0].value + a[1].value + h).
    // The maximum f value will be max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h).
    //
    // The critical observation is that if we have two non-empty subsequences,
    // then there must be at least one pair (a_i, a_j) in the same subsequence,
    // and at least one pair (a_k, a_l) in different subsequences.
    //
    // So, min_f will be at most a[0].value + a[1].value.
    // And max_f will be at least a[n-2].value + a[n-1].value + h.
    //
    // However, we can try to make the minimum f value as large as possible,
    // and the maximum f value as small as possible.
    //
    // Consider a partition where a[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a[0].value + a[1].value + h (a[0] in group 1, a[1] in group 2)
    //   - a[1].value + a[2].value (a[1], a[2] in group 2)
    //   The minimum of these two is a[1].value + a[2].value.
    // max_f:
    //   - a[n-2].value + a[n-1].value (a[n-2], a[n-1] in group 2)
    //   - a[0].value + a[n-1].value + h (a[0] in group 1, a[n-1] in group 2)
    //   The maximum of these two is a[0].value + a[n-1].value + h.
    //
    // Goodness = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Let's simplify.
    // The smallest possible sum is `a[0].value + a[1].value`.
    // The largest possible sum is `a[n-1].value + a[n-2].value`.
    //
    // If we put `a[0]` in group 1 and all others in group 2:
    // Pairs in same group: `(a[i], a[j])` for `i,j >= 1`. Smallest is `a[1].value + a[2].value`. Largest is `a[n-2].value + a[n-1].value`.
    // Pairs in different groups: `(a[0], a[j])` for `j >= 1`. Smallest is `a[0].value + a[1].value + h`. Largest is `a[0].value + a[n-1].value + h`.
    //
    // So, for this partition:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // Goodness = max_f - min_f;
    //
    // This is the goodness for the partition where a[0] is in group 1, and all others are in group 2.
    // Let's call this goodness2.
    long long min_f2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long max_f2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
    long long goodness2 = max_f2 - min_f2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        std::vector<int> result_partition(n);
        for (int i = 0; i < n; ++i) {
            result_partition[a[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> result_partition(n);
        result_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[a[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate multiple such values.
// x is an index, so it fits in int, but intermediate calculations for x might exceed int range
// if a_x is large, though the problem constraints on n (2*10^5) mean x itself won't exceed int.
// However, x can become negative or very large, so it's safer to use long long for x in calculations
// to avoid overflow issues before the termination check.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_1 is not given, it's varied for each test case.
    // a_2 to a_n are given.
    // We'll use 1-based indexing for convenience, so vector size n+1.
    // a[0] will be unused.
    std::vector<long long> a_fixed(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_fixed[i];
    }

    // Memoization table for results.
    // dp[i] stores the pair {final_x, final_y} if starting at x=i, y=0 and taking one full step (x+a_x, y+a_x, then x-a_x, y+a_x).
    // Or, more precisely, dp[i] stores the result of the *next* full cycle if we are at x=i.
    // This is a bit tricky because the problem defines steps 2 and 3.
    // Let's define dp[i] as the result of starting at x=i, y=0 and performing the sequence of operations
    // until termination or loop.
    // This is a dynamic programming approach where we compute results for larger x values first.
    // The problem states x can go up to n.
    // When x becomes x + a_x, it can jump far.
    // When x becomes x - a_x, it can jump far.
    // This suggests a recursive solution with memoization or a specific DP order.

    // Let's define dp[i] as the pair {delta_x, delta_y} if we start at x=i and perform one full cycle
    // (x+a_x, y+a_x, then x-a_x, y+a_x) and then recursively call for the new x.
    // This is essentially finding the total delta_x and delta_y from a starting point.
    // We need to handle cycles.

    // dp[i] will store {total_y_change, final_x_after_termination}
    // If it terminates, final_x_after_termination will be <=0 or >n.
    // If it loops, final_x_after_termination will be a special value (e.g., 0, or -1, or -2).
    // Let's use -1 for non-terminating.
    // We need to store the state of computation for each starting x.
    // 0: unvisited
    // 1: visiting (part of current path, potential cycle)
    // 2: visited (result computed)
    std::vector<int> state(n + 1, 0);
    std::vector<std::pair<long long, long long>> memo(n + 1); // {total_y, final_x}

    // Function to compute the result for a given starting x.
    // Returns {total_y_accumulated, final_x_value}.
    // If it loops, returns {-1, -1}.
    auto solve = [&](auto self, long long current_x) -> std::pair<long long, long long> {
        if (current_x <= 0 || current_x > n) {
            return {0, current_x}; // Terminated, no more y added, current_x is the final x.
        }

        // If already computed, return memoized result.
        if (state[current_x] == 2) {
            return memo[current_x];
        }

        // If currently visiting, we found a cycle.
        if (state[current_x] == 1) {
            return {-1, -1}; // Indicate non-termination
        }

        state[current_x] = 1; // Mark as visiting

        long long val1 = a_fixed[current_x];
        long long next_x1 = current_x + val1;
        long long y_added1 = val1;

        // Check termination after first part of the step
        if (next_x1 <= 0 || next_x1 > n) {
            state[current_x] = 2; // Mark as visited
            memo[current_x] = {y_added1, next_x1};
            return memo[current_x];
        }

        long long val2 = a_fixed[next_x1];
        long long next_x2 = next_x1 - val2;
        long long y_added2 = val2;

        // Recursively call for the next state
        std::pair<long long, long long> res = self(self, next_x2);

        long long total_y = y_added1 + y_added2;
        long long final_x = res.second;

        if (res.first == -1) { // If recursive call indicated non-termination
            total_y = -1;
            final_x = -1;
        } else {
            total_y += res.first;
        }

        state[current_x] = 2; // Mark as visited
        memo[current_x] = {total_y, final_x};
        return memo[current_x];
    };

    // For each i from 1 to n-1, set a_1 = i and run the program.
    for (int i = 1; i < n; ++i) {
        a_fixed[1] = i; // Set a_1 for the current run

        // Reset state and memoization for each run.
        // This is inefficient if n is large.
        // The problem structure suggests that a_1 is the only changing part.
        // The values a_2...a_n are fixed.
        // The DP state depends on a_x. If a_x changes, the DP state changes.
        // However, a_x only changes for x=1.
        // So, for x > 1, the results of solve(x) are always the same.
        // We only need to recompute for x=1.
        // For x > 1, the results are independent of a_1.
        // So, we can compute solve(x) for x=2 to n once.

        // Let's optimize:
        // Only reset state[1] to 0.
        // For other states, if a_fixed[x] hasn't changed, their memoized value is still valid.
        // But the `state` array needs to be cleared for each run to detect cycles correctly
        // because a cycle might involve `x=1` which has a new `a_1`.
        // A full reset is needed for `state` and `memo` for each `i` if `a_1` affects all paths.
        // The problem statement implies `a_1` is set for the *entire* run.
        // So, for each `i`, we have a *new* sequence `i, a_2, ..., a_n`.
        // This means the `a_fixed` array is effectively different for each `i`.
        // Therefore, a full reset of `state` and `memo` is necessary for each `i`.
        // This makes the complexity O(N * N) which is too slow for N=2*10^5.

        // Let's re-read: "Suppose for each i (1 ≤ i ≤ n - 1) we run the program on the sequence i, a_2, a_3, ..., a_{n}."
        // This means a_1 is set to `i` for *that specific run*.
        // So, `a_fixed[1]` changes for each iteration of the outer loop.
        // This means the `solve` function's behavior changes for any path that involves `x=1`.
        // A full reset of `state` and `memo` is indeed required for each `i`.
        // This implies the DP approach as written is too slow.

        // Let's reconsider the problem constraints and structure.
        // N = 2 * 10^5. O(N^2) is 4 * 10^10, too slow.
        // We need something faster, likely O(N log N) or O(N).

        // The key observation must be that `a_x` is only `a_1` or `a_k` for `k >= 2`.
        // `a_k` for `k >= 2` are fixed.
        // `a_1` changes.
        // When `x` is not 1, `a_x` is fixed.
        // When `x` is 1, `a_x` is `i`.

        // Let's analyze the path:
        // Start at x=1.
        // Step 1: x = 1 + a_1, y = a_1.
        // Step 2: x = (1 + a_1) - a_{1+a_1}, y = a_1 + a_{1+a_1}.
        // From this point, if x != 1, the path is independent of the initial `a_1` value.
        // If x == 1, it depends on `a_1` again.

        // This structure suggests that we can precompute results for all `x` from `2` to `n`.
        // For `x` from `2` to `n`, `a_x` is fixed.
        // So, `solve(x)` for `x >= 2` will always yield the same result.
        // We can compute these once.
        // Then, for each `i`, we only need to compute `solve(1)` using the current `a_1 = i`.

        // Let's modify the DP:
        // `state` and `memo` should be global or passed around.
        // We need to clear `state` and `memo` only for `x=1` for each iteration.
        // But `solve` is recursive. If `solve(1)` calls `solve(k)` where `k != 1`,
        // and `solve(k)` then calls `solve(1)`, we have a cycle involving `1`.
        // If `solve(k)` calls `solve(j)` where `j != 1`, and `solve(j)` calls `solve(k)`,
        // this is a cycle not involving `1`. This cycle's result is fixed.

        // Let's compute `solve(x)` for `x = n` down to `2`.
        // This ensures that when `solve(x)` is called, any `solve(x')` it depends on (where `x'` is the next state)
        // will have already been computed if `x'` is within the range `[2, n]` and `x'` is "further along" in some sense.
        // The issue is that `x` can jump arbitrarily. `x+a_x` or `x-a_x` can be any value.
        // So, a simple `n` down to `2` loop won't guarantee dependencies are met.
        // A true recursive DP with memoization is the correct way to handle arbitrary jumps and cycles.

        // The `state` array is crucial for cycle detection.
        // If `state` is fully reset for each `i`, it's O(N^2).
        // If `state` is not fully reset, `solve(x)` for `x != 1` might return a result that was computed
        // when `a_1` was different, if its path eventually led to `x=1`.
        // This is the core problem.

        // What if we only clear `state[1]` and `memo[1]`?
        // When `solve(k)` is called (k != 1), it might eventually reach `x=1`.
        // If `state[1]` is 0, it will compute `solve(1)` with the current `a_1`.
        // If `state[1]` is 1, it means `solve(1)` is currently on the stack, so it's a cycle.
        // If `state[1]` is 2, it means `solve(1)` was already computed for the *current* `a_1`.
        // This seems correct.

        // So, for each `i`:
        // 1. Set `a_fixed[1] = i`.
        // 2. Reset `state[1] = 0` and `memo[1]` to default.
        // 3. Call `solve(solve, 1)`.

        // This approach is still problematic.
        // Consider `solve(k)` where `k != 1`.
        // If `solve(k)` was called in a previous iteration (for a different `a_1`),
        // and its path did *not* involve `x=1`, then its memoized result is valid.
        // If its path *did* involve `x=1`, then its memoized result is invalid because `a_1` changed.
        // So, `state[k]` and `memo[k]` for `k != 1` are only valid if their computation path
        // did not depend on `a_1`.

        // This means we need to know if a path from `x` to termination (or cycle) involves `x=1`.
        // Let `memo[x]` store `{total_y, final_x, depends_on_a1}`.
        // `depends_on_a1` is a boolean.

        // Let's refine the DP state:
        // `memo[x]` stores `std::tuple<long long, long long, bool>`:
        // `{total_y_change, final_x_value, bool_depends_on_a1}`
        // `state[x]` still 0, 1, 2.

        std::vector<std::tuple<long long, long long, bool>> memo_optimized(n + 1);
        std::vector<int> state_optimized(n + 1, 0); // 0: unvisited, 1: visiting, 2: visited

        auto solve_optimized = [&](auto self, long long current_x) -> std::tuple<long long, long long, bool> {
            if (current_x <= 0 || current_x > n) {
                return {0, current_x, false}; // Terminated, no more y added, current_x is the final x. Doesn't depend on a_1.
            }

            // If already computed and doesn't depend on a_1, return memoized result.
            // If it depends on a_1, it's invalid for the current a_1 unless current_x is 1.
            if (state_optimized[current_x] == 2) {
                if (current_x != 1 && std::get<2>(memo_optimized[current_x])) {
                    // This result depends on a_1, but we are not at x=1.
                    // This means the path from current_x to termination went through x=1.
                    // So, this memoized result is invalid for the current a_1.
                    // We need to recompute.
                    // To recompute, we need to mark it as unvisited.
                    state_optimized[current_x] = 0;
                } else {
                    return memo_optimized[current_x];
                }
            }

            // If currently visiting, we found a cycle.
            if (state_optimized[current_x] == 1) {
                return {-1, -1, true}; // Indicate non-termination, and it depends on a_1 (because it's a cycle).
            }

            state_optimized[current_x] = 1; // Mark as visiting

            long long val1 = a_fixed[current_x];
            long long next_x1 = current_x + val1;
            long long y_added1 = val1;

            bool depends_on_a1_current_step = (current_x == 1);

            // Check termination after first part of the step
            if (next_x1 <= 0 || next_x1 > n) {
                state_optimized[current_x] = 2; // Mark as visited
                memo_optimized[current_x] = {y_added1, next_x1, depends_on_a1_current_step};
                return memo_optimized[current_x];
            }

            long long val2 = a_fixed[next_x1];
            long long next_x2 = next_x1 - val2;
            long long y_added2 = val2;

            // Recursively call for the next state
            std::tuple<long long, long long, bool> res = self(self, next_x2);

            long long total_y = y_added1 + y_added2;
            long long final_x = std::get<1>(res);
            bool depends_on_a1_recursive = std::get<2>(res);

            bool current_path_depends_on_a1 = depends_on_a1_current_step || depends_on_a1_recursive;

            if (std::get<0>(res) == -1) { // If recursive call indicated non-termination
                total_y = -1;
                final_x = -1;
            } else {
                total_y += std::get<0>(res);
            }

            state_optimized[current_x] = 2; // Mark as visited
            memo_optimized[current_x] = {total_y, final_x, current_path_depends_on_a1};
            return memo_optimized[current_x];
        };

        // Precompute for x from 2 to n.
        // These results will be valid as long as their path doesn't involve x=1.
        // If they do involve x=1, their `depends_on_a1` flag will be true.
        // We iterate from n down to 2 to try and fill memo for larger indices first,
        // but the recursive nature handles arbitrary jumps.
        for (int k = 2; k <= n; ++k) {
            if (state_optimized[k] == 0) { // Only compute if not already computed
                solve_optimized(solve_optimized, k);
            }
        }

        // Now, for each i:
        for (int i = 1; i < n; ++i) {
            a_fixed[1] = i; // Set a_1 for the current run

            // Reset state and memo for x=1.
            // This is crucial because a_1 changes.
            state_optimized[1] = 0;
            // No need to explicitly clear memo_optimized[1], it will be overwritten.

            std::tuple<long long, long long, bool> result = solve_optimized(solve_optimized, 1);
            std::cout << std::get<0>(result) << "\n";
        }

    // The optimized DP approach:
    // The `solve_optimized` function correctly handles memoization and cycle detection.
    // The `depends_on_a1` flag ensures that results for `x != 1` that depend on `a_1` are recomputed.
    // The initial loop `for (int k = 2; k <= n; ++k)` computes all paths starting at `k >= 2`
    // that do not involve `x=1`. If they involve `x=1`, their `depends_on_a1` flag will be true.
    // For each `i` in the outer loop:
    //   `a_fixed[1]` is set.
    //   `state_optimized[1]` is reset to 0.
    //   `solve_optimized(solve_optimized, 1)` is called.
    //   When `solve_optimized(..., 1)` is called, it will use the current `a_fixed[1]`.
    //   If it calls `solve_optimized(..., k)` for `k != 1`:
    //     If `memo_optimized[k]` is valid (state 2 and `!depends_on_a1`), it uses it.
    //     If `memo_optimized[k]` is invalid (state 2 and `depends_on_a1`), it recomputes `solve_optimized(..., k)`.
    //     This recomputation will correctly use the current `a_fixed[1]` if it hits `x=1` again.
    // This seems to be the correct approach.

    // Complexity:
    // The `for (int k = 2; k <= n; ++k)` loop: Each `solve_optimized(..., k)` for `k >= 2` is called at most once
    // if its path doesn't involve `x=1`. If it involves `x=1`, it might be recomputed.
    // The total number of states is N. Each state computation involves constant work + recursive calls.
    // In the worst case, a path from `k` to termination might visit `x=1` multiple times.
    // The `depends_on_a1` flag helps.
    // A state `(x, a_1_value)` is unique. But we only memoize `x`.
    // The `depends_on_a1` flag means that if a path from `x` depends on `a_1`, its memoized value is only valid
    // for the `a_1` it was computed with.
    // When `solve_optimized(..., k)` is called for `k != 1`, and it has `state_optimized[k] == 2` and `depends_on_a1 == true`,
    // it means it was computed with a *previous* `a_1`. So it needs to be recomputed.
    // This recomputation will traverse the path again.
    // The total number of edges in the state graph is `2N`.
    // Each edge is traversed at most twice (once for initial computation, once for recomputation if `a_1` changes and it depends on `a_1`).
    // So, the precomputation part for `k >= 2` is roughly O(N).
    // The outer loop runs `N-1` times. In each iteration, `solve_optimized(..., 1)` is called.
    // This call might trigger recomputations for states `k != 1` that depend on `a_1`.
