    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_duration += a[i];
    }

    if (total_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_duration = total_duration / k;
    std::vector<int> s_values;
    long long current_segment_sum = 0;
    int current_segment_length = 0;
    int segments_found = 0;

    for (int i = 0; i < n; ++i) {
        current_segment_sum += a[i];
        current_segment_length++;

        if (current_segment_sum == target_post_duration) {
            s_values.push_back(current_segment_length);
            current_segment_sum = 0;
            current_segment_length = 0;
            segments_found++;
        } else if (current_segment_sum > target_post_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (segments_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be covered by the current_segment_sum > target_post_duration check
        // or if the loop finishes and current_segment_sum != 0 (meaning last segment didn't sum up correctly)
        // or if segments_found < k (meaning not enough segments were formed)
        // The problem statement implies uniqueness if a solution exists, so this path means no solution.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last element

        // Iterate from right to left (second to last element down to the first)
        // The last element a[n-1] can never be a bad price because there are no later days.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is the new minimum for the suffix starting at i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue;
            }
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is n-1 and all other p[j] are less than n-1.
    // If so, it means p[i] should be n.
    // This handles the case where n is the actual maximum value in the permutation.
    // If n is not present in the max_val_in_row values, it means one of the p[i]
    // must be n, and its max_val_in_row would be n-1.
    bool n_found_in_p = false;
    for (int val : p) {
        if (val == n) {
            n_found_in_p = true;
            break;
        }
    }

    if (!n_found_in_p) {
        // If n is not found, it means one of the p[i] values that was calculated as n-1
        // should actually be n. We need to find which one.
        // The problem guarantees a solution exists.
        // The logic is that if p[k] = n, then max_{j!=k} min(p[k], p[j]) = max_{j!=k} p[j] = n-1.
        // So, if n is not in the calculated p, it means one of the elements calculated as n-1
        // is actually n. We can just pick any one of them and change it to n.
        // Since the problem guarantees a solution, and we know n must be present,
        // if it's not in the calculated values, it means one of the (n-1)s should be n.
        // We can simply increment the first occurrence of (n-1) to n.
        // Or, more robustly, find the maximum value in the current p and if it's n-1, change it to n.
        // Since all values are distinct in a permutation, there will be only one n-1 if n is missing.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

