    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost for a 1-stair nice staircase
        long long k = 1;            // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
                                    // k = 2^p - 1 for p = 1, 2, 3, ...
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            k = k * 2 + 1; // Next nice staircase has (2k+1) stairs
            current_cost = k * (k + 1) / 2; // Cost for the next nice staircase
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // It can only jump right from cell 0.
        // From any cell i (1 to n), if s[i-1] is 'R', it can jump right.
        // If s[i-1] is 'L', it can jump left.
        // To reach n+1, the frog must always make progress to the right.
        // This means the frog can only use 'R' cells to jump right.
        // If the frog lands on an 'L' cell, it is forced to jump left,
        // which means it cannot reach n+1 from that 'L' cell by jumping right.
        // Therefore, the frog must only land on 'R' cells or jump over 'L' cells.
        // The critical path is to jump from 0, then from one 'R' cell to the next 'R' cell,
        // until it can jump to n+1.

        // Consider the sequence of 'R' cells.
        // Let's add virtual 'R' cells at 0 and n+1.
        // The frog starts at 0.
        // It needs to jump from 0 to the first 'R' cell (or n+1 if no 'R' cells).
        // Then from one 'R' cell to the next 'R' cell.
        // Finally, from the last 'R' cell to n+1.

        // The maximum distance between consecutive 'R' cells (including 0 and n+1)
        // determines the minimum 'd'.

        std::vector<int> r_positions;
        r_positions.push_back(0); // Virtual 'R' cell at the start

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Cell indices are 1-based
            }
        }
        r_positions.push_back(n + 1); // Virtual 'R' cell at the end

        int max_dist = 0;
        for (size_t i = 0; i < r_positions.size() - 1; ++i) {
            max_dist = std::max(max_dist, r_positions[i+1] - r_positions[i]);
        }

        std::cout << max_dist << "\n";
    }
    return 0;
}

