#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    // We start from n-2 and go left.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // We start from i-1 and go left.
    // If i is 0, this loop won't run, j will remain i-1 (-1).
    int j = i - 1;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // If j is 0, then a[0...i-1] is non-increasing.

    // The prefix to erase is a[0...j-1].
    // The length of this prefix is j.
    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        available_numbers.insert(i);
    }

    bool possible = true;

    // Determine p_1
    p[0] = q[0];
    if (available_numbers.count(p[0])) {
        available_numbers.erase(p[0]);
    } else {
        // q[0] must be 1 to n, so it should always be available.
        // This case implies q[0] is out of range or duplicate, which is not possible by problem constraints.
        // However, for robustness, we can mark as impossible.
        possible = false;
    }

    // Determine p_i for i > 0
    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            // If q[i] is a new maximum, p[i] must be q[i]
            p[i] = q[i];
            if (available_numbers.count(p[i])) {
                available_numbers.erase(p[i]);
            } else {
                // q[i] was already used (e.g., q[i] == q[j] for j < i and p[j] = q[j])
                // or q[i] is out of range [1, n].
                // The problem guarantees q_i <= n, so it must be already used.
                possible = false;
            }
        } else { // q[i] == q[i-1]
            // p[i] must be some available number less than or equal to q[i]
            // To maximize chances for future elements, we should pick the smallest available number.
            // However, the problem asks for ANY suitable permutation.
            // A better strategy for q[i] == q[i-1] is to pick the largest available number
            // that is less than q[i]. This leaves smaller numbers for later.
            // But the example output suggests a different strategy.
            // Let's re-evaluate. If q[i] == q[i-1], then p[i] must be some value x <= q[i-1].
            // We need to pick an x that is available.
            // The most constrained choice is to pick the largest available number that is less than q[i].
            // This is because if we pick a smaller number, a larger number might be needed later
            // but might not be available.
            // Let's try to pick the largest available number that is strictly less than q[i].
            // If no such number exists, it's impossible.
            auto it = available_numbers.upper_bound(q[i]);
            if (it == available_numbers.begin()) {
                // No number available that is less than or equal to q[i].
                // This means all available numbers are greater than q[i], or no numbers are available.
                // Since q[i] == q[i-1], p[i] must be <= q[i].
                // If all available numbers are > q[i], then no valid p[i] can be chosen.
                possible = false;
            } else {
                --it; // This is the largest available number <= q[i]
                p[i] = *it;
                available_numbers.erase(it);
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

