#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Expand the window to include 'm'
        // 'm' is at pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // satisfies the conditions for 'm' to be beautiful.
        // 1. Length of the window must be 'm'.
        // 2. The minimum element in the window must be 1.
        // 3. The maximum element in the window must be 'm'.
        //
        // By construction, the window [current_min_idx, current_max_idx]
        // contains all numbers from 1 to 'm' (because we expanded it to include 'm'
        // and all previous numbers 1 to m-1 were already included).
        // So, the minimum element in this window is 1 and the maximum is 'm'.
        // We only need to check the length.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

