    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    long long current_a0_b1_count = 0; // Count of indices i such that a[i]='0', b[i]='1'
    long long current_a1_b0_count = 0; // Count of indices i such that a[i]='1', b[i]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // If a[i] == b[i], any pending mismatches must be resolved by flips.
            // We cannot use this position for a swap to resolve a mismatch.
            // So, any '0' that needs to be '1' (a0_b1) or '1' that needs to be '0' (a1_b0)
            // must be flipped.
            total_cost += current_a0_b1_count; // Flip all '0's that should be '1's
            total_cost += current_a1_b0_count; // Flip all '1's that should be '0's
            current_a0_b1_count = 0;
            current_a1_b0_count = 0;
        } else { // a[i] != b[i]
            if (a[i] == '0' && b[i] == '1') {
                // This position is a '0' that needs to be '1'.
                // We can potentially swap it with a '1' that needs to be '0'.
                if (current_a1_b0_count > 0) {
                    // Found a '1' that needs to be '0'. Swap them.
                    // Cost is 1 for the swap (since they are adjacent in the "mismatch" sequence).
                    // This resolves one a0_b1 and one a1_b0.
                    total_cost += 1;
                    current_a1_b0_count--;
                } else {
                    // No '1' that needs to be '0' available to swap with.
                    // This '0' needs to be '1' and will either be flipped later
                    // or swapped with a future '1' that needs to be '0'.
                    current_a0_b1_count++;
                }
            } else { // a[i] == '1' && b[i] == '0'
                // This position is a '1' that needs to be '0'.
                // We can potentially swap it with a '0' that needs to be '1'.
                if (current_a0_b1_count > 0) {
                    // Found a '0' that needs to be '1'. Swap them.
                    // Cost is 1 for the swap.
                    total_cost += 1;
                    current_a0_b1_count--;
                } else {
                    // No '0' that needs to be '1' available to swap with.
                    // This '1' needs to be '0' and will either be flipped later
                    // or swapped with a future '0' that needs to be '1'.
                    current_a1_b0_count++;
                }
            }
        }
    }

    // After iterating through all positions, any remaining current_a0_b1_count
    // or current_a1_b0_count must be resolved by flips.
    total_cost += current_a0_b1_count;
    total_cost += current_a1_b0_count;

    std::cout << total_cost << std::endl;

    return 0;
}

