        // The number of such points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let k_count = right_ptr - 1 - i.
        // These k_count points are candidates for x_j and x_k.
        // We need to choose 2 points from these k_count points.
        // The number of ways to choose 2 points from k_count points is k_count * (k_count - 1) / 2.

        long long k_count = right_ptr - 1 - i;
        if (k_count >= 2) {
            count += k_count * (k_count - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

