    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char ch : s) {
            if (ch == 'R') {
                countR++;
            } else if (ch == 'S') {
                countS++;
            } else { // ch == 'P'
                countP++;
            }
        }

        char dominant_bot_move;
        if (countR >= countS && countR >= countP) {
            dominant_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            dominant_bot_move = 'S';
        } else { // countP is dominant
            dominant_bot_move = 'P';
        }

        char our_optimal_move = get_winning_move(dominant_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

