void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // We want (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let b1 = current_xor_sum.
    // Then the new XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
    // So we want (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * b2
    // current_sum + current_xor_sum = b2
    // So, b2 = current_sum + current_xor_sum.

    // Let's verify this strategy:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum
    // New sum: S' = current_sum + b1 + b2
    //             = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //             = 2 * (current_sum + current_xor_sum)
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
    //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                = 0 ^ (current_sum + current_xor_sum)
    //                = current_sum + current_xor_sum
    // Check condition: S' = 2 * X'
    //                  2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This strategy always works and uses 2 elements.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << "\n";
    std::cout << b1 << " " << b2 << "\n";
}

