    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends who receive w_i = 1 integer
    // These friends should get the largest available numbers, and their happiness is 2 * number.
    // Since w is sorted, friends with w_i = 1 are at the beginning.
    // We want to give the largest numbers to these friends.
    // So, iterate w from largest w_i to smallest w_i.
    // Friends with w_i = 1 will be processed last in this loop.

    // Give the largest numbers to friends with w_i = 1
    // These are the k largest numbers from 'a'.
    // The largest k numbers are a[n-1], a[n-2], ..., a[n-k].
    // The friends with w_i = 1 should get these numbers.
    // Since we want to maximize sum, it doesn't matter which specific friend with w_i=1 gets which specific largest number.
    // Each of these friends will contribute 2 * (largest number) to happiness.
    // So, we pair the k largest numbers from 'a' with the k friends.
    // The friends with w_i = 1 will take the largest numbers.
    // The friends with w_i > 1 will take the next largest numbers as their 'max'.

    int a_ptr_max = n - 1; // Pointer to the largest available number in 'a'
    int a_ptr_min = 0;     // Pointer to the smallest available number in 'a'

    // First, handle friends with w_i = 1.
    // These friends should get the largest remaining numbers.
    // Sort w in descending order to process w_i=1 first.
    std::sort(w.rbegin(), w.rend());

    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // These are friends with w_i > 1.
            // They will take the largest remaining numbers as their 'max'.
            total_happiness += a[a_ptr_max];
            a_ptr_max--;
        }
    }

    // Now, handle friends with w_i > 1.
    // These friends have already received their 'max' number.
    // They need to receive w_i - 1 more numbers, and one of them will be their 'min'.
    // To maximize happiness, their 'min' should be as large as possible.
    // This means they should take the smallest available numbers from 'a' for their w_i - 1 slots,
    // but the smallest of these w_i - 1 numbers will be their 'min'.
    // To maximize the sum of 'min's, we should give the smallest available numbers to friends who need to take many numbers,
    // and the largest available numbers (among the remaining 'min' candidates) to friends who need to take few numbers.
    // This is equivalent to giving the smallest available numbers to friends who have the largest w_i.
    // So, sort w in ascending order again to process friends with largest w_i first (among those with w_i > 1).
    std::sort(w.begin(), w.end());

    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // This friend needs to take w[i] - 1 more numbers.
            // The smallest of these will be their 'min'.
            // We give them the smallest available numbers from 'a'.
            // The first number they take (a[a_ptr_min]) will be their 'min'.
            total_happiness += a[a_ptr_min];
            a_ptr_min += (w[i] - 1); // Skip w[i] - 1 numbers
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

