            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_score = calculate_score(s);
        int changes_made = 0;

        // Fill in gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                changes_made += gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W, connects two Ws, adds 2 points. The first L in a gap connects two Ws, adding 2 points. Subsequent Ls also add 2 points.
                                                  // No, this is wrong. If we fill a gap of length `g`, we change `g` 'L's to 'W's.
                                                  // The `g` 'L's were giving 0 points.
                                                  // Now they are `g` 'W's. The first 'W' in the gap connects to a previous 'W', giving 2 points.
                                                  // The remaining `g-1` 'W's also connect to previous 'W's, giving 2 points each.
                                                  // So, `g` 'W's give `2*g` points.
                                                  // The score increases by `2*g`.
            } else {
