        }

        // Count existing correct sequences (i -> i+1)
        // A sequence starts with 1 and continues as 1 -> 2 -> 3 ...
        // If chain[0] is 1, then we check how many subsequent elements are consecutive.
        if (m > 0 && chain[0] == 1) {
            int current_val = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_val) {
                    correct_sequences++;
                    current_val++;
                } else {
                    // The sequence 1 -> 2 -> ... is broken
                    break;
                }
            }
        }
    }

    // Total operations to disassemble everything:
    // Each chain of length m has m-1 internal nestings.
    // To disassemble a chain of length m, we need m-1 "get out" operations.
    // Sum of (m-1) for all chains is (sum of m) - k = n - k.
    // This is the number of "get out" operations needed for all existing nestings.
    // However, we only need to disassemble what is NOT part of the 1->2->...->n sequence.
    // The number of existing correct (i -> i+1) relationships is `correct_sequences - 1`
    // (because `correct_sequences` counts the dolls, not the relationships).
    // So, `(correct_sequences - 1)` relationships are already in place and don't need to be touched.
    // The total number of relationships in the initial configuration is `n - k`.
    // The number of relationships that need to be broken is `(n - k) - (correct_sequences - 1)`.
    // Each break costs 1 operation.
    // So, `n - k - correct_sequences + 1` operations to break incorrect nestings.

    // Total operations to assemble everything:
    // We need `n-1` total relationships in the final chain.
    // `correct_sequences - 1` relationships are already correct and don't need to be assembled.
    // So, `(n-1) - (correct_sequences - 1)` relationships need to be formed.
    // This simplifies to `n - correct_sequences` "put in" operations.

    // Total operations = (operations to break incorrect nestings) + (operations to form new nestings)
    // Total operations = ( (n - k) - (correct_sequences - 1) ) + ( (n - 1) - (correct_sequences - 1) )
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    // Let's re-evaluate.
    // The `correct_sequences` variable counts how many dolls are in the prefix 1, 2, ..., `correct_sequences`.
    // So, `correct_sequences - 1` is the number of *correct* `i -> i+1` relationships that already exist
    // and are part of the `1 -> 2 -> ... -> n` target chain.
    // These `correct_sequences - 1` relationships do not need to be broken or formed.

    // Number of relationships that need to be broken:
    // Total initial relationships: `n - k` (sum of `m_i - 1` for all chains).
    // Relationships that are part of the correct prefix `1 -> 2 -> ... -> correct_sequences`: `correct_sequences - 1`.
    // So, `(n - k) - (correct_sequences - 1)` relationships must be broken.
    // Cost: `n - k - correct_sequences + 1` operations.

    // Number of relationships that need to be formed:
    // Total relationships in the final `1 -> 2 -> ... -> n` chain: `n - 1`.
    // Relationships already existing in the correct prefix: `correct_sequences - 1`.
    // So, `(n - 1) - (correct_sequences - 1)` relationships must be formed.
    // Cost: `n - correct_sequences` operations.

    // Total minimum operations = (operations to break) + (operations to form)
    // total_operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // total_operations = 2 * n - k - 2 * correct_sequences + 1

    total_operations = (long long)2 * n - k - (long long)2 * correct_sequences + 1;

    std::cout << total_operations << std::endl;

