// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is not divisible by q.
        // x must be a divisor of p.
        // To make x not divisible by q, we must remove at least one prime factor of q from p
        // (or reduce its power) such that x no longer has enough of that prime factor to be divisible by q.

        // Get distinct prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long q_factor : q_prime_factors) {
            // For each prime factor `q_factor` of `q`, we try to construct an `x`
            // by dividing `p` by `q_factor` until `x` is no longer divisible by `q`.
            // The resulting `x` will be `p / (q_factor^k)` for some `k`.
            // We want to find the largest such `x`.

            long long current_p = p;
            while (current_p % q_factor == 0) {
                current_p /= q_factor;
            }
            // Now current_p is p with all occurrences of q_factor removed.
            // We need to find the largest multiple of current_p that divides p
            // and is not divisible by q.
            // The candidate x is current_p * (q_factor raised to some power).
            // We want to find the largest power of q_factor, say q_factor^k,
            // such that (current_p * q_factor^k) divides p AND
            // (current_p * q_factor^k) is NOT divisible by q.

            // Let's rephrase: we want to find the largest divisor of p, say x,
            // such that x is not divisible by q.
            // If p is divisible by q, then p is not the answer.
            // We iterate through each prime factor `f` of `q`.
            // For each `f`, we consider `p / f^k` where `f^k` is the highest power of `f` that divides `p`.
            // We want to find the largest `x` such that `x` divides `p` and `x % q != 0`.
            // This means `x` must be `p / (f^k)` for some `f` that is a prime factor of `q`,
            // and `f^k` is the smallest power of `f` such that `p / f^k` is not divisible by `q`.

            // Let's try a different approach:
            // For each prime factor `f` of `q`:
            //   Calculate `temp_p = p`.
            //   While `temp_p` is divisible by `q`:
            //     `temp_p /= f`.
            //   The resulting `temp_p` is a candidate for `x`.
            //   We take the maximum of all such `temp_p`.

            long long current_candidate_x = p;
            while (current_candidate_x % q == 0) {
                current_candidate_x /= q_factor;
            }
            max_x = std::max(max_x, current_candidate_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(n, '?');

    // Step 1: Propagate known characters based on s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            // Propagate s[i] to s[i % k], s[i % k + k], s[i % k + 2k], ...
            // This means all characters at indices j such that j % k == i % k
            // must eventually be s[i] if they are not '?' or conflict.
            // We can simplify this by just setting fixed_s[i % k]
            // and checking for conflicts.
            if (fixed_s[i % k] == '?') {
                fixed_s[i % k] = s[i];
            } else if (fixed_s[i % k] != s[i]) {
                // Conflict detected: s[i] implies a value for fixed_s[i%k]
                // that contradicts an earlier implication.
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Fill in '?' in s based on fixed_s
    // And check for conflicts with existing '0' or '1' in s
    for (int i = 0; i < n; ++i) {
        if (fixed_s[i % k] != '?') {
            if (s[i] == '?') {
                s[i] = fixed_s[i % k];
            } else if (s[i] != fixed_s[i % k]) {
                // Conflict detected: s[i] is '0'/'1' but fixed_s[i%k] implies a different value.
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 3: Check the first k characters for balance
    int zeros = 0;
    int ones = 0;
    int q_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros++;
        } else if (s[i] == '1') {
            ones++;
        } else { // s[i] == '?'
            q_marks++;
        }
    }

    // Check if it's possible to balance the first k characters
    if (zeros > k / 2 || ones > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we have enough '?' to fill the remaining slots to reach k/2 for both 0s and 1s
    // The number of '?' needed for zeros is k/2 - zeros
    // The number of '?' needed for ones is k/2 - ones
    // The total '?' needed is (k/2 - zeros) + (k/2 - ones) = k - zeros - ones
    // This must be less than or equal to q_marks.
    // Since zeros + ones + q_marks = k, this condition is always met if zeros <= k/2 and ones <= k/2.
    // So, if zeros <= k/2 and ones <= k/2, it's always possible to fill the first k characters.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
