long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_coins += 1;
                n = 0;
            } else if (n == 2) {
                chanek_coins += 1; // Take 1, opponent takes 1. Or take N/2, opponent takes 1. Both give 1.
                n = 0;
            } else if (n == 3) {
                chanek_coins += 1; // Take 1, N becomes 2. Opponent takes 1, N becomes 1. Chanek takes 1. Total 2.
                n = 2;
            } else if (n % 2 == 1) { // N is odd and > 3
                chanek_coins += 1;
                n -= 1;
            } else { // N is even and > 3
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent will play optimally on N-1.
                // If N-1 is odd, opponent takes 1. N-2 remains.
                // If N-1 is even, opponent takes N-1/2. N-1/2 remains.
                // This path is complex. Let's consider the other option.

                // Option 2: Take N/2 coins
                // Remaining N/2.
                // If N/2 is odd, opponent takes 1. N/2-1 remains.
                // If N/2 is even, opponent takes N/4. N/4 remains.

                // The key insight for even N:
                // If N is even, Chanek can choose to take N/2.
                // If N/2 is odd, then the opponent will take 1 coin.
                // If N/2 is even, then the opponent will take N/4.
                // This suggests a pattern related to powers of 2.

                // If N is even, Chanek wants to take N/2 if it leads to a better outcome.
                // When N is even, Chanek can take N/2.
                // If N/2 is odd, the opponent will be forced to take 1 coin (as N/2 is odd, they can't take half).
                // This leaves N/2 - 1 coins for Chanek's next turn.
                // If N/2 is even, the opponent can take N/4. This leaves N/4 coins.

