#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1), so target X must be >= current x
            // If f1 = 0, cannot move left. If target X < current x, it's impossible.
            // So, if f1 = 0, target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1 means can move right (x+1), so target X must be <= current x
            // If f3 = 0, cannot move right. If target X > current x, it's impossible.
            // So, if f3 = 0, target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1 means can move down (y-1), so target Y must be >= current y
            // If f4 = 0, cannot move down. If target Y < current y, it's impossible.
            // So, if f4 = 0, target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1 means can move up (y+1), so target Y must be <= current y
            // If f2 = 0, cannot move up. If target Y > current y, it's impossible.
            // So, if f2 = 0, target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

