int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    for (int i = 0; i < n; ++i) {
        int block_start = (n - 1) - (i / k) * k;
        int val = block_start - (i % k);
        std::cout << val << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

