    bool found_solution = false;

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string current_coloring(n, ' ');
        char last_1 = '0';
        char first_2 = '9' + 1; // Larger than any digit

        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            if (s[i] < pivot + '0') {
                current_coloring[i] = '1';
                if (s[i] < last_1) {
                    possible_pivot = false;
                    break;
                }
                last_1 = s[i];
            } else if (s[i] > pivot + '0') {
                current_coloring[i] = '2';
                if (s[i] < first_2) { // This check is for the '2' sequence itself
                    first_2 = s[i];
                }
            }
        }

        if (!possible_pivot) {
            continue;
        }

        // Now handle digits equal to pivot
        // Digits equal to pivot can be 1 or 2.
        // If s[i] == pivot + '0', it must be '1' if it appears before any '2'
        // and '2' if it appears after any '1' that is greater than last_1.
        // More precisely, if s[i] == pivot + '0':
        //   - If it's colored '1', it must be >= last_1.
        //   - If it's colored '2', it must be <= first_2.
        //   - The overall condition is last_1 <= first_2.

        // Strategy: color all pivot digits that appear before the first '2' as '1',
        // and all pivot digits that appear after the last '1' as '2'.
        // This is equivalent to finding the first occurrence of a digit > pivot,
        // and the last occurrence of a digit < pivot.
        // All pivot digits before the first > pivot can be '1'.
        // All pivot digits after the last < pivot can be '2'.

        // Let's refine:
        // All digits < pivot are '1'.
        // All digits > pivot are '2'.
        // For digits == pivot:
        //   We need to find a split point `j` such that `d_i` for `i < j` and `d_i == pivot` are '1',
        //   and `d_i` for `i >= j` and `d_i == pivot` are '2'.
        //   This split point `j` must ensure that the '1' sequence remains non-decreasing
        //   and the '2' sequence remains non-decreasing.
        //   And `last_1 <= first_2`.

        // A simpler approach for pivot digits:
        // Iterate through the string.
        // If s[i] < pivot, it's '1'.
        // If s[i] > pivot, it's '2'.
        // If s[i] == pivot:
        //   If we haven't encountered any digit > pivot yet, we can color it '1'.
        //   If we have encountered a digit > pivot, we must color it '2'.
        // This ensures that all '1's are <= pivot and all '2's are >= pivot.
        // And the split between '1's and '2's for pivot digits happens at the first digit > pivot.

        char current_last_1 = '0';
        char current_first_2 = '9' + 1;
        bool seen_digit_greater_than_pivot = false;
        bool current_pivot_possible = true;

        std::string temp_coloring(n, ' ');

        for (int i = 0; i < n; ++i) {
            if (s[i] < pivot + '0') {
                temp_coloring[i] = '1';
                if (s[i] < current_last_1) {
                    current_pivot_possible = false;
                    break;
                }
                current_last_1 = s[i];
            } else if (s[i] > pivot + '0') {
                temp_coloring[i] = '2';
                seen_digit_greater_than_pivot = true;
                if (s[i] < current_first_2) {
                    current_first_2 = s[i];
                }
            } else { // s[i] == pivot + '0'
                if (!seen_digit_greater_than_pivot) {
                    temp_coloring[i] = '1';
                    // current_last_1 is already pivot or less, so s[i] >= current_last_1 is true
                    current_last_1 = s[i]; // Update last_1 to pivot
                } else {
                    temp_coloring[i] = '2';
                    // current_first_2 is already pivot or greater, so s[i] <= current_first_2 is true
                    current_first_2 = s[i]; // Update first_2 to pivot
                }
            }
        }

        if (!current_pivot_possible) {
            continue;
        }

        // Final check: last_1 <= first_2
        // In this strategy, current_last_1 will be at most 'pivot'
        // and current_first_2 will be at least 'pivot'.
        // So current_last_1 <= current_first_2 is always true.
        // The only remaining check is that the '2' sequence itself is non-decreasing.
        // This is handled by `if (s[i] < current_first_2)` for digits > pivot.
        // For digits == pivot colored '2', they are equal to current_first_2 (if current_first_2 is pivot)
        // or less than current_first_2 (if current_first_2 is > pivot).
        // This means we need to track the actual last digit of color 1 and first digit of color 2.

        char actual_last_1 = '0';
        char actual_first_2 = '9' + 1;
        bool first_2_set = false;

        // Re-verify the generated coloring
        bool valid_coloring = true;
        for (int i = 0; i < n; ++i) {
            if (temp_coloring[i] == '1') {
                if (s[i] < actual_last_1) {
                    valid_coloring = false;
                    break;
                }
                actual_last_1 = s[i];
            } else { // temp_coloring[i] == '2'
                if (!first_2_set) {
                    actual_first_2 = s[i];
                    first_2_set = true;
                } else if (s[i] < actual_first_2) {
                    valid_coloring = false;
                    break;
                }
                actual_first_2 = s[i]; // Update actual_first_2 to be the current digit, as it's the last '2' seen so far
                                        // This is wrong. actual_first_2 should be the *first* digit of the '2' sequence.
                                        // We need to build the sequences and check.
            }
        }

        if (!valid_coloring) {
            continue;
        }

        std::string seq1_str = "";
        std::string seq2_str = "";
        for (int i = 0; i < n; ++i) {
            if (temp_coloring[i] == '1') {
                seq1_str += s[i];
            } else {
                seq2_str += s[i];
            }
        }

        bool seq1_sorted = true;
        if (!seq1_str.empty()) {
            for (size_t i = 0; i < seq1_str.length() - 1; ++i) {
                if (seq1_str[i] > seq1_str[i+1]) {
                    seq1_sorted = false;
                    break;
                }
            }
        }

        bool seq2_sorted = true;
        if (!seq2_str.empty()) {
            for (size_t i = 0; i < seq2_str.length() - 1; ++i) {
                if (seq2_str[i] > seq2_str[i+1]) {
                    seq2_sorted = false;
                    break;
                }
            }
        }

        bool combined_sorted = true;
        if (!seq1_str.empty() && !seq2_str.empty()) {
            if (seq1_str.back() > seq2_str.front()) {
                combined_sorted = false;
            }
        }

        if (seq1_sorted && seq2_sorted && combined_sorted) {
            result = temp_coloring;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

