    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of k from 1 to a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    sum_k = (sum_k * inv2) % MOD;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k * b + 1) * r
    // = sum_k (k * b * sum_r + 1 * sum_r)
    // = (sum_k * b * sum_r) + (a * sum_r)
    // = sum_r * (sum_k * b + a)

    long long term1 = (sum_k * (b % MOD)) % MOD;
    long long term2 = a % MOD;
    long long inner_sum = (term1 + term2) % MOD;

    long long total_sum = (sum_r * inner_sum) % MOD;

    std::cout << total_sum << std::endl;

