#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1] (no change)
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1] (no change)
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Segment [1, n-1]
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long add_val = remainder * (n - 1); // Add (n-1) * remainder
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n
    // Segment [n, n]
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = (a[n - 1] % n + n) % n; // Ensure positive remainder
    long long add_val_n_minus_1 = remainder_n_minus_1 * n; // Add n * remainder
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1;

    // Operation 3: Make all elements zero
    // Segment [1, n]
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If there are no zeros, all substrings contain '1'
        if (num_zeros == 0) {
            std::cout << total_substrings << "\n";
            continue;
        }

        // To maximize f(s), we need to minimize the number of substrings
        // consisting only of zeros. This is achieved by distributing the
        // zeros as evenly as possible among the m+1 possible blocks
        // created by the m ones.

        // Number of blocks of zeros
        // If m ones are placed, they divide the string into m+1 potential
        // blocks of zeros (before the first '1', between '1's, after the last '1').
        long long num_zero_blocks = m + 1;

        // Calculate the size of the blocks of zeros
        // k = floor(num_zeros / num_zero_blocks)
        long long k = num_zeros / num_zero_blocks;
        // r = num_zeros % num_zero_blocks
        long long r = num_zeros % num_zero_blocks;

        // r blocks will have length k+1
        // (num_zero_blocks - r) blocks will have length k

        // Number of substrings of all zeros from blocks of length k+1
        long long substrings_from_k_plus_1 = r * (k + 1) * (k + 2) / 2;

        // Number of substrings of all zeros from blocks of length k
        long long substrings_from_k = (num_zero_blocks - r) * k * (k + 1) / 2;

        long long min_zero_substrings = substrings_from_k_plus_1 + substrings_from_k;

        long long max_f_s = total_substrings - min_zero_substrings;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track what 0 becomes and what 1 becomes.
    // initial_val_0[bit_idx] = final value of bit_idx if initial input bit was 0
    // initial_val_1[bit_idx] = final value of bit_idx if initial input bit was 1
    std::vector<int> initial_val_0(10); // All bits are 0 initially
    std::vector<int> initial_val_1(10); // All bits are 1 initially

    for (int i = 0; i < 10; ++i) {
        initial_val_0[i] = 0;
        initial_val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
            int x_bit = (x >> bit_idx) & 1;

            if (op_char == '&') {
                initial_val_0[bit_idx] &= x_bit;
                initial_val_1[bit_idx] &= x_bit;
            } else if (op_char == '|') {
                initial_val_0[bit_idx] |= x_bit;
                initial_val_1[bit_idx] |= x_bit;
            } else if (op_char == '^') {
                initial_val_0[bit_idx] ^= x_bit;
                initial_val_1[bit_idx] ^= x_bit;
            }
        }
    }

    // Now, reconstruct the simplified operations.
    // We need to find A_AND, A_OR, A_XOR such that:
    // ( ( (x & A_AND) | A_OR) ^ A_XOR ) == original_result(x)
    // for all x from 0 to 1023.

    // Let's determine the values for A_AND, A_OR, A_XOR bit by bit.
    int A_AND = 1023; // Initialize to all 1s (no effect on &)
    int A_OR = 0;     // Initialize to all 0s (no effect on |)
    int A_XOR = 0;    // Initialize to all 0s (no effect on ^)

    for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
        int final_0 = initial_val_0[bit_idx];
        int final_1 = initial_val_1[bit_idx];

        // Case 1: If input bit 0 becomes 0, and input bit 1 becomes 0.
        // This means the bit is always 0, regardless of input.
        // To achieve this:
        // (0 & A_AND_bit) | A_OR_bit ^ A_XOR_bit = 0
        // (1 & A_AND_bit) | A_OR_bit ^ A_XOR_bit = 0
        // This implies A_AND_bit must be 0.
        // Then (0 | A_OR_bit) ^ A_XOR_bit = 0 => A_OR_bit ^ A_XOR_bit = 0 => A_OR_bit = A_XOR_bit.
        // The simplest way is A_AND_bit=0, A_OR_bit=0, A_XOR_bit=0.
        // Or A_AND_bit=0, A_OR_bit=1, A_XOR_bit=1.
        // We want to minimize operations.
        // If final_0 == 0 and final_1 == 0:
        //   We need (x_bit & A_AND_bit) | A_OR_bit ^ A_XOR_bit = 0
        //   If A_AND_bit = 0: (0 | A_OR_bit) ^ A_XOR_bit = 0 => A_OR_bit = A_XOR_bit.
        //   If A_AND_bit = 1: (x_bit | A_OR_bit) ^ A_XOR_bit = 0
        //     For x_bit=0: A_OR_bit ^ A_XOR_bit = 0 => A_OR_bit = A_XOR_bit
        //     For x_bit=1: (1 | A_OR_bit) ^ A_XOR_bit = 0 => 1 ^ A_XOR_bit = 0 => A_XOR_bit = 1.
        //     So A_OR_bit = 1.
        //     This means A_AND_bit=1, A_OR_bit=1, A_XOR_bit=1.
        //     This is equivalent to (x_bit | 1) ^ 1 = 1 ^ 1 = 0.
        //     Or (x_bit & 0) | 0 ^ 0 = 0.
        //     The simplest way to force a bit to 0 is `& 0`.
        if (final_0 == 0 && final_1 == 0) {
            A_AND &= ~(1 << bit_idx); // Set A_AND_bit to 0
            // A_OR_bit and A_XOR_bit remain 0 for this bit, which is consistent.
        }
        // Case 2: If input bit 0 becomes 1, and input bit 1 becomes 1.
        // This means the bit is always 1, regardless of input.
        // The simplest way to force a bit to 1 is `| 1`.
        else if (final_0 == 1 && final_1 == 1) {
            A_OR |= (1 << bit_idx); // Set A_OR_bit to 1
            // A_AND_bit remains 1, A_XOR_bit remains 0.
            // (x_bit & 1) | 1 ^ 0 = x_bit | 1 = 1. This works.
        }
        // Case 3: If input bit 0 becomes 0, and input bit 1 becomes 1.
        // This means the bit is unchanged (x_bit -> x_bit).
        // This is the default behavior if A_AND_bit=1, A_OR_bit=0, A_XOR_bit=0.
        // (x_bit & 1) | 0 ^ 0 = x_bit. This works.
        else if (final_0 == 0 && final_1 == 1) {
            // A_AND_bit remains 1, A_OR_bit remains 0, A_XOR_bit remains 0.
        }
        // Case 4: If input bit 0 becomes 1, and input bit 1 becomes 0.
        // This means the bit is flipped (x_bit -> !x_bit).
        // This can be achieved by `^ 1`.
        else if (final_0 == 1 && final_1 == 0) {
            A_XOR |= (1 << bit_idx); // Set A_XOR_bit to 1
            // A_AND_bit remains 1, A_OR_bit remains 0.
            // (x_bit & 1) | 0 ^ 1 = x_bit ^ 1. This works.
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all 1s, we need an & operation
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all 0s, we need an | operation
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all 0s, we need an ^ operation
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // We are interested in jars 1 to n, which are indices 0 to n-1.
    // diff_L[k] will store the balance after removing k jars from the left.
    // So, diff_L[k] is the balance of jars a[k]...a[n-1].
    // This is equivalent to (total balance of a[0...n-1]) - (balance of a[0...k-1]).
    // Let's rephrase:
    // left_balance[k] = balance of jars a[0]...a[k-1]
    // left_balance[0] = 0
    // left_balance[k] = left_balance[k-1] + (a[k-1] == 1 ? 1 : -1) for k=1...n
    std::vector<int> left_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_balance[i + 1] = left_balance[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // We are interested in jars n+1 to 2n, which are indices n to 2n-1.
    // right_balance[k] = balance of jars a[2n-k]...a[2n-1]
    // right_balance[0] = 0
    // right_balance[k] = right_balance[k-1] + (a[2n-k] == 1 ? 1 : -1) for k=1...n
    std::vector<int> right_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_balance[i + 1] = right_balance[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store indices for each balance value in the left half
    // map: balance_value -> number of jars removed from left (k)
    std::map<int, int> left_balance_map;
    for (int k = 0; k <= n; ++k) {
        // We want to find the minimum k for a given balance.
        // Since we iterate k from 0 upwards, the first time we see a balance,
        // it corresponds to the minimum k.
        if (left_balance_map.find(left_balance[k]) == left_balance_map.end()) {
            left_balance_map[left_balance[k]] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible removals from the right side (k_R)
    // For each k_R, we calculate the balance of the removed right jars.
    // We need the remaining jars to have a total balance of 0.
    // This means (balance of remaining left jars) + (balance of remaining right jars) = 0.
    // (left_balance[n] - left_balance[k_L]) + (right_balance[n] - right_balance[k_R]) = 0
    // This is not quite right.
    // The balance of the *entire* remaining segment (a[k_L]...a[2n-1-k_R]) must be 0.
    // Let B_total be the balance of all jars a[0]...a[2n-1].
    // B_total = left_balance[n] + right_balance[n] (if right_balance was calculated from n to 2n-1)
    // Let's use the definition of left_balance[k] as balance of a[0...k-1]
    // and right_balance[k] as balance of a[2n-k...2n-1].
    // The balance of the remaining jars a[k_L]...a[2n-1-k_R] is:
    // (Balance of a[0...2n-1]) - (Balance of a[0...k_L-1]) - (Balance of a[2n-k_R...2n-1])
    // = (left_balance[n] + right_balance[n]) - left_balance[k_L] - right_balance[k_R]
    // We want this to be 0.
    // So, left_balance[k_L] + right_balance[k_R] = left_balance[n] + right_balance[n].
    // Let target_balance_sum = left_balance[n] + right_balance[n].
    // We need to find k_L and k_R such that left_balance[k_L] + right_balance[k_R] = target_balance_sum.
    // And we want to minimize k_L + k_R.

    // The balance of the full array is left_balance[n] + right_balance[n].
    // Let's define the balance of the full array as `initial_total_balance`.
    // `initial_total_balance` = (count of 1s in a[0...2n-1]) - (count of 2s in a[0...2n-1])
    // This is `left_balance[n]` (balance of a[0...n-1]) + `right_balance[n]` (balance of a[n...2n-1] if calculated from left to right)
    // Or, `left_balance[n]` + `right_balance_from_n_to_2n_minus_1`
    // Let's re-evaluate `right_balance` to be consistent.
    // `right_balance[k]` is the balance of `a[2n-k]` to `a[2n-1]`.
    // So, `left_balance[n]` is balance of `a[0]` to `a[n-1]`.
    // `right_balance[n]` is balance of `a[n]` to `a[2n-1]`.
    // The total balance of all jars is `left_balance[n] + right_balance[n]`.
    // Let `current_total_balance` be the balance of jars `a[k_L]` to `a[2n-1-k_R]`.
    // `current_total_balance` = `initial_total_balance` - `left_balance[k_L]` - `right_balance[k_R]`.
    // We want `current_total_balance = 0`.
    // So, `initial_total_balance` - `left_balance[k_L]` - `right_balance[k_R]` = 0.
    // This means `left_balance[k_L] + right_balance[k_R] = initial_total_balance`.

    // Let's use the definition of `left_balance[k]` as balance of `a[0...k-1]`
    // and `right_balance[k]` as balance of `a[2n-k...2n-1]`.
    // The balance of the remaining segment `a[k_L]` to `a[2n-1-k_R]` is what we need to be 0.
    // This is `(balance of a[0...2n-1]) - (balance of a[0...k_L-1]) - (balance of a[2n-k_R...2n-1])`.
    // Let `total_initial_balance = left_balance[n] + right_balance[n]`.
    // We need `total_initial_balance - left_balance[k_L] - right_balance[k_R] = 0`.
    // So, `left_balance[k_L] + right_balance[k_R] = total_initial_balance`.

    // Iterate `k_R` from 0 to `n` (number of jars removed from the right).
    for (int k_R = 0; k_R <= n; ++k_R) {
        int target_left_balance = (left_balance[n] + right_balance[n]) - right_balance[k_R];

        if (left_balance_map.count(target_left_balance)) {
            int k_L = left_balance_map[target_left_balance];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

