    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks vertices currently in the graph

    // Process deletions in reverse order
    // This allows us to add vertices one by one and update APSP using Floyd-Warshall's intermediate vertex logic
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back to the graph

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using k as an intermediate vertex
        // For all pairs (i, j) of currently active vertices, check if path i -> k -> j is shorter
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating paths through k,
        // we also need to consider paths between existing active vertices
        // that might now be shorter because of other active vertices (not k)
        // This is the standard Floyd-Warshall triple loop, but restricted to active vertices.
        // The previous loop (i,j,k) already handled k as an intermediate.
        // Now we need to handle other active vertices as intermediate for paths involving k.
        // Specifically, for any active i, j, and any active intermediate m:
        // dist[i][j] = min(dist[i][j], dist[i][m] + dist[m][j])
        // Since we are adding vertices one by one, when we add vertex 'k',
        // all previously added vertices (which are active) have already been used as intermediate 'm'.
        // So, we only need to consider 'k' as an intermediate for all pairs (i,j)
        // and then consider 'k' as one of the endpoints for paths through other active intermediates.
        // The following two loops handle paths where k is an endpoint and another active vertex 'm' is an intermediate.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Path i -> m -> k
                if (dist[i][j] + dist[j][k] < dist[i][k]) { // This is actually dist[i][m] + dist[m][k] < dist[i][k]
                    dist[i][k] = dist[i][j] + dist[j][k];
                }
                // Path k -> m -> j
                if (dist[k][j] + dist[j][i] < dist[k][i]) { // This is actually dist[k][m] + dist[m][j] < dist[k][j]
                    dist[k][i] = dist[k][j] + dist[j][i];
                }
            }
        }
        // The above two loops are not quite right.
        // The standard Floyd-Warshall update is:
        // for m in active:
        //   for i in active:
        //     for j in active:
        //       dist[i][j] = min(dist[i][j], dist[i][m] + dist[m][j])
        // When we add vertex 'k', 'k' becomes the new 'm'.
        // So, the first triple loop (i,j,k) correctly updates paths using 'k' as an intermediate.
        // However, the paths involving 'k' as an endpoint might also be shortened by other active intermediates.
        // Example: i -> m -> k. This is dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k]).
        // Example: k -> m -> j. This is dist[k][j] = min(dist[k][j], dist[k][m] + dist[m][j]).
        // These updates are implicitly handled by the first triple loop if we consider all active vertices.
        // Let's re-evaluate the Floyd-Warshall structure for adding vertices.
        // When we add vertex 'k', it means 'k' can now be used as an intermediate.
        // So, for all existing active pairs (i, j), we check dist[i][k] + dist[k][j].
        // Also, 'k' itself might have new shortest paths to/from other active vertices through other active vertices.
        // For example, dist[k][j] might be shortened by k -> m -> j, where m is an already active vertex.
        // And dist[i][k] might be shortened by i -> m -> k.
        // The correct way to integrate a new vertex 'k' into an existing APSP matrix is:
        // 1. For all active i, j: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // 2. For all active i: dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k]) for all active m
        // 3. For all active j: dist[k][j] = min(dist[k][j], dist[k][m] + dist[m][j]) for all active m
        //
        // The first loop (i,j,k) handles step 1.
        // Steps 2 and 3 are handled by the following loops:
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int m = 0; m < n; ++m) {
                if (!active[m]) continue;
                if (dist[i][m] + dist[m][k] < dist[i][k]) {
                    dist[i][k] = dist[i][m] + dist[m][k];
                }
                if (dist[k][m] + dist[m][i] < dist[k][i]) {
                    dist[k][i] = dist[k][m] + dist[m][i];
                }
            }
        }
        // After these updates, we need to re-run the first loop again,
        // because the new dist[i][k] or dist[k][j] might create new shorter paths for i->j.
        // This suggests that simply adding 'k' and running the triple loop with 'k' as the intermediate
        // is not enough. We need to run the full Floyd-Warshall for all active vertices.
        //
        // A simpler way is to just run the standard Floyd-Warshall for all active vertices.
        // When vertex 'k' is added, it becomes the 'm' in the Floyd-Warshall loop.
        // The standard Floyd-Warshall algorithm iterates through intermediate vertices 'm'.
        // If we iterate 'm' in the order of vertices being added back (k_idx from n-1 down to 0),
        // then when we process 'k', all vertices that were added *before* 'k' (i.e., x[k_idx+1]...x[n-1])
        // have already been used as intermediates.
        // So, when we add 'k', we use 'k' as the intermediate vertex for all pairs (i,j)
        // that are currently active.
        //
        // Let's refine the update logic:
        // When vertex `k` (from `x[k_idx]`) is activated:
        // 1. Update all paths `i -> j` using `k` as an intermediate:
        //    `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])` for all active `i, j`.
        // 2. Update all paths `i -> k` using any other active vertex `m` as an intermediate:
        //    `dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k])` for all active `i, m`.
        // 3. Update all paths `k -> j` using any other active vertex `m` as an intermediate:
        //    `dist[k][j] = min(dist[k][j], dist[k][m] + dist[m][j])` for all active `j, m`.
        //
        // After steps 1, 2, 3, the `dist` matrix correctly reflects shortest paths
        // between all pairs of currently active vertices, considering `k` and all previously active vertices
        // as intermediates.
        //
        // The order of loops matters.
        // The standard Floyd-Warshall is `for k, for i, for j`.
        // Here, `k` is the vertex being added.
        // So, the outer loop is `k` (the vertex being added).
        // Inside, we need to update all `dist[i][j]` for active `i, j`.
        //
        // Let's use the standard Floyd-Warshall structure, but with `k` being the *current* intermediate vertex.
        // The `k` in Floyd-Warshall is the intermediate vertex.
        // In our reverse process, `x[k_idx]` is the vertex that becomes available as an intermediate.
        // So, the `k` in the Floyd-Warshall algorithm corresponds to `x[k_idx]`.
        //
        // The loops should be:
        // `k` (from `x[k_idx]`) is the new intermediate vertex.
        // For all `i` (active):
        //   For all `j` (active):
        //     `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // This single triple loop (with `k` as the intermediate) is sufficient.
        // Why? Because when we add `k`, `dist[i][k]` and `dist[k][j]` already contain shortest paths
        // using only vertices that were active *before* `k` was added.
        // So, `dist[i][k] + dist[k][j]` correctly represents the shortest path `i -> ... -> k -> ... -> j`
        // where `...` uses only previously active vertices.
        //
        // Let's trace:
        // Initial: `dist` matrix from input. `active` all false.
        // `k_idx = n-1`: `k = x[n-1]`. `active[k] = true`.
        //   Now, `k` is the *only* active vertex. Sum is 0.
        //   The loops `for i, for j` will only run if `i` and `j` are active.
        //   If `i=k, j=k`, `dist[k][k]` is 0.
        //   Sum for this step: 0.
        // `k_idx = n-2`: `k = x[n-2]`. `active[k] = true`.
        //   Now, `x[n-1]` and `x[n-2]` are active. Let `k1 = x[n-1]`, `k2 = x[n-2]`.
        //   The loop `for i, for j` will run for `i,j` in `{k1, k2}`.
        //   `dist[k1][k1] = min(dist[k1][k1], dist[k1][k2] + dist[k2][k1])` (no change, `dist[k1][k1]=0`)
        //   `dist[k1][k2] = min(dist[k1][k2], dist[k1][k2] + dist[k2][k2])` (no change)
        //   `dist[k2][k1] = min(dist[k2][k1], dist[k2][k2] + dist[k2][k1])` (no change)
        //   `dist[k2][k2] = min(dist[k2][k2], dist[k2][k2] + dist[k2][k2])` (no change)
        //   This is not right. The standard Floyd-Warshall is `for m, for i, for j`.
        //   Here, `m` is the intermediate vertex.
        //   When we add `k = x[k_idx]`, `k` becomes the new `m`.
        //   So, the loop should be:
        //   `m = k` (the newly added vertex)
        //   For `i` from `0` to `n-1`:
        //     If `!active[i]` continue;
        //     For `j` from `0` to `n-1`:
        //       If `!active[j]` continue;
        //       `dist[i][j] = min(dist[i][j], dist[i][m] + dist[m][j])`
        // This is the correct Floyd-Warshall update for adding one intermediate vertex.
        // The `dist[i][m]` and `dist[m][j]` values are already correct for paths using only previously active vertices.

        // Calculate sum of shortest paths for currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first deletion to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[i] to a very large value (effectively infinity)
    // This represents the upper bound for a_0[i]
    std::vector<long long> initial_a(n, 2000000000LL); // Max possible value for a_i is 10^9,
                                                      // but d can be -10^4, so max_val - sum_d can be larger.
                                                      // 2*10^9 is a safe upper bound for initial_a[i]
                                                      // given |a_i| <= 10^9 and max_m is 5*10^7.
                                                      // The actual max value for initial_a[i] is 5*10^7 - min_sum_d.
                                                      // min_sum_d can be -5000 * 10^4 = -5*10^7.
                                                      // So initial_a[i] can be up to 5*10^7 - (-5*10^7) = 10^8.
                                                      // 2*10^9 is a safe upper bound for the initial value.

    // Calculate the sum of d values for each prefix
    std::vector<long long> current_d_sum(n + 1, 0);

    // Process operations in reverse to find constraints on initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a_j = a_j + d
            // This means the current_d_sum for elements in [l, r] was d less before this operation.
            // So, we subtract d from the current_d_sum for elements in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_d_sum[j] -= ops[i].val;
            }
        } else {
            // Type 2: max(a_j) = m for j in [l, r]
            // This means for all j in [l, r], a_j <= m.
            // Since a_j = initial_a[j] + current_d_sum[j],
            // we have initial_a[j] + current_d_sum[j] <= m.
            // So, initial_a[j] <= m - current_d_sum[j].
            // We update initial_a[j] with the minimum of its current value and (m - current_d_sum[j]).
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_d_sum[j]);
            }
        }
    }

    // Check if the reconstructed initial_a is valid
    // Simulate operations with the found initial_a
    std::vector<long long> current_array = initial_a;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: a_j = a_j + d
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_array[j] += ops[i].val;
            }
        } else {
            // Type 2: max(a_j) = m for j in [l, r]
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_array[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if initial_a elements are within the |10^9| bound
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] > 1000000000LL || initial_a[i] < -1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution
            // within |10^9| bounds, as our initial_a[i] is derived from valid m_i values.
            // However, it's a good sanity check.
            // If initial_a[i] was initialized to 2*10^9, and no type 2 op constrained it,
            // it might remain large. We can cap it at 10^9.
            // The problem asks for *any* suitable array. If it's not constrained, 0 is a valid choice.
            // But the logic above sets it to min(current_val, m - sum_d).
            // If no type 2 op constrains it, it remains 2*10^9.
            // Let's cap it to 10^9 if it's still at the initial large value.
            if (initial_a[i] == 2000000000LL) {
                initial_a[i] = 1000000000LL; // Cap to 10^9 if unconstrained
            }
            if (initial_a[i] > 1000000000LL || initial_a[i] < -1000000000LL) {
                // If after capping it's still out of bounds, it means a constraint forced it out.
                // This implies no solution, but the problem implies a solution exists if we find one.
                // The problem states "Levko clearly remembers that all numbers in his array didn't exceed 10^9 in their absolute value"
                // This implies the *initial* array elements are within this bound.
                // Our derivation of initial_a[j] <= m - current_d_sum[j] should naturally lead to values
                // within the bounds if a solution exists.
                // If m - current_d_sum[j] is outside the bound, then no solution exists.
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
    }

    std::vector<int> cured_children_ids;
    std::vector<bool> is_cured(n + 1, false); // To mark children who have been cured

    for (int i = 0; i < n; ++i) {
        if (is_cured[children[i].id]) {
            continue; // This child has already been cured (or processed)
        }

        // Child i goes to the doctor
        cured_children_ids.push_back(children[i].id);
        is_cured[children[i].id] = true;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (is_cured[children[j].id]) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Apply accumulated d_cry from previously leaving children
            children[j].p -= total_d_cry_from_leaving;
        }

        // Process chain reactions of children leaving
        bool chain_reaction_happened;
        do {
            chain_reaction_happened = false;
            for (int j = i + 1; j < n; ++j) {
                if (is_cured[children[j].id]) {
                    continue;
                }

                if (children[j].p < 0) {
                    // This child leaves
                    is_cured[children[j].id] = true;
                    total_d_cry_from_leaving += children[j].d;
                    chain_reaction_happened = true;

                    // Apply this child's d_cry to subsequent children
                    for (int k = j + 1; k < n; ++k) {
                        if (!is_cured[children[k].id]) {
                            children[k].p -= children[j].d;
                        }
                    }
                }
            }
        } while (chain_reaction_happened);
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);

    // Case 2: The smallest element a_1 is in one subsequence, and all others are in the other.
    // min_f:
    //   - a_1 + a_2 + h (a_1 and a_2 are in different subsequences)
    //   - a_2 + a_3 (a_2 and a_3 are in the same subsequence)
    //   So, min_f = min(a_1 + a_2 + h, a_2 + a_3)
    // max_f:
    //   - a_1 + a_n + h (a_1 and a_n are in different subsequences)
    //   - a_{n-1} + a_n (a_{n-1} and a_n are in the same subsequence)
    //   So, max_f = max(a_1 + a_n + h, a_{n-1} + a_n)
    // goodness = max_f - min_f

    long long min_f2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    long long max_f2 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
    long long goodness2 = max_f2 - min_f2;

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            partition[elements[i].original_index] = 1;
        }
    } else {
        std::cout << goodness2 << "\n";
        partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition[elements[i].original_index] = 2;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zeros(n, 0);
    std::vector<int> right_zeros(n, 0);
    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate consecutive zeros/ones to the left
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = (i > 0 ? left_ones[i - 1] : 0) + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate consecutive zeros/ones to the right
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = (i < n - 1 ? right_zeros[i + 1] : 0) + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> b = a; // The final stable sequence

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            // If it's a 0, it can only become 1 if it's part of a 011 or 110 pattern.
            // This means it's surrounded by 1s.
            // A 0 will remain 0 if it's part of 000, 001, 100, 010.
            // It will become 1 if it's part of 011, 110, 111.
            // But we are looking for the minimum k.
            // A 0 can only become 1 if it's part of a block of 0s that is "eaten" by 1s.
            // The 0s in the middle of a block of 0s will remain 0.
            // The 0s at the boundary of a block of 0s and 1s might change.
            // A 0 at index i will remain 0 if it's part of a block of 0s of length >= 2.
            // Or if it's 010.
            // A 0 at index i will become 1 if it's part of 101.
