int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance between any h_i and p_j is 10^10.
    // So max T can be around 10^10.
    // A safe upper bound: max(p_m, h_n) - min(p_1, h_1)
    long long high = std::max(p.back(), h.back()) - std::min(p[0], h[0]);
    if (high < 0) high = 0; // In case p and h ranges don't overlap, e.g., p_max < h_min
    high = std::max(high, 20000000000LL); // A sufficiently large upper bound, 2 * 10^10

    long long ans = high; // Initialize with a value that will be improved

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

