int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required for k torches:
        // k sticks for crafting + k * y sticks for buying k coal
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using trade offer 1.
        // Each trade offer 1 consumes 1 stick and produces x sticks,
        // resulting in a net gain of (x - 1) sticks.
        long long sticks_to_gain = total_sticks_needed - 1;

        // Number of trades of type 1 needed:
        // ceil(sticks_to_gain / (x - 1))
        long long num_stick_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades + num_coal_trades
        // num_coal_trades is k (one trade for each coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

