    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // A 'one' uses 'o', 'n', 'e'
    // The number of 'one's is limited by the count of 'n'
    // because 'n' is only used in 'one'.
    int num_ones = count_n;

    // A 'zero' uses 'z', 'e', 'r', 'o'
    // The number of 'zero's is limited by the count of 'z'
    // because 'z' is only used in 'zero'.
    int num_zeros = count_z;

    // To maximize the number, print all '1's first, then all '0's.
    bool first_output = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 1;
        first_output = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 0;
        first_output = false;
    }
    std::cout << std::endl;

