        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only consider numbers up to 2048
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of this power of two to the current sum
        // We can think of this as having 'count' copies of 'val'.
        // Each 'val' contributes 'val' to the total sum that can be potentially merged.
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

