#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Iterate from right to left (n-1 down to 1)
    // For each position i, we need to check if a[i] can become b[i]
    // based on the elements a[0]...a[i-1] and the current state of has_pos_one/has_neg_one
    for (int i = n - 1; i >= 1; --i) {
        if (a[i] == 1) {
            has_pos_one = true; // This 1 is now to the left of any future i-1
        } else if (a[i] == -1) {
            has_neg_one = true; // This -1 is now to the left of any future i-1
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Cannot increase if no '1' is available to the left
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) { // Cannot decrease if no '-1' is available to the left
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The current a[i] (which is either -1, 0, or 1) contributes to has_pos_one/has_neg_one
        // for elements to its right (which are already processed).
        // For elements to its left (i-1, i-2, etc.), its original value is what matters.
        // The has_pos_one/has_neg_one flags correctly track if there's a 1 or -1
        // *at or to the left of the current index i-1* in the original array `a`.
    }

    std::cout << "YES\n";
}

