int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l != r, there will always be at least one even number.
        // If l is even, l itself is even.
        // If l is odd, l+1 is even (since l < r, l+1 <= r is possible).
        // The only case where there might not be an even number is if l=r and l is odd.
        // But we handle l=r separately.
        // So, for l != r, there's always at least one even number.
        // This means '2' will appear at least once as a divisor.
        //
        // Consider any divisor d > 2.
        // The count of multiples of d in [l, r] is floor(r/d) - floor((l-1)/d).
        // The count of multiples of 2 in [l, r] is floor(r/2) - floor((l-1)/2).
        //
        // If d > 2, then d is either odd or an even number greater than 2.
        //
        // Case 1: d is odd.
        // The multiples of d are d, 2d, 3d, ...
        // The multiples of 2 are 2, 4, 6, ...
        // For any given range, the density of multiples of 2 is higher than the density of multiples of any odd d > 1.
        // Specifically, for any interval of length L, there are approximately L/2 multiples of 2, and L/d multiples of d.
        // Since d > 2, L/d < L/2.
        //
        // Case 2: d is even and d > 2 (e.g., d=4, 6, 8, ...).
        // The multiples of d are d, 2d, 3d, ...
        // The multiples of 2 are 2, 4, 6, ...
        // Again, the density of multiples of 2 is higher than the density of multiples of d.
        // L/d < L/2.
        //
        // The only exception to this general rule is when the range [l, r] is very small and specifically aligned.
        // For example, if [l, r] = [3, 3], then 3 is the answer. (Handled by l==r)
        // If [l, r] = [3, 5], multiples of 2: {4} (count 1). Multiples of 3: {3} (count 1). Multiples of 5: {5} (count 1).
        // In this case, any of 2, 3, 5 would be valid. The problem says "print any of them".
        //
        // If [l, r] = [3, 6], multiples of 2: {4, 6} (count 2). Multiples of 3: {3, 6} (count 2).
        // Here, 2 and 3 both appear twice. The example output is 3.
        //
        // The question asks for the integer that we wrote down the maximum number of times.
        // The number 2 is a divisor of every even number.
        // The number of even numbers in [l, r] is floor(r/2) - floor((l-1)/2).
        //
        // For any d > 2, the number of its multiples in [l, r] is floor(r/d) - floor((l-1)/d).
        // Since d > 2, r/d <= r/2 and (l-1)/d <= (l-1)/2.
        // This implies floor(r/d) - floor((l-1)/d) <= floor(r/2) - floor((l-1)/2) in most cases.
        //
        // The only scenario where a number d > 2 could have an equal or greater count than 2 is if the range is very short
        // and happens to contain more multiples of d than 2, or an equal number.
        //
        // Example: [3, 6]
        // Count for 2: floor(6/2) - floor(2/2) = 3 - 1 = 2 (numbers: 4, 6)
        // Count for 3: floor(6/3) - floor(2/3) = 2 - 0 = 2 (numbers: 3, 6)
        // Here, 2 and 3 both have count 2. The problem allows printing any.
        //
        // Example: [19, 29]
        // Count for 2: floor(29/2) - floor(18/2) = 14 - 9 = 5 (numbers: 20, 22, 24, 26, 28)
        // Count for 3: floor(29/3) - floor(18/3) = 9 - 6 = 3 (numbers: 21, 24, 27)
        // Count for 4: floor(29/4) - floor(18/4) = 7 - 4 = 3 (numbers: 20, 24, 28)
        // Count for 5: floor(29/5) - floor(18/5) = 5 - 3 = 2 (numbers: 20, 25)
        // In this case, 2 clearly wins.
        //
        // The maximum possible count for any divisor is when d=2.
        // The only exception is when l=r, in which case l itself is the only number, and its smallest prime factor (or l itself if prime) would be the answer.
        // But if l=r, then l is the only number, and its divisors (except 1) are the only ones written down.
        // The problem asks for the integer written down the maximum number of times.
        // If l=r, then l is written down once (if l > 1). Any other divisor d of l is also written down once.
        // In this specific case, any divisor of l (except 1) would be a valid answer.
        // The simplest is to just output l itself.
        //
        // Given l != r, the number 2 will always be a divisor for at least one number (an even number) in the range.
        // And its frequency will be maximal or tied for maximal.
        // So, 2 is always a safe answer when l != r.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::max_element

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the input matrix 'a'.
    // The size is (n+1)x(n+1) to use 1-based indexing, matching problem description.
    std::vector<std::vector<int>> a(n + 1, std::vector<int>(n + 1));

    // Read the input matrix 'a'.
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            std::cin >> a[i][j];
        }
    }

    // Declare a vector to store the reconstructed permutation 'p'.
    // Size (n+1) for 1-based indexing.
    std::vector<int> p(n + 1);

    // Iterate through each row 'i' to determine p[i].
    for (int i = 1; i <= n; ++i) {
        // Find the maximum value in the i-th row of 'a', excluding a[i][i].
        // This maximum value will be p[i] if p[i] is not 'n'.
        // If p[i] is 'n', then the maximum value in the row (excluding a[i][i])
        // will be 'n-1' (the second largest element in the permutation).
        int max_val_in_row = 0;
        for (int j = 1; j <= n; ++j) {
            if (i == j) {
                continue; // Skip a[i][i] which is 0
            }
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }

        // If the maximum value found in the row is 'n-1', it means p[i] must be 'n'.
        // This is because if p[i] were less than 'n', then max_val_in_row would be p[i].
        // But if p[i] is 'n', then min(p[i], p[j]) = p[j] for all j != i.
        // The maximum of these p[j] values would be 'n-1'.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            // Otherwise, p[i] is simply the maximum value found in its row.
            // This is because for any j such that p[j] > p[i], min(p[i], p[j]) = p[i].
            // If there is at least one such j, then p[i] will be the maximum in the row.
            // If p[i] is the largest element overall (i.e., p[i]=n), this case is handled above.
            p[i] = max_val_in_row;
        }
    }

    // Print the reconstructed permutation.
    for (int i = 1; i <= n; ++i) {
        std::cout << p[i] << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

