    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos is -1, it means the frog is at cell 0.
                             // If last_R_pos is i, it means the frog is at cell i.
                             // The actual cell index is last_R_pos + 1 for string s.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i (cell i+1).
                // The previous 'R' (or start) was at last_R_pos (cell last_R_pos+1, or 0 if -1).
                // The gap is (current cell) - (previous cell).
                // If last_R_pos was -1 (start at 0), current cell is i+1. Gap is (i+1) - 0 = i+1.
                // If last_R_pos was j, current cell is i+1. Gap is (i+1) - (j+1) = i-j.
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1));
                last_R_pos = i;
            }
        }

        // After iterating through the string, consider the jump from the last 'R' (or start)
        // to the target cell n+1.
        // The last 'R' was at index last_R_pos (cell last_R_pos+1).
        // The target is cell n+1.
        // The gap is (n+1) - (last_R_pos+1).
        max_gap = std::max(max_gap, (n + 1) - (last_R_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

