int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The number of coders (each team needs at least one coder)
        // 2. The number of mathematicians (each team needs at least one mathematician)
        // 3. The total number of students (each team needs 3 students)
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This implies k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'high'.
        // The lower bound is 0.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        // Binary search for the maximum k
        while (low <= high) {
            long long mid = low + (high - low) / 2; // Number of teams we are trying to form

            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians at minimum.
            // The remaining students are:
            // coders_left = c - mid
            // mathematicians_left = m - mid
            // unspecialized_left = x

            // Total students remaining after assigning one coder and one mathematician to each of 'mid' teams:
            // (c - mid) + (m - mid) + x
            // Each of the 'mid' teams still needs one more student.
            // So, we need 'mid' additional students from the remaining pool.
            // If (c - mid) + (m - mid) + x >= mid, then it's possible to form 'mid' teams.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_elements.insert(p[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is greater than q_{i-1}, then p_i must be q_i
            p[i] = q[i];
            if (used_elements.count(p[i])) {
                // q_i is already used, which means it appeared earlier as some p_j (j < i)
                // This is impossible because q_i must be distinct and greater than q_{i-1}
                // and q_i is also the maximum up to this point.
                // If q_i was already used, it means q_i was some p_k for k < i.
                // But then q_k would be q_i, and q_i would not be greater than q_{i-1} if q_i was already used.
                // More simply, if p_i = q_i and q_i was already used, then p is not a permutation.
                possible = false;
                break;
            }
            used_elements.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some value x such that x <= q_{i-1}
            // and x has not been used yet.
            // To maximize our chances of finding a valid permutation, we should pick the smallest available number.
            // The smallest available number that is not used and is less than q_i.
            // We need to find the smallest positive integer 'val' such that 'val' is not in 'used_elements'.
            // We will fill these 'p_i' values later.
            p[i] = -1; // Placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << std::endl;
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet.
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (!used_elements.count(i)) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order for easy pop_back

    // Fill in the placeholder values for p_i where q_i == q_{i-1}
    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q_i == q_{i-1}
            if (available_numbers.empty()) {
                possible = false;
                break;
            }
            int val = available_numbers.back();
            available_numbers.pop_back();

            if (val > q[i]) { // If the smallest available number is greater than q_i, it's impossible
                possible = false;
                break;
            }
            p[i] = val;
        }
    }

    if (!possible) {
        std::cout << -1 << std::endl;
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }
}

