int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use to generate k distinct differences (1 to k)

    // Generate the first k+1 elements to produce k distinct differences
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // For example, if k=4, it's 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1. All 4 distinct differences (1 to 4) are generated.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // The remaining n - (k+1) elements should not introduce new distinct differences.
    // The simplest way to do this is to print the remaining numbers in increasing order.
    // Since we've used numbers from 1 up to (k+1) (or some subset of them, specifically 1 to k+1),
    // the next available number is `left` (which is `(k+1)/2 + 1` if k is odd, or `k/2 + 1` if k is even,
    // but more simply, it's the next unused number from the 'left' side of the alternating sequence).
    // However, the numbers used are 1, 2, ..., k+1. So the next number is k+2.
    // The `left` variable correctly holds the next unused number from the sequence 1, 2, ..., k+1.
    // After the loop, `left` will be `(k+1)/2 + 1` if k is odd, or `k/2 + 1` if k is even.
    // `right` will be `(k+1)/2` if k is odd, or `k/2 + 1` if k is even.
    // The numbers used are `1, 2, ..., k+1`.
    // So, the next number to print is `k+2`.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

