        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        if (n <= 2) { // For n=2, the only subsequence of length >= 2 is p itself.
            std::cout << n << "\n";
            for (int i = 0; i < n; ++i) {
                std::cout << p[i] << (i == n - 1 ? "" : " ");
            }
            std::cout << "\n";
            continue;
        }

        std::vector<int> result_subsequence;
        result_subsequence.push_back(p[0]);

        for (int i = 1; i < n - 1; ++i) {
            // Check if p[i] is a local extremum (peak or valley)
            // A peak: p[i-1] < p[i] and p[i] > p[i+1]
            // A valley: p[i-1] > p[i] and p[i] < p[i+1]
            if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
                result_subsequence.push_back(p[i]);
            }
        }
        result_subsequence.push_back(p[n-1]);

        std::cout << result_subsequence.size() << "\n";
        for (size_t i = 0; i < result_subsequence.size(); ++i) {
