}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count_01 = 0; // Number of positions where a[i] = '0' and b[i] = '1'
    int count_10 = 0; // Number of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            count_01++;
        } else if (a[i] == '1' && b[i] == '0') {
            count_10++;
        }
    }

    // The number of '0's that need to become '1's must equal the number of '1's that need to become '0's
    // if we only use swaps.
    // Any excess must be handled by flips.
    // For example, if count_01 > count_10, then count_01 - count_10 '0's need to become '1's,
    // but there are no '1's available to swap into them. These must be flipped.
    // Similarly if count_10 > count_01.
    // The number of flips needed is |count_01 - count_10|.
    // Each flip costs 1.
    cost += std::abs(count_01 - count_10);

    // After handling the excess with flips, we are left with min(count_01, count_10) pairs
    // where a '0' needs to become a '1' and a '1' needs to become a '0'.
    // These can be handled by swaps. Each swap costs 1.
    cost += std::min(count_01, count_10);

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // They must be <= s. If a[i] > s, decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // They must be >= s. If a[i] < s, increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::upper_bound

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the first point of a potential triplet (x_i)
    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find points x[j] and x[k] such that i < j < k
        // and x[k] - x[i] <= d.
        // This means x[k] <= x[i] + d.

        // Find the rightmost index 'k_max_idx' such that x[k_max_idx] <= x[i] + d.
        // std::upper_bound returns an iterator to the first element greater than (x[i] + d).
        // So, we need to decrement the iterator to get the last element less than or equal to (x[i] + d).
        // The search range for k is from i+1 to n-1.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The elements from x[i+1] up to *(it-1) are potential candidates for x[j] or x[k].
        // The number of such candidates is (it - x.begin()) - (i + 1).
        // Let this count be 'num_candidates'.
        // These candidates are at indices from (i+1) to (it - x.begin() - 1).

        // If it points to x.begin() + i + 1, it means no element in the range is <= x[i] + d.
        // In this case, num_candidates would be 0 or negative, which is handled correctly.

        // The index of the last valid point for k is (it - x.begin() - 1).
        // Let's call this index 'k_upper_bound_idx'.
        // All points x[j] and x[k] must be chosen from the range [x[i+1], ..., x[k_upper_bound_idx]].
        // The number of points in this range is (k_upper_bound_idx - (i+1) + 1).
        // Let m be the number of points available after x[i] that satisfy the distance condition.
        // m = (it - x.begin()) - (i + 1);
        // These 'm' points are x[i+1], x[i+2], ..., x[i+m].
        // We need to choose 2 points from these 'm' points to form x[j] and x[k].
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (it - x.begin()) - (i + 1);

        if (m >= 2) { // We need at least 2 points (for x_j and x_k)
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

