struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th element of the sorted A (a_elements[i].value)
    // should be paired with the (m-1-i)-th element of the sorted B (b_elements[m-1-i].value)
    // This pairing maximizes F(A'_i, B_i) because F(n, k) is increasing in n and decreasing in k.
    // So, largest A values should be paired with smallest B values.
    // The original index of b_elements[m-1-i] tells us where this pair should go in the output.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The value a_elements[i].value (which is the i-th smallest A value)
        // should be placed at the position corresponding to b_elements[m-1-i].original_index
        // because b_elements[m-1-i] is the (m-1-i)-th smallest B value,
        // which means it's the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

