        }
        suffix_max[i] = current_max;
        if (distinct_count == len_from_end && current_max == len_from_end) {
            suffix_is_perm[len_from_end] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

