int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int win_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (i > 0 && s[i-1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (win_count == 0) { // All L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k L's to W's. Maximize by making them consecutive.
                // If k=1, score is 1. If k>1, score is 1 + 2*(k-1).
                std::cout << 1 + 2 * (k - 1) << "\n";
            }
            continue;
        }

        // If there are already W's
        // Strategy:
        // 1. Fill gaps between W's.
        // 2. Extend W streaks at ends.
        // 3. If k still remains, convert isolated L's to W's.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Calculate gaps between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        // Fill gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len; // Each L in gap becomes W, connecting two W streaks, adding 2 points per L
                win_count += gap_len;
            } else {
                // Not enough k to fill this gap, use remaining k here
                current_score += 2 * k;
                win_count += k;
                k = 0;
                break;
            }
        }

        // Extend streaks at ends
        if (k > 0) {
            // L's before first W
            int L_before_first_W = first_W;
            int can_add_before = std::min(k, L_before_first_W);
            current_score += 2 * can_add_before;
            win_count += can_add_before;
            k -= can_add_before;
        }

        if (k > 0) {
            // L's after last W
            int L_after_last_W = n - 1 - last_W;
            int can_add_after = std::min(k, L_after_last_W);
            current_score += 2 * can_add_after;
            win_count += can_add_after;
            k -= can_add_after;
        }

        // If k still remains, it means we can convert more L's to W's.
        // These would be isolated L's or L's that extend existing streaks.
        // Since we've already filled gaps and extended ends, any remaining k
        // will convert an L to a W, adding 2 points (if it connects to an existing W)
        // or 1 point (if it's an isolated W).
        // However, the current_score calculation already accounts for the 1 point for the first W.
        // Each additional W (beyond the first one in a streak) adds 2 points.
        // We've already added 1 point for each initial W.
        // When we convert an L to W, it either:
        // 1. Connects two W streaks (handled by gaps, adds 2 per L)
        // 2. Extends a W streak (handled by ends, adds 2 per L)
        // 3. Creates a new W streak (if it's an L far from any W, adds 1 per L)
        // 4. Converts an L adjacent to a W, but not connecting two Ws (adds 2 per L)
        // The logic for `current_score += 2 * k` for remaining `k` is correct because
        // `win_count` is the total number of W's.
        // The score is `1 + 2 * (total_W - 1)` if all are connected.
        // Or, more simply, each W contributes 1 point, and each W that follows another W contributes an additional 1 point.
        // So, score = total_W + (total_W - number_of_W_streaks).
        // When we convert an L to W, it increases total_W by 1.
        // If it connects two streaks, number_of_W_streaks decreases by 1.
        // If it extends a streak, number_of_W_streaks stays same.
        // If it creates a new streak, number_of_W_streaks increases by 1.
        //
        // A simpler way to think about the remaining k:
        // Each L converted to W adds 1 point (base for being a W).
        // If this new W is adjacent to an existing W, it adds an *additional* 1 point.
        // Since we've already maximized connections, any remaining k will either extend a streak (adding 2 points)
        // or create a new isolated W (adding 1 point).
        // The maximum we can get from remaining k is by extending streaks.
        // The `win_count` variable already tracks the total number of 'W's.
        // The maximum possible score for `win_count` 'W's is `1 + 2 * (win_count - 1)` if `win_count > 0`.
        // If `win_count == 0`, it's 0.
        // The `current_score` is the score from the current configuration of W's.
        // The `k` remaining can be used to convert `k` more L's to W's.
        // Each such conversion will add 2 points to the score, as it will extend an existing streak or connect to one.
        // The only exception is if all `n` games are already W's, in which case `k` must be 0.
        // If `win_count < n`, there are still L's.
        // Each remaining `k` can be used to convert an L to W. This will add 2 points to the score.
        // This is because we've already handled the case where `win_count == 0` at the beginning.
        // So, if `win_count > 0`, any new W will either extend an existing streak or connect to one.
        // The only case where it adds 1 point is if it's the very first W, which is handled.
        // So, `current_score += 2 * k` is correct for remaining `k`.
        current_score += 2 * k;

        // The maximum possible score is 1 + 2*(n-1) if all games are W.
        // We should cap the score at this maximum.
        std::cout << std::min(current_score, 1 + 2 * (n - 1)) << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char move : s) {
            counts[move]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine as per problem statement.
        // R, P, S order is arbitrary but consistent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints),
        // or if there's a tie, the first one encountered in the above order wins.
        // For example, if R=2, P=2, S=1, then P would be chosen.
        // If R=2, P=1, S=2, then R would be chosen.
        // This is fine as any optimal answer is accepted.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends who get w_i = 1 items:
    // These friends contribute 2 * item_value to happiness.
    // To maximize, they should get the largest available items.
    // These are the k_ones largest items from 'a'.
    int a_idx = n - 1; // Pointer to the largest available elements in 'a'
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_idx];
            a_idx--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here and process them in the next loop.
            // Or, more simply, just let the loop continue and the next loop
            // will handle the remaining w[i] values.
            // For clarity, let's process w_i > 1 in a separate pass.
            // The current loop processes w_i = 1 from smallest w_i to largest w_i.
            // This means it processes the smallest w_i values first.
            // Since w_i=1 are at the beginning of sorted w, this is correct.
            // The largest elements of 'a' are assigned to these friends.
        }
    }

    // Friends who get w_i > 1 items:
    // These friends contribute max_val + min_val to happiness.
    // To maximize, they should get the largest available item as max_val,
    // and the largest available item as min_val (among the smallest available items).
    // The largest available items for max_val are the remaining largest elements in 'a'.
    // The smallest available items for min_val are the smallest elements in 'a'.

    // The largest elements of 'a' are already assigned to friends with w_i = 1.
    // The remaining largest elements of 'a' (from a_idx down to 0) will be assigned as max_val.
    // The smallest elements of 'a' (from 0 upwards) will be assigned as min_val.

    // Iterate w in descending order for w_i > 1.
    // This ensures friends who need more items (larger w_i) get their min_val from smaller 'a' indices.
    // Friends who need fewer items (smaller w_i > 1) get their min_val from larger 'a' indices.
    // This is because larger w_i values "consume" more of the smallest elements.
    int current_a_min_idx = 0; // Pointer to the smallest available elements in 'a'
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            // This friend gets w[i] items.
            // They get one largest available item (from a_idx) as their max_val.
            total_happiness += a[a_idx];
            a_idx--;

            // They get one smallest available item (from current_a_min_idx) as their min_val.
            total_happiness += a[current_a_min_idx];

            // The remaining w[i] - 2 items are "filler" items.
            // These filler items are taken from the smallest available elements,
            // effectively skipping w[i] - 2 elements from the beginning of 'a'.
            current_a_min_idx += (w[i] - 1); // Move past the min_val and filler items
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

