#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be combined with any 'a's to its left.
            // Each 'a' to its left will eventually "pass through" this 'b'.
            // When an 'a' passes a 'b', it effectively creates a new 'b' and moves past it.
            // The number of steps this 'b' contributes is equal to the current count of 'a's.
            // This 'b' also doubles the number of 'a's that will be processed by 'b's further left.
            // This is because 'ab' -> 'bba'. The 'a' moves past the 'b', and a new 'b' is created.
            // The 'a' that moved past will interact with subsequent 'b's.
            // The new 'b' will also interact with subsequent 'a's (which are to its left).
            // However, the logic is simpler: each 'a' to the left of a 'b' will eventually
            // cause an 'ab' -> 'bba' operation involving that 'b'.
            // The total steps for this 'b' is `count_a`.
            // After this 'b' is processed, any 'a's to its left will effectively see
            // not just the original 'b', but also the new 'b' created by the 'ab' -> 'bba' operation.
            // This means the number of 'a's effectively doubles for the next 'b' to the left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's that are
            // waiting to be processed by 'b's to their right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the string produced by our w
    for (int i = 0; i < n; ++i) {
        // s_prime[i] is '1' if w[i-x] is '1' OR w[i+x] is '1'
        bool possible_from_left = (i - x >= 0 && w[i - x] == '1');
        bool possible_from_right = (i + x < n && w[i + x] == '1');

        if (possible_from_left || possible_from_right) {
            s_prime[i] = '1';
        }
    }

    // Step 3: Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

