#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            counts[j][i + 1] = counts[j][i];
        }
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The condition for termination is that all 3-character substrings
        // are permutations of 'x', 'y', 'z' AND are one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' must be "balanced"
        // such that their difference is at most 1.
        // If the counts are not balanced, then there must be at least one
        // 3-character substring that is not a permutation of 'x', 'y', 'z'
        // (e.g., "xxx", "xxy", "xyy", etc.) or is one of "xyz", "yzx", "zxy".
        // In either case, such a substring can be picked and rearranged.
        // The algorithm terminates if it can reach a state where all 3-char substrings
        // are "zyx", "xzy", "yxz". This is possible if and only if the counts
        // of 'x', 'y', 'z' in the substring can be made to differ by at most 1.
        // Since rearranging a 3-char substring doesn't change the total counts
        // of 'x', 'y', 'z' in the entire string, the initial counts must satisfy this.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

