#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string result(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');
        bool possible_with_split = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) {
                // Must be color 1
                if (!s1_digits.empty() && d[i] < s1_digits.back()) {
                    possible_with_split = false;
                    break;
                }
                s1_digits.push_back(d[i]);
                current_coloring[i] = '1';
            } else if (d[i] > split_digit) {
                // Must be color 2
                if (!s2_digits.empty() && d[i] < s2_digits.back()) {
                    possible_with_split = false;
                    break;
                }
                s2_digits.push_back(d[i]);
                current_coloring[i] = '2';
            } else { // d[i] == split_digit
                // Can be either color 1 or color 2
                // Prioritize color 2 if it maintains non-decreasing order for S2
                // This greedy choice is crucial: if d[i] == split_digit,
                // it's better to put it in S2 if possible, to keep S1 smaller.
                // If S2 is empty or d[i] >= S2.back(), put it in S2.
                // Otherwise, it must go to S1.
                if (s2_digits.empty() || d[i] >= s2_digits.back()) {
                    s2_digits.push_back(d[i]);
                    current_coloring[i] = '2';
                } else {
                    // Must go to S1
                    if (!s1_digits.empty() && d[i] < s1_digits.back()) {
                        possible_with_split = false;
                        break;
                    }
                    s1_digits.push_back(d[i]);
                    current_coloring[i] = '1';
                }
            }
        }

        if (possible_with_split) {
            // Final check: S1 and S2 must be individually sorted.
            // The logic above ensures this for S1 and S2 based on their last elements.
            // Also, the last element of S1 must be <= first element of S2.
            // This is implicitly handled by the split_digit logic:
            // all S1 elements are <= split_digit, all S2 elements are >= split_digit.
            // So, if S1 is not empty and S2 is not empty, S1.back() <= split_digit <= S2.front().
            // The only edge case is if a digit equal to split_digit was forced into S1
            // but it was greater than S1.back(). This is handled by the `d[i] < s1_digits.back()` check.

            // The crucial part is that if d[i] == split_digit, we try to put it in S2.
            // If it can't go to S2 (because d[i] < s2_digits.back()), then it must go to S1.
            // If it can't go to S1 either (because d[i] < s1_digits.back()), then this split_digit fails.

            // Let's re-verify the logic for d[i] == split_digit.
            // If d[i] == split_digit:
            //   Option A: Paint 1. Requires d[i] >= s1_digits.back() (if s1_digits not empty).
            //   Option B: Paint 2. Requires d[i] >= s2_digits.back() (if s2_digits not empty).
            //
            // Our current strategy:
            //   If (s2_digits is empty OR d[i] >= s2_digits.back()):
            //     Paint 2.
            //   Else (d[i] < s2_digits.back()):
            //     Must paint 1. Requires d[i] >= s1_digits.back() (if s1_digits not empty).
            //     If not, then impossible.
            // This strategy is correct because it tries to keep S1 as small as possible,
            // which maximizes the chance that future digits (especially those < split_digit)
            // can be placed in S1.

            found_solution = true;
            result = current_coloring;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?');

    // Step 1: Propagate known characters based on k-periodicity
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_chars[i % k] == '?') {
                fixed_chars[i % k] = s[i];
            } else if (fixed_chars[i % k] != s[i]) {
                // Conflict: s[i] contradicts a previously determined character for this position modulo k
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Apply fixed_chars back to s (conceptually, not modifying s directly)
    // and check for k-balance in the first k characters.
    // We only need to check the first k characters because of the periodicity.
    // If s[0...k-1] is k-balanced, and s[i] == s[i+k], then all k-length substrings will be k-balanced.
    int zeros = 0;
    int ones = 0;
    int questions = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            zeros++;
        } else if (fixed_chars[i] == '1') {
            ones++;
        } else { // fixed_chars[i] == '?'
            questions++;
        }
    }

    // Check if it's possible to fill '?'s to achieve k/2 zeros and k/2 ones
    int required_zeros = k / 2;
    int required_ones = k / 2;

    if (zeros > required_zeros || ones > required_ones) {
        std::cout << "NO\n";
        return;
    }

    // We need to fill (required_zeros - zeros) more zeros and (required_ones - ones) more ones
    // using the '?' characters.
    int needed_zeros_from_q = required_zeros - zeros;
    int needed_ones_from_q = required_ones - ones;

    if (needed_zeros_from_q + needed_ones_from_q == questions) {
        std::cout << "YES\n";
    } else {
        // This case should ideally not happen if the previous checks are correct,
        // as (required_zeros - zeros) + (required_ones - ones) must equal questions
        // if a solution exists.
        // However, it's a good final check.
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_p = p;
        long long i = temp_q; // The remaining prime factor
        while (current_p % i == 0 && current_p % q == 0) {
            current_p /= i;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

