int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 == 0, robot cannot move left.
            // This means it must be able to reach (X, Y) from (x, y)
            // without needing to move left from (x, y).
            // If X < x, it would need to move left.
            // So, if f1 == 0, then X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 == 0, robot cannot move up.
            // If Y > y, it would need to move up.
            // So, if f2 == 0, then Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 == 0, robot cannot move right.
            // If X > x, it would need to move right.
            // So, if f3 == 0, then X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 == 0, robot cannot move down.
            // If Y < y, it would need to move down.
            // So, if f4 == 0, then Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // Our calculated min_x, max_x, min_y, max_y might be outside this range
            // if all robots have full movement capabilities and start far away.
            // However, any point within the valid range [min_x, max_x] x [min_y, max_y] is a valid target.
            // We just need to pick one. The problem statement implies that if a solution exists,
            // we can pick one within [-10^5, 10^5].
            // So, we can clamp the chosen point to the guaranteed range.
            // For example, if min_x is 10^6, we can still output 10^5 as X,
            // because the problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // This means that if min_x > 10^5, then there must be a valid X <= 10^5.
            // This implies that the actual valid range for X must be within [-10^5, 10^5]
            // if a solution exists.
            // So, we can just output min_x and min_y directly, as they will be within the guaranteed range
            // if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum_r = sum of r from 1 to b-1
    // Sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14.
    // We need to handle division by 2.
    // (b-1) * b is always even, so (b-1)*b/2 is an integer.
    // We need to compute this modulo MOD.
    // (b-1) % MOD * (b % MOD) % MOD * (2^-1 % MOD) % MOD
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum_k_term = sum of (k*b + 1) from k=1 to a
    // Sum_k_term = sum of (k*b) + sum of (1)
    // Sum_k_term = b * sum of k from 1 to a + a
    // Sum_k_term = b * (a * (a+1) / 2) + a
    // Again, handle division by 2.
    long long sum_k_val_part1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val_part1 = (sum_k_val_part1 * inv2) % MOD;
    sum_k_val_part1 = (sum_k_val_part1 * (b % MOD)) % MOD;

    long long sum_k_val_part2 = a % MOD;

    long long sum_k_term = (sum_k_val_part1 + sum_k_val_part2) % MOD;

    // Total sum = sum_r_term * sum_k_term
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

