int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long val_from_left = 0;

        // Remove elements from deque that are taller than or equal to current_h
        // These elements cannot be the 'leftmost' block for current_h's water level
        while (!dq_L.empty() && dq_L.back().first >= current_h) {
            dq_L.pop_back();
        }

        if (dq_L.empty()) {
            // No tower to the left is shorter than current_h.
            // The water level can rise up to current_h.
            // The number of operations is current_h.
            val_from_left = current_h;
        } else {
            // The closest shorter tower to the left is dq_L.back().first.
            // The water level can rise up to dq_L.back().first.
            // From that point, it can rise further by 1 for each step to the right.
            // The number of operations is dq_L.back().first + (i - dq_L.back().second).
            val_from_left = dq_L.back().first + (i - dq_L.back().second);
        }
        L[i] = val_from_left;

        // Add current tower to deque.
        // It's important to add {min(current_h, val_from_left), i}
        // because the effective height for future towers to its right is limited by val_from_left.
        // If current_h is smaller than val_from_left, it means current_h is the bottleneck.
        // If current_h is larger than val_from_left, it means val_from_left is the bottleneck.
        // The actual height that can be "seen" from the right is min(current_h, val_from_left).
        // However, the problem is about the number of operations.
        // The value `val_from_left` represents the number of operations for the block at `(i, val_from_left-1)`.
        // If `current_h` is smaller than `val_from_left`, then the tower `i` itself limits the operations.
        // The maximum operations for tower `i` is `current_h`.
        // So, the effective height for future towers is `min(current_h, val_from_left)`.
        // But the deque should store the actual height `h[i]` to correctly calculate `val_from_left` for `i+1`.
        // The logic for `val_from_left` already correctly handles `h[i]`.
        // The deque should store `h[i]` as the height, and `i` as the index.
        dq_L.push_back({current_h, i});
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_h = h[i];
        long long val_from_right = 0;

        while (!dq_R.empty() && dq_R.back().first >= current_h) {
            dq_R.pop_back();
        }

        if (dq_R.empty()) {
            val_from_right = current_h;
        } else {
            val_from_right = dq_R.back().first + (dq_R.back().second - i);
        }
        R[i] = val_from_right;
        dq_R.push_back({current_h, i});
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

