#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make all elements except the last one divisible by n.
    // For each a[i] (0 <= i < n-1), we want a[i] + b_i = k * n for some integer k.
    // We can achieve this by adding (n - (a[i] % n)) % n to a[i].
    // Let rem = a[i] % n. If rem is negative, (rem + n) % n gives the positive remainder.
    // So, we want to add (n - (a[i] % n + n) % n) % n.
    // Let's simplify: target_rem = 0. We want a[i] + b_i = 0 (mod n).
    // So b_i = -a[i] (mod n).
    // b_i = (-a[i] % n + n) % n.
    // This b_i is in [0, n-1].
    // We need to add b_i to a[i].
    // The segment is [1, n-1] (0-indexed: [0, n-2]). Length is n-1.
    // This operation is tricky because the length is n-1, not n.
    // The problem states we can add a multiple of len.
    // If n=1, this segment is empty.

    // A common strategy for this type of problem is to use the property that
    // if we have a number x, we can make it 0 (mod N) by adding (N - (x % N)) % N.
    // This added value is in [0, N-1].
    // If we apply this to a segment of length N, we can make all elements 0 (mod N).

    // Let's use the standard approach for this problem:
    // 1. Make all elements a[i] divisible by n.
    // 2. Make all elements 0.

    // Operation 1: For elements a[0] to a[n-2] (segment [1, n-1])
    // Length of segment is n-1.
    // We want to make a[i] + b_i = 0 for i in [0, n-2].
    // This is not directly possible if a[i] is not divisible by n-1.

    // The standard solution for this problem type:
    // 1. For each a[i], make a[i] % n == 0.
    //    This can be done by adding (n - (a[i] % n + n) % n) to a[i].
    //    The added value is in [0, n-1].
    //    If we select segment [1, n] (length n), we can add these values.
    //    After this, all a[i] are multiples of n.
    // 2. For each a[i], make a[i] = 0.
    //    Since all a[i] are now multiples of n, we can select segment [1, n] (length n)
    //    and add -a[i] to each a[i]. This makes them all zero.

    // This uses two operations. We need three.
    // The trick is to handle the case n=1 separately or carefully.

    // If n=1:
    // Op 1: [1, 1], add -a[0]. a[0] becomes 0.
    // Op 2: [1, 1], add 0. a[0] remains 0.
    // Op 3: [1, 1], add 0. a[0] remains 0.
    if (n == 1) {
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // General case n > 1:

    // Operation 1: Make a[0]...a[n-2] divisible by n.
    // Segment: [1, n-1] (0-indexed: [0, n-2]). Length: n-1.
    // For each a[i] in this segment, we want to add b_i such that a[i] + b_i is a multiple of n.
    // And b_i must be a multiple of (n-1).
    // Let current_val = a[i]. We want current_val + b_i = k * n.
    // And b_i = m * (n-1).
    // So, current_val + m * (n-1) = k * n.
    // current_val + m * (-1) = k * 0 (mod n)
    // current_val - m = 0 (mod n)
    // m = current_val (mod n).
    // Let m_val = (a[i] % n + n) % n. This is the smallest non-negative m.
    // Then b_i = m_val * (n-1).
    // This b_i will make a[i] + b_i a multiple of n.
    // Example: a[i]=1, n=4. Segment length n-1=3.
    // m_val = (1 % 4 + 4) % 4 = 1.
    // b_i = 1 * 3 = 3.
    // a[i] + b_i = 1 + 3 = 4. This is a multiple of n=4.
    // Example: a[i]=3, n=4. Segment length n-1=3.
    // m_val = (3 % 4 + 4) % 4 = 3.
    // b_i = 3 * 3 = 9.
    // a[i] + b_i = 3 + 9 = 12. This is a multiple of n=4.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // a[i] mod n, always non-negative
        long long add_val = remainder * (n - 1); // This is b_i
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n.
    // Segment: [n, n] (0-indexed: [n-1, n-1]). Length: 1.
    // For a[n-1], we want to add b_{n-1} such that a[n-1] + b_{n-1} is a multiple of n.
    // And b_{n-1} must be a multiple of 1. This is always true.
    // We want a[n-1] + b_{n-1} = k * n.
    // So b_{n-1} = -a[n-1] (mod n).
    // Let remainder = (a[n-1] % n + n) % n.
    // We need to add (n - remainder) % n.
    // This value is in [0, n-1].
    // This makes a[n-1] a multiple of n.
    // Example: a[n-1]=1, n=4. Segment length 1.
    // remainder = (1 % 4 + 4) % 4 = 1.
    // add_val = (4 - 1) % 4 = 3.
    // a[n-1] + add_val = 1 + 3 = 4. This is a multiple of n=4.

    std::cout << n << " " << n << "\n";
    long long remainder_last = (a[n - 1] % n + n) % n;
    long long add_val_last = (n - remainder_last) % n;
    std::cout << add_val_last << "\n";
    a[n - 1] += add_val_last; // Update a[n-1]

    // After these two operations, all elements a[i] are multiples of n.
    // Operation 3: Make all elements zero.
    // Segment: [1, n] (0-indexed: [0, n-1]). Length: n.
    // For each a[i], since it's a multiple of n, we can add -a[i].
    // -a[i] is a multiple of n. So this is a valid operation.

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two "test" values: 0 and 1023 (all bits set)
    // We track how these values change after all operations.
    // This allows us to determine the final state of each bit.
    int val0 = 0;    // Represents the state of a bit if it starts as 0
    int val1023 = 1023; // Represents the state of a bit if it starts as 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 0:
    //   The bit always becomes 0, regardless of input. (x_j -> 0)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 1:
    //   The bit always becomes 1, regardless of input. (x_j -> 1)
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 1:
    //   The bit remains unchanged. (x_j -> x_j)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 0:
    //   The bit is flipped. (x_j -> !x_j)

    // We want to find three constants A, B, C such that
    // ( (x & A) | B ) ^ C
    // can represent the final transformation for all bits.

    // Let's determine the target values for A, B, C bit by bit.
    // For each bit j:
    // Let x_j be the j-th bit of the input.
    // Let a_j, b_j, c_j be the j-th bits of A, B, C respectively.
    // The output bit is ((x_j & a_j) | b_j) ^ c_j.

    // Case 1: x_j -> 0
    //   This means:
    //   If x_j=0, output is 0: ((0 & a_j) | b_j) ^ c_j = (0 | b_j) ^ c_j = b_j ^ c_j = 0
    //   If x_j=1, output is 0: ((1 & a_j) | b_j) ^ c_j = (a_j | b_j) ^ c_j = 0
    //   From b_j ^ c_j = 0, we get b_j = c_j.
    //   Then (a_j | b_j) ^ b_j = 0. This implies a_j | b_j = b_j.
    //   This is true if a_j = 0.
    //   So, for x_j -> 0, we need a_j=0, b_j=0, c_j=0 OR a_j=0, b_j=1, c_j=1.
    //   The simplest choice is a_j=0, b_j=0, c_j=0.

    // Case 2: x_j -> 1
    //   This means:
    //   If x_j=0, output is 1: ((0 & a_j) | b_j) ^ c_j = b_j ^ c_j = 1
    //   If x_j=1, output is 1: ((1 & a_j) | b_j) ^ c_j = (a_j | b_j) ^ c_j = 1
    //   From b_j ^ c_j = 1, we get b_j != c_j.
    //   Then (a_j | b_j) ^ c_j = 1.
    //   If b_j=0, c_j=1: (a_j | 0) ^ 1 = a_j ^ 1 = 1 => a_j = 0.
    //   If b_j=1, c_j=0: (a_j | 1) ^ 0 = 1 ^ 0 = 1. This is always true.
    //   So, for x_j -> 1, we need a_j=0, b_j=0, c_j=1 OR a_j=any, b_j=1, c_j=0.
    //   The simplest choice is a_j=0, b_j=0, c_j=1.

    // Case 3: x_j -> x_j (identity)
    //   This means:
    //   If x_j=0, output is 0: b_j ^ c_j = 0 => b_j = c_j
    //   If x_j=1, output is 1: (a_j | b_j) ^ c_j = 1
    //   Since b_j = c_j, we have (a_j | b_j) ^ b_j = 1.
    //   This implies a_j | b_j != b_j. This is true if a_j = 1 and b_j = 0.
    //   So, for x_j -> x_j, we need a_j=1, b_j=0, c_j=0.

    // Case 4: x_j -> !x_j (flip)
    //   This means:
    //   If x_j=0, output is 1: b_j ^ c_j = 1 => b_j != c_j
    //   If x_j=1, output is 0: (a_j | b_j) ^ c_j = 0
    //   If b_j=0, c_j=1: (a_j | 0) ^ 1 = a_j ^ 1 = 0 => a_j = 1.
    //   If b_j=1, c_j=0: (a_j | 1) ^ 0 = 1 ^ 0 = 0. This is false.
    //   So, for x_j -> !x_j, we need a_j=1, b_j=0, c_j=1.

    // Let's define the target A, B, C values based on these observations.
    // We want to find A_final, B_final, C_final such that
    // ( (x & A_final) | B_final ) ^ C_final
    // is the desired function.

    // Initialize A_final to all ones (1023), B_final to all zeros (0), C_final to all zeros (0).
    // This corresponds to the identity transformation (x_j -> x_j) for all bits.
    int A_final = 1023; // Initial state for A: all bits are 1
    int B_final = 0;    // Initial state for B: all bits are 0
    int C_final = 0;    // Initial state for C: all bits are 0

    for (int j = 0; j < 10; ++j) { // Iterate through each bit position
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1023 = (val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) { // x_j -> 0
            // To achieve x_j -> 0 with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=0, b_j=0, c_j=0.
            // Current A_final has 1 at bit j. Set it to 0.
            A_final &= ~(1 << j); // Set j-th bit of A_final to 0
            // B_final and C_final already have 0 at bit j.
        } else if (bit_val0 == 1 && bit_val1023 == 1) { // x_j -> 1
            // To achieve x_j -> 1 with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=0, b_j=0, c_j=1.
            // Current A_final has 1 at bit j. Set it to 0.
            A_final &= ~(1 << j); // Set j-th bit of A_final to 0
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Set it to 1.
            C_final |= (1 << j);  // Set j-th bit of C_final to 1
        } else if (bit_val0 == 0 && bit_val1023 == 1) { // x_j -> x_j (identity)
            // To achieve x_j -> x_j with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=1, b_j=0, c_j=0.
            // Current A_final has 1 at bit j. Keep it 1.
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Keep it 0.
            // No change needed for A_final, B_final, C_final for this bit.
        } else if (bit_val0 == 1 && bit_val1023 == 0) { // x_j -> !x_j (flip)
            // To achieve x_j -> !x_j with ((x_j & a_j) | b_j) ^ c_j:
            // We need a_j=1, b_j=0, c_j=1.
            // Current A_final has 1 at bit j. Keep it 1.
            // Current B_final has 0 at bit j. Keep it 0.
            // Current C_final has 0 at bit j. Set it to 1.
            C_final |= (1 << j);  // Set j-th bit of C_final to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_final != 1023) { // If A_final is not all ones, we need an AND operation
        result_ops.push_back({'&', A_final});
    }
    if (B_final != 0) { // If B_final is not all zeros, we need an OR operation
        result_ops.push_back({'|', B_final});
    }
    if (C_final != 0) { // If C_final is not all zeros, we need an XOR operation
        result_ops.push_back({'^', C_final});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If there are no zeros, all substrings contain '1's
        if (num_zeros == 0) {
            std::cout << total_substrings << "\n";
            continue;
        }

        // To maximize f(s), we need to minimize the number of substrings
        // consisting only of '0's. This is achieved by distributing the
        // '0's as evenly as possible among the 'm+1' possible gaps
        // created by 'm' ones.
        // The 'm' ones divide the string into m+1 segments where zeros can be placed.
        // Example: _ 1 _ 1 _ ... _ 1 _
        // There are m+1 "slots" for zeros.

        // Number of zeros to be placed in each of the (m+1) slots
        long long k = num_zeros / (m + 1); // Minimum number of zeros in a slot
        long long r = num_zeros % (m + 1); // Number of slots that get one extra zero

        // r slots will have (k+1) zeros
        // (m+1 - r) slots will have k zeros

        // Calculate substrings of '0's from blocks of k zeros
        long long substrings_from_k_zeros = k * (k + 1) / 2;
        // Calculate substrings of '0's from blocks of (k+1) zeros
        long long substrings_from_k_plus_1_zeros = (k + 1) * (k + 2) / 2;

        // Total substrings consisting only of '0's
        long long zero_substrings_count = 
            r * substrings_from_k_plus_1_zeros + 
            (m + 1 - r) * substrings_from_k_zeros;

        // f(s) = (total substrings) - (substrings with only '0's)
        long long result = total_substrings - zero_substrings_count;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an initially empty graph
    // and calculating APSP sum for the current set of active vertices.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added to the active set

        active_vertices[k] = true;

        // Update shortest paths using vertex k as an intermediate node
        // Floyd-Warshall update step: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This needs to be done for all pairs (i, j) where i, j are currently active.
        // Since we are adding k, we also need to consider paths involving k.
        // The order of loops matters for correctness: k must be the outermost loop
        // in the standard Floyd-Warshall. Here, k is the vertex being added.
        // So, we iterate over all currently active i and j, and update paths
        // using k as an intermediate.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Update paths using k as an intermediate
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if -1 was used for infinity
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // After adding k and updating paths involving k, we also need to update
        // paths between existing active vertices using k as an intermediate.
        // This is already covered by the triple loop above, but it's important
        // to ensure that all pairs (i,j) where i,j,k are active are considered.
        // The previous loop structure correctly handles this.
        // The standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // Here, 'k' is the vertex being added. So, we iterate over all 'i' and 'j'
        // that are currently active (including 'k' itself).
        // The loops above correctly implement this.

        // Calculate the sum of shortest paths for all currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Output results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
