int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> left_ones(n, 0);  // left_ones[i] = count of consecutive ones ending at i

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = (i > 0 ? left_ones[i - 1] : 0) + 1;
            left_zeros[i] = 0;
        }
    }

    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> right_ones(n, 0);  // right_ones[i] = count of consecutive ones starting at i

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = (i < n - 1 ? right_zeros[i + 1] : 0) + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> b = a; // The final stable sequence

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0 && a[i - 1] == 1 && a[i + 1] == 1) { // Pattern 101
            int l = left_ones[i - 1]; // Length of 1s to the left
            int r = right_ones[i + 1]; // Length of 1s to the right
            int k = std::min(l, r);
            max_k = std::max(max_k, k);

            // Change 0s to 1s
            for (int j = 0; j < k; ++j) {
                b[i - j] = 1;
                b[i + j] = 1;
            }
        } else if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) { // Pattern 010
            int l = left_zeros[i - 1]; // Length of 0s to the left
            int r = right_zeros[i + 1]; // Length of 0s to the right
            int k = std::min(l, r);
            max_k = std::max(max_k, k);

            // Change 1s to 0s
            for (int j = 0; j < k; ++j) {
                b[i - j] = 0;
                b[i + j] = 0;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

