#include <numeric>

// Using a global array for a_values to avoid passing it around
// and to allow direct access from the recursive function.
// Max N is 2e5, so a_values[2e5] is fine.
// We need a_values[0] to a_values[N-1] for 0-indexed access.
// The problem uses 1-indexed a_1 to a_n.
// We'll map problem's a_k to a_values[k-1].
// So a_values[0] is a_1, a_values[1] is a_2, ..., a_values[N-1] is a_n.
std::vector<long long> a_values;
int N_global; // Store N globally for easy access

// Memoization tables for results and visited states
// `memo_res[x_idx][parity]` stores the final y value if terminated, or -1 if cycle/non-terminating.
// `memo_state[x_idx][parity]` stores the state:
//   0: not visited
//   1: currently visiting (part of current path, potential cycle)
//   2: visited and computed (result in memo_res is final)
std::vector<std::vector<long long>> memo_res;
std::vector<std::vector<int>> memo_state;

// Recursive function to calculate the final y value
// current_x_1_indexed: The current value of x (1-indexed as per problem)
// current_y: The current value of y
// is_step2: true if we are about to perform step 2, false if about to perform step 3
long long solve(long long current_x_1_indexed, long long current_y, bool is_step2) {
    // Termination condition check
    if (current_x_1_indexed <= 0 || current_x_1_indexed > N_global) {
        return current_y;
    }

    // Convert 1-indexed x to 0-indexed array index
    int x_idx = static_cast<int>(current_x_1_indexed - 1);
    int parity = is_step2 ? 0 : 1; // 0 for step 2, 1 for step 3

    // Check memoization table
    if (memo_state[x_idx][parity] == 1) { // Cycle detected
        return -1;
    }
    if (memo_state[x_idx][parity] == 2) { // Already computed
        return memo_res[x_idx][parity];
    }

    // Mark as currently visiting
    memo_state[x_idx][parity] = 1;

    long long val = a_values[x_idx];
    long long next_y = current_y + val;
    long long result;

    if (is_step2) {
        // Perform step 2: x = x + val, y = y + val
        // Next step will be step 3
        result = solve(current_x_1_indexed + val, next_y, false);
    } else {
        // Perform step 3: x = x - val, y = y + val
        // Next step will be step 2
        result = solve(current_x_1_indexed - val, next_y, true);
    }

    // Store result and mark as computed
    memo_res[x_idx][parity] = result;
    memo_state[x_idx][parity] = 2;

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    // Resize a_values to hold n elements (0-indexed a_0 to a_{n-1})
    a_values.resize(n);

    // Read a_2, ..., a_n into a_values[1], ..., a_values[n-1]
    for (int i = 1; i < n; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize memoization tables
    // Size N_global for x_idx (0 to N_global-1)
    // Size 2 for parity (0 for step 2, 1 for step 3)
    memo_res.resize(N_global, std::vector<long long>(2));
    memo_state.resize(N_global, std::vector<int>(2));

    // Iterate for each starting value of a_1 (from 1 to n-1)
    for (int i = 1; i < n; ++i) {
