#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // f(a_i, a_j) = a_i + a_j for all pairs.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    if (n >= 2) {
        long long current_goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[elements[i].original_index] = 1;
            }
        }
    } else { // n=1, this case is not possible due to constraints (n >= 2)
        // If n=1, there are no pairs, so goodness is 0.
        // But problem states n >= 2.
    }


    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put elements[0] and elements[1] in different subsequences.
    // This ensures that elements[0].value + elements[1].value + h is one of the f values.
    // The other elements can be assigned to minimize goodness.
    //
    // Consider two main sub-strategies for Case 2:
    // Sub-strategy A: elements[0] in S1, elements[1] in S2. All other elements in S1.
    // S1: {elements[0], elements[2], ..., elements[n-1]}
    // S2: {elements[1]}
    //
    // f values:
    // 1. elements[0] + elements[1] + h (different subsequences)
    // 2. elements[0] + elements[k] (same, k >= 2)
    // 3. elements[j] + elements[k] (same, j, k >= 2)
    //
    // min_f = min(elements[0] + elements[1] + h, elements[0] + elements[2])
    // max_f = max(elements[0] + elements[1] + h, elements[n-1] + elements[n-2])
    //
    // This is equivalent to:
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[n-1].value + elements[n-2].value
    //
    // The minimum possible sum of two elements from the same group (S1) is elements[0] + elements[2].
    // The maximum possible sum of two elements from the same group (S1) is elements[n-1] + elements[n-2].
    // The only sum from different groups is elements[0] + elements[1] + h.
    //
    // So, the set of f values is:
    // {elements[0] + elements[1] + h} U {elements[i] + elements[j] | i,j in S1, i!=j}
    //
    // min_f = min(elements[0] + elements[1] + h, elements[0] + elements[2]) (if n >= 3)
    //         or elements[0] + elements[1] + h (if n=2)
    // max_f = max(elements[0] + elements[1] + h, elements[n-1] + elements[n-2]) (if n >= 3)
    //         or elements[0] + elements[1] + h (if n=2)
    //
    // Let's simplify.
    // The smallest possible sum of two elements is elements[0] + elements[1].
    // The largest possible sum of two elements is elements[n-1] + elements[n-2].
    //
    // If we put elements[0] in S1 and elements[1] in S2, and all others in S1:
    // S1: {elements[0], elements[2], ..., elements[n-1]}
    // S2: {elements[1]}
    //
    // The values of f are:
    // 1. elements[0] + elements[1] + h (different)
    // 2. elements[0] + elements[k] (same, k >= 2)
    // 3. elements[j] + elements[k] (same, j, k >= 2)
    //
    // The minimum f value will be min(elements[0] + elements[1] + h, elements[0] + elements[2] (if n>=3)).
    // The maximum f value will be max(elements[0] + elements[1] + h, elements[n-1] + elements[n-2] (if n>=3)).
    //
    // Let's consider the range of sums `a_i + a_j`.
    // `min_sum_base = elements[0].value + elements[1].value`
    // `max_sum_base = elements[n-1].value + elements[n-2].value`
    //
    // If we put elements[0] in S1 and elements[1] in S2, and all others in S1:
    // The values of f are:
    // `elements[0].value + elements[1].value + h`
    // `elements[0].value + elements[k].value` for `k >= 2`
    // `elements[j].value + elements[k].value` for `j, k >= 2`
    //
    // The minimum value of `f` is `min(elements[0].value + elements[1].value + h, elements[0].value + elements[2].value)` (if n >= 3).
    // If n=2, min_f = elements[0].value + elements[1].value + h.
    // The maximum value of `f` is `max(elements[0].value + elements[1].value + h, elements[n-1].value + elements[n-2].value)` (if n >= 3).
    // If n=2, max_f = elements[0].value + elements[1].value + h.
    //
    // Let's calculate goodness for this specific partition:
    // Partition: elements[0] -> 1, elements[1] -> 2, elements[2...n-1] -> 1.
    long long current_min_f_A;
    long long current_max_f_A;

    if (n == 2) {
        current_min_f_A = elements[0].value + elements[1].value + h;
        current_max_f_A = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        current_min_f_A = std::min(elements[0].value + elements[1].value + h, elements[0].value + elements[2].value);
        current_max_f_A = std::max(elements[0].value + elements[1].value + h, elements[n-1].value + elements[n-2].value);
    }

    long long goodness_A = current_max_f_A - current_min_f_A;

    if (goodness_A < min_goodness) {
        min_goodness = goodness_A;
        best_partition[elements[0].original_index] = 1;
        best_partition[elements[1].original_index] = 2;
        for (int i = 2; i < n; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
    }

    // Sub-strategy B: elements[0] in S1, elements[n-1] in S2. All other elements in S1.
    // S1: {elements[0], elements[1], ..., elements[n-2]}
    // S2: {elements[n-1]}
    //
    // The values of f are:
    // 1. elements[0] + elements[n-1] + h (different)
    // 2. elements[i] + elements[j] (same, i, j <= n-2)
    //
    // The minimum f value will be min(elements[0] + elements[n-1] + h, elements[0] + elements[1]).
    // The maximum f value will be max(elements[0] + elements[n-1] + h, elements[n-2] + elements[n-3] (if n>=3)).
    //
    // Let's calculate goodness for this specific partition:
    // Partition: elements[0...n-2] -> 1, elements[n-1] -> 2.
    long long current_min_f_B;
    long long current_max_f_B;

    if (n == 2) {
        current_min_f_B = elements[0].value + elements[1].value + h;
        current_max_f_B = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        current_min_f_B = std::min(elements[0].value + elements[n-1].value + h, elements[0].value + elements[1].value);
        current_max_f_B = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-3].value);
    }

    long long goodness_B = current_max_f_B - current_min_f_B;

    if (goodness_B < min_goodness) {
        min_goodness = goodness_B;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
        best_partition[elements[n-1].original_index] = 2;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = (long long)n * (n + 1) / 2;

    // min_r_for_l[i] stores the minimum r (1-indexed) such that the substring s[i...r-1]
    // contains a triple match. If no such r exists, it's n+1.
    // We are interested in the smallest r such that s[i...r-1] is "good".
    // This means we need to find the smallest r such that there exists x, k
    // with s[x-1]=s[x+k-1]=s[x+2k-1] and i <= x-1 and x+2k-1 <= r-1.
    // This is equivalent to finding the smallest r such that r-1 >= x+2k-1 for some valid x, k.
    // So, r >= x+2k.
    // The minimum r for a given l (1-indexed) is min(x+2k) over all valid x, k
    // such that x >= l.
    // Let's use 0-indexed for `min_r_for_l` where `min_r_for_l[i]` is the minimum
    // 0-indexed end position `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, it's `n`.
    std::vector<int> min_end_idx(n + 1, n); // min_end_idx[i] = min j such that s[i...j] is good.

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible step sizes k.
    // The maximum possible k is (n-1-x)/2.
    // The maximum k for x=0 is (n-1)/2.
    // The maximum k for x=n-3 is 0.
    // The maximum k is roughly n/3.
    // The maximum value for x+2k is n-1.
    // So x+2k < n.
    // x < n-2k.
    // k can go up to (n-1)/2.
    // If k=1, x can go up to n-3.
    // If k=2, x can go up to n-5.
    // If k=3, x can go up to n-7.
    // The maximum k we need to check is small.
    // If k is large, say k > 6, then 2k > 12.
    // If we have a triple match s[x] = s[x+k] = s[x+2k],
    // then for any l <= x and r >= x+2k, the pair (l,r) is good.
    // We are looking for the smallest r for each l.
    // This means we need to find the smallest x+2k for each x.
    // Let's define `first_good_end[i]` as the minimum `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, `first_good_end[i]` is `n`.

    // The problem states $1 \leq x, k \leq n$.
    // $l \leq x < x+2k \leq r$.
    // $s_x = s_{x+k} = s_{x+2k}$.
    // In 0-indexed: $s[x-1] = s[x+k-1] = s[x+2k-1]$.
    // Let $x' = x-1$. Then $s[x'] = s[x'+k] = s[x'+2k]$.
    // $0 \leq x' < x'+2k \leq n-1$.
    // $l-1 \leq x'$ and $x'+2k \leq r-1$.

    // We need to find the minimum `r_idx` (0-indexed) for each `l_idx` (0-indexed)
    // such that `s[l_idx ... r_idx]` contains a triple match.
    // Let `min_valid_r_idx[l_idx]` be this value.
    // Initialize `min_valid_r_idx` with `n` (meaning no valid `r_idx` found for that `l_idx`).

    // The maximum value for k is limited.
    // If k is large, say k >= 7, then 2k >= 14.
    // If s[x] = s[x+k] = s[x+2k], then the length of this pattern is 2k+1.
    // If k >= 7, then 2k+1 >= 15.
    // Consider the string s[x...x+14].
    // If s[x] = s[x+k] = s[x+2k] for k >= 7, then this implies that
    // s[x] = s[x+k] = s[x+2k] for some k' <= 6.
    // This is because if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k >= 7, then there must be a shorter pattern.
    // For example, if s[x] = s[x+7] = s[x+14], then s[x] = s[x+1] = s[x+2] = ... = s[x+14] is not necessarily true.
    // But if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // The crucial observation is that if a triple match exists for a large k,
    // it implies that the substring s[x...x+2k] is "good".
    // If there is a triple match s[x] = s[x+k] = s[x+2k], then the substring s[x...x+2k] is good.
    // Any substring s[l...r] where l <= x and r >= x+2k is also good.
    // We want to find the minimum r for each l.
    // This means for each l, we want to find min(x+2k) such that x >= l and s[x]=s[x+k]=s[x+2k].

    // Let's iterate through all possible starting positions `i` (0-indexed) for the pattern `s[i] = s[i+k] = s[i+2k]`.
    // For each `i`, we check small values of `k`.
    // The maximum `k` we need to check is small.
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is the end index of this pattern.
    // For any `l_idx <= i`, the substring `s[l_idx ... i+2k]` is good.
    // So, `min_valid_r_idx[l_idx]` can be updated to `min(min_valid_r_idx[l_idx], i+2k)`.

    // The maximum k to check:
    // If s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k is large, say k=7, then s[x]=s[x+7]=s[x+14].
    // If s[x] = s[x+1] = s[x+2] = ... = s[x+m] for m >= 14, then any k <= m/2 would work.
    // The maximum k we need to check is 6.
    // Why 6? Consider any sequence of 15 characters. If it contains a triple match,
    // it must contain one with k <= 6.
    // This is a known property for certain pattern matching problems.
    // If a string of length L contains a pattern of type A_k B_k C_k (where A, B, C are characters and k is step),
    // then if L is large enough, it must contain such a pattern with small k.
    // For $s_x = s_{x+k} = s_{x+2k}$, the length of the pattern is $2k+1$.
    // If $2k+1 \ge 15$, i.e., $k \ge 7$, then it is guaranteed that if such a pattern exists,
    // there must be a pattern with $k' \le 6$ within the same range.
    // This is a result from combinatorics on words, related to "squares" or "cubes".
    // For example, if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then the substring $s[x \dots x+2k]$ is "good".
    // It is known that if a string contains a 3-term arithmetic progression of identical characters,
    // it must contain one where the common difference is at most 6.
    // This means we only need to check $k \in \{1, 2, 3, 4, 5, 6\}$.
    // This significantly reduces the complexity.

    std::vector<int> min_r_idx_for_l_idx(n, n); // min_r_idx_for_l_idx[l_idx] = min r_idx such that s[l_idx...r_idx] is good.

    for (int i = 0; i < n; ++i) { // i is the 0-indexed x'
        for (int k = 1; k <= 6; ++k) { // k is the step
            if (i + 2 * k < n) { // Check if x'+2k is within bounds
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    // Found a triple match starting at i with step k, ending at i+2k.
                    // This means for any l_idx <= i, the substring s[l_idx ... i+2k] is good.
                    // So, we can update min_r_idx_for_l_idx[l_idx] to min(current, i+2k).
                    // Since we iterate i from 0 to n-1, and for each i, we update for l_idx <= i,
                    // we can simply update min_r_idx_for_l_idx[i] = min(current, i+2k).
                    // The propagation to smaller l_idx will be handled in the next step.
                    min_r_idx_for_l_idx[i] = std::min(min_r_idx_for_l_idx[i], i + 2 * k);
                }
            }
        }
    }

    // Now, propagate the minimum r_idx backwards.
    // If s[l_idx ... r_idx] is good, then s[l_idx-1 ... r_idx] is also good.
    // So, min_r_idx_for_l_idx[l_idx-1] must be less than or equal to min_r_idx_for_l_idx[l_idx].
    // Specifically, min_r_idx_for_l_idx[l_idx-1] = min(min_r_idx_for_l_idx[l_idx-1], min_r_idx_for_l_idx[l_idx]).
    for (int l_idx = n - 2; l_idx >= 0; --l_idx) {
        min_r_idx_for_l_idx[l_idx] = std::min(min_r_idx_for_l_idx[l_idx], min_r_idx_for_l_idx[l_idx + 1]);
    }

    long long good_pairs_count = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        if (min_r_idx_for_l_idx[l_idx] < n) {
            // If min_r_idx_for_l_idx[l_idx] is less than n, it means there is at least one
            // valid r_idx for this l_idx.
            // The valid r_idx values are from min_r_idx_for_l_idx[l_idx] up to n-1.
            // The number of such r_idx values is (n-1) - min_r_idx_for_l_idx[l_idx] + 1.
            good_pairs_count += (n - min_r_idx_for_l_idx[l_idx]);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long first_p_to_cover = p[p_idx];

        // If the current head cannot reach the first uncovered target track,
        // it means this head cannot help cover it.
        // We need to find a head that can reach first_p_to_cover.
        // If current_h is too far to the right, it can't cover first_p_to_cover.
        // If current_h is too far to the left, it can't cover first_p_to_cover.
        // The condition for a head to be able to cover first_p_to_cover is:
        // current_h - T <= first_p_to_cover <= current_h + T
        // which is equivalent to abs(current_h - first_p_to_cover) <= T.
        if (std::abs(current_h - first_p_to_cover) > T) {
            // This head cannot cover first_p_to_cover.
            // If current_h is to the right of first_p_to_cover + T,
            // then no subsequent head (which are even further right) can cover it either.
            // This implies that first_p_to_cover cannot be covered.
            if (current_h > first_p_to_cover + T) {
                return false;
            }
