    std::vector<int> right_balance_suffix(n + 1, 0); // right_balance_suffix[i] = balance of jars 2n-i+1 to 2n
    for (int i = 0; i < n; ++i) {
        right_balance_suffix[i + 1] = right_balance_suffix[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain balance for the remaining left jars.
    // Key: balance of remaining left jars
    // Value: number of jars removed from left (k)
    std::map<int, int> left_remaining_balance_to_removed_count;

    // Iterate through possible number of jars removed from left (k)
    // k can be from 0 to n.
    // If k jars are removed, jars 1 to k are gone.
    // Remaining jars are k+1 to n.
    // Balance of remaining left jars = left_balance_prefix[n] - left_balance_prefix[k]
    for (int k = 0; k <= n; ++k) {
        int current_remaining_left_balance = left_balance_prefix[n] - left_balance_prefix[k];
        if (left_remaining_balance_to_removed_count.find(current_remaining_left_balance) == left_remaining_balance_to_removed_count.end()) {
            left_remaining_balance_to_removed_count[current_remaining_left_balance] = k;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from right (m)
    // m can be from 0 to n.
    // If m jars are removed, jars 2n-m+1 to 2n are gone.
    // Remaining jars are n+1 to 2n-m.
    // Balance of remaining right jars = right_balance_suffix[n] - right_balance_suffix[m]
    // Note: right_balance_suffix[i] is balance of jars 2n-i+1 to 2n.
    // So, right_balance_suffix[n] is balance of jars n+1 to 2n.
    // And right_balance_suffix[m] is balance of jars 2n-m+1 to 2n.
    // The balance of remaining right jars (n+1 to 2n-m) is right_balance_suffix[n] - right_balance_suffix[m].

    for (int m = 0; m <= n; ++m) {
        int current_remaining_right_balance = right_balance_suffix[n] - right_balance_suffix[m];

        // We need total balance to be 0.
        // So, balance_remaining_left + balance_remaining_right = 0
        // This means balance_remaining_left = -balance_remaining_right
        int target_left_balance = -current_remaining_right_balance;

        if (left_remaining_balance_to_removed_count.count(target_left_balance)) {
            int k = left_remaining_balance_to_removed_count[target_left_balance];
            min_removed_jars = std::min(min_removed_jars, k + m);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

