    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form '1' (from "one"): requires 'o', 'n', 'e'
    // To form '0' (from "zero"): requires 'z', 'e', 'r', 'o'

    // Maximize the number by having as many '1's as possible first.
    // The number of '1's is limited by the count of 'n', 'o', 'e'.
    int num_ones = count_n; // 'n' is unique to "one" among 'n', 'z', 'r'

    // After forming 'num_ones' "one"s, we use:
    // num_ones 'n's
    // num_ones 'o's
    // num_ones 'e's

    // Remaining letters for "zero"s:
    // count_z
    // count_e - num_ones
    // count_r
    // count_o - num_ones

    // The number of '0's is limited by 'z', 'e', 'r', 'o'
    // Since 'z' and 'r' are unique to "zero", we can directly count 'z's.
    int num_zeros = count_z;

