#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[n - 1] != b[n - 1]) {
        std::cout << "NO\n";
        return;
    }

    // Iterate from right to left (n-2 down to 0)
    // This allows us to check conditions for a[i] based on the state of a[0...i-1]
    // before a[i] itself is considered for modification.
    // The has_pos_one and has_neg_one flags track if a 1 or -1 exists in a[0...i]
    // which can be used to modify a[j] for j > i.
    // When we process a[i], we need to know if a 1 or -1 exists in a[0...i-1].
    // So, we update the flags *after* checking a[i].

    // Re-initialize flags for the actual check, as the initial scan was just for the first element.
    has_pos_one = false;
    has_neg_one = false;
    if (a[0] == 1) has_pos_one = true;
    if (a[0] == -1) has_neg_one = true;

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element.
        // The existing has_pos_one/has_neg_one flags are sufficient.

        // Update flags for the next iteration (i+1)
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

