                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] is not n, then there must be some p[k] > p[i].
        // In that case, a[i][k] = min(p[i], p[k]) = p[i].
        // So, max_val_in_row would be at least p[i].
        // If p[i] is the largest value in the permutation (n), then for all j != i, p[j] < p[i].
        // Thus, a[i][j] = p[j]. The maximum of these p[j] values would be n-1.
        // So, if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is the maximum value found in its row (excluding a[i][i]).
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

