#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i.
            // Check if q_i has already been used.
            if (used_numbers.count(q[i])) {
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some value less than or equal to q_{i-1}
            // and not yet used. To maximize chances, pick the smallest available number.
            // The smallest available number must be less than q_i (which is q_{i-1}).
            // If we pick a number equal to q_i, it would have to be q_i itself, but q_i
            // is already the maximum of p_1...p_{i-1}, so it must have been used.
            // So p_i must be strictly less than q_i.

            // Find the smallest unused number.
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            // If the smallest unused number is greater than q_i, then no valid p_i exists.
            // This is because p_i must be <= q_i, and all numbers <= q_i are either used
            // or are greater than the smallest available number.
            if (current_val > q[i]) {
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

