int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the number of cells for a staircase with k stairs
            // This is k * (k + 1) / 2
            // However, k here is 2^p - 1.
            // The actual number of stairs is (2^p - 1).
            // The cost for a staircase with (2^p - 1) stairs is (2^p - 1) * (2^p) / 2.
            // Let m = 2^p - 1. Then the cost is m * (m + 1) / 2.
            // The sequence of costs for nice staircases is:
            // p=1, k=1: cost = 1 * 2 / 2 = 1
            // p=2, k=3: cost = 3 * 4 / 2 = 6
            // p=3, k=7: cost = 7 * 8 / 2 = 28
            // p=4, k=15: cost = 15 * 16 / 2 = 120
            // The cost for the next nice staircase is (2*k + 1) * (2*k + 2) / 2.
            // This is (2k+1)(k+1).
            // Let's use the formula for the cost of a nice staircase with (2^p - 1) stairs.
            // Cost_p = (2^p - 1) * (2^p) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of costs is 1, 6, 28, 120, ...
            // The next k is 2*k + 1.
            // The cost for the staircase with k stairs is k * (k + 1) / 2.
            long long cost_for_k_stairs = k * (k + 1) / 2;

            if (current_cost + cost_for_k_stairs <= x) {
                current_cost += cost_for_k_stairs;
                count++;
                // Calculate the next k.
                // k_next = 2 * k_current + 1.
                // Check for overflow before multiplying.
                // k_current can be up to 2^62 - 1 (approx 4.6e18).
                // 2 * k_current + 1 can exceed long long max if k_current > LLONG_MAX / 2.
                // LLONG_MAX is approx 9e18.
                // If k is around 4.5e18, 2*k+1 will overflow.
                // The maximum x is 10^18.
                // The costs are 1, 6, 28, 120, 496, 2016, 8128, 32640, 130816, 523776, 2096128, 8386560, 33550336, 134209536, 536854528, 2147450880, 8589869056, 34359607296, 137438691328, 549755681280, 2199022800896, 8796091877376, 35184366086144, 140737479009280, 562949949532672, 2251799813685248, 9007199194004480, 36028797018963968, 144115187000000000 (approx 1.44e17).
                // The next cost would be for k = 2 * (3.6e17) + 1, which is approx 7.2e17.
                // The sum of costs can reach x = 10^18.
                // The largest k for which cost_for_k_stairs <= 10^18 is when k * (k+1)/2 <= 10^18.
                // k^2/2 approx 10^18 => k^2 approx 2*10^18 => k approx sqrt(2)*10^9 approx 1.4 * 10^9.
                // The k values are 1, 3, 7, ..., 2^p - 1.
                // If k is 1.4 * 10^9, then 2*k+1 is 2.8 * 10^9, which fits in long long.
                // The cost for k=2^p-1 is (2^p-1)*2^p/2.
                // If 2^p-1 is approx 1.4*10^9, then 2^p is approx 1.4*10^9.
                // p is approx log2(1.4*10^9) approx log2(10^9) + log2(1.4) approx 9*log2(10) + 0.5 approx 9*3.32 + 0.5 approx 29.88 + 0.5 approx 30.38.
                // So p can go up to around 30.
                // 2^30 - 1 is approx 10^9.
                // The next k would be 2*(2^30-1)+1 = 2^31-1. This is fine.
                // The cost for 2^31-1 stairs is (2^31-1)*2^31/2. This is approx (2*10^9)*(2*10^9)/2 = 2*10^18.
                // This cost alone might exceed x.
                // So k will not overflow.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

