int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // We can only add a ')' if it doesn't make the balance negative
            // and we still need closing brackets.
            // Also, we must ensure we don't add more ')' than '('.
            // The condition `balance > 0` ensures it's a valid closing bracket for some open bracket.
            // The condition `close_count < k / 2` ensures we don't exceed the target count.
            // The condition `balance > close_count` ensures we have enough open brackets to match.
            // A simpler way: if we have open brackets to close (balance > 0)
            // AND we still need closing brackets (close_count < k/2)
            // AND adding this closing bracket won't make the total length exceed k
            // (which is implicitly handled by open_count + close_count < k)
            // AND we haven't used all our open_count yet (balance > 0)
            if (balance > 0 && close_count < k / 2) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count + close_count == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

