void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to include m.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index among {pos[1], ..., pos[m]}
        // to the maximum index among {pos[1], ..., pos[m]}.

        // Update current_min_idx and current_max_idx to include pos[m]
        // These variables track the span of indices for numbers 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the segment containing all numbers from 1 to m is (current_max_idx - current_min_idx + 1).
        // If this length is exactly m, then all numbers from 1 to m are present
        // and no other numbers are present in this segment.
        // This is because the numbers 1 to m are distinct, and if their span is exactly m,
        // it means they occupy exactly m positions without gaps or other numbers.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

