    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Mismatch at index i
            // Check if there's an adjacent mismatch that can be swapped
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // If a[i] != b[i] and a[i+1] != b[i+1]
                // AND a[i] != a[i+1] (meaning a[i] and a[i+1] are different bits)
                // Then swapping a[i] and a[i+1] will fix both mismatches.
                // Example: a = "01", b = "10"
                // a[i]=0, b[i]=1; a[i+1]=1, b[i+1]=0
                // a[i] != a[i+1] is true (0 != 1)
                // Swapping a[i] and a[i+1] makes a = "10", which matches b.
                // Cost is |i - (i+1)| = 1.
                cost += 1;
                i += 2; // Both i and i+1 are resolved
            } else {
                // No adjacent swap possible or beneficial.
                // Must flip a[i]. Cost is 1.
                cost += 1;
                i += 1; // Only i is resolved
            }
        } else {
            // No mismatch at index i, move to the next.
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

