        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        //
        // We need to partition 2n students into two classes, C1 and C2,
        // such that |C1| is odd and |C2| is odd.
        // Let |C1| = 2k1+1 and |C2| = 2k2+1.
        // (2k1+1) + (2k2+1) = 2n
        // 2k1 + 2k2 + 2 = 2n
        // k1 + k2 + 1 = n
        //
        // The median of C1 (size 2k1+1) is its (k1+1)-th smallest element.
        // The median of C2 (size 2k2+1) is its (k2+1)-th smallest element.
        //
