#include <algorithm> // For std::upper_bound

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the first point of a potential triplet (x_i)
    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find points x[j] and x[k] such that i < j < k
        // and x[k] - x[i] <= d.
        // This means x[k] <= x[i] + d.

        // Find the rightmost index 'k_max_idx' such that x[k_max_idx] <= x[i] + d.
        // std::upper_bound returns an iterator to the first element greater than (x[i] + d).
        // So, we need to decrement the iterator to get the last element less than or equal to (x[i] + d).
        // The search range for k is from i+1 to n-1.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The elements from x[i+1] up to *(it-1) are potential candidates for x[j] or x[k].
        // The number of such candidates is (it - x.begin()) - (i + 1).
        // Let this count be 'num_candidates'.
        // These candidates are at indices from (i+1) to (it - x.begin() - 1).

        // If it points to x.begin() + i + 1, it means no element in the range is <= x[i] + d.
        // In this case, num_candidates would be 0 or negative, which is handled correctly.

        // The index of the last valid point for k is (it - x.begin() - 1).
        // Let's call this index 'k_upper_bound_idx'.
        // All points x[j] and x[k] must be chosen from the range [x[i+1], ..., x[k_upper_bound_idx]].
        // The number of points in this range is (k_upper_bound_idx - (i+1) + 1).
        // Let m be the number of points available after x[i] that satisfy the distance condition.
        // m = (it - x.begin()) - (i + 1);
        // These 'm' points are x[i+1], x[i+2], ..., x[i+m].
        // We need to choose 2 points from these 'm' points to form x[j] and x[k].
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (it - x.begin()) - (i + 1);

        if (m >= 2) { // We need at least 2 points (for x_j and x_k)
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th element of the sorted A (a_elements[i].value)
    // should be paired with the (m-1-i)-th element of the sorted B (b_elements[m-1-i].value)
    // This pairing maximizes F(A'_i, B_i) because F(n, k) is increasing in n and decreasing in k.
    // So, largest A values should be paired with smallest B values.
    // The original index of b_elements[m-1-i] tells us where this pair should go in the output.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The value a_elements[i].value (which is the i-th smallest A value)
        // should be placed at the position corresponding to b_elements[m-1-i].original_index
        // because b_elements[m-1-i] is the (m-1-i)-th smallest B value,
        // which means it's the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, Opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, next turn opponent takes 1.
            } else if ((n / 2) % 2 != 0) { // N is even, N/2 is odd
                // If Chanek takes N/2, remaining N/2 is odd. Opponent takes 1.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // In both cases, opponent will take 1.
                // Chanek wants to maximize his coins.
                // Taking N/2 gives Chanek N/2 coins.
                // Taking 1 gives Chanek 1 coin.
                // Since N > 2, N/2 > 1. So Chanek takes N/2.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even, N/2 is even
                // If Chanek takes N/2, remaining N/2 is even. Opponent can take (N/2)/2 = N/4.
                // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                // Chanek wants to maximize his coins.
                // Taking N/2 gives Chanek N/2 coins.
                // Taking 1 gives Chanek 1 coin.
                // Since N > 2, N/2 > 1. So Chanek takes N/2.
                chanek_coins += n / 2;
                n /= 2;
            }
        }

        if (n == 0) {
            break;
        }

        // Opponent's turn (optimal play for opponent)
        if (n % 2 != 0) { // N is odd
            n -= 1;
        } else { // N is even
            if (n == 2) {
                n -= 1;
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                n /= 2;
            } else { // N/2 is even
                n /= 2;
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

