// Function to solve a single test case
void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Count occurrences of R, S, P in the bot's string s
    int countR = 0;
    int countS = 0;
    int countP = 0;
    for (char ch : s) {
        if (ch == 'R') {
            countR++;
        } else if (ch == 'S') {
            countS++;
        } else { // ch == 'P'
            countP++;
        }
    }

    // Determine which choice (R, S, or P) would win against the most frequent bot move
    // If bot plays R, we play P to win.
    // If bot plays S, we play R to win.
    // If bot plays P, we play S to win.

    // We want to maximize wins.
    // If we play P, we win against R. Wins = countR.
    // If we play R, we win against S. Wins = countS.
    // If we play S, we win against P. Wins = countP.

    // Find the maximum count among countR, countS, countP
    int max_wins_against_single_move = 0;
    char optimal_player_move = ' ';

    if (countR >= max_wins_against_single_move) {
        max_wins_against_single_move = countR;
        optimal_player_move = 'P'; // P beats R
    }
    if (countS >= max_wins_against_single_move) {
        max_wins_against_single_move = countS;
        optimal_player_move = 'R'; // R beats S
    }
    if (countP >= max_wins_against_single_move) {
        max_wins_against_single_move = countP;
        optimal_player_move = 'S'; // S beats P
    }

    // The optimal strategy is to always play the move that beats the most frequent bot move.
    // This is because for any given round k, our choice c_k will be compared against
    // each s_j exactly once across all n possible starting positions for the bot.
    // So, if we choose c_k = 'P', it will win against 'R' exactly countR times,
    // lose against 'S' exactly countS times, and draw against 'P' exactly countP times.
    // The total number of wins is maximized by picking the move that beats the most frequent bot move.
    // Since we want to maximize the average, and the average is (total wins) / n,
    // maximizing total wins is equivalent to maximizing the average.
    // And since each c_k contributes independently to the total wins,
    // we should make each c_k the optimal_player_move.

    for (int i = 0; i < n; ++i) {
        std::cout << optimal_player_move;
    }
    std::cout << std::endl;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w to handle w_i=1 first, then w_i>1

    long long total_happiness = 0;

    // First, handle friends who get w_i = 1 integer.
    // They should get the largest available integers, as their happiness is 2 * integer.
    // These are the k largest integers from 'a'.
    int a_ptr_large = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_large];
            a_ptr_large--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here and handle them in the next loop.
            break;
        }
    }

    // Now, handle friends who get w_i > 1 integers.
    // For these friends, happiness is max_val + min_val.
    // To maximize this, they should get the largest remaining available integers as their max_val.
    // The smallest available integers should be used as their min_val.
    // The w_i values are sorted, so w[0] is the smallest w_i > 1.
    // We iterate through w from smallest w_i to largest w_i (excluding w_i=1 already handled).

    int a_ptr_small = 0; // Pointer for the smallest available integers
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // The largest remaining integer for this friend's max_val
            total_happiness += a[a_ptr_large];
            a_ptr_large--;

            // The smallest available integer for this friend's min_val
            // This friend needs w[i] integers. One is the max_val (a[a_ptr_large+1]),
            // one is the min_val (a[a_ptr_small]), and w[i]-2 integers in between.
            // We use the smallest available a[a_ptr_small] for min_val.
            // Then we skip w[i]-2 integers from the small end.
            total_happiness += a[a_ptr_small];
            a_ptr_small += (w[i] - 1); // Move pointer past the w[i]-1 smallest integers used
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Otherwise, we need to append elements.
    // We can always append 2 elements: current_xor_sum and current_sum + current_xor_sum.
    // Let's verify this strategy.
    // New elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum S' = current_sum + b1 + b2
    //            = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //            = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum X' = current_xor_sum ^ b1 ^ b2
    //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                = 0 ^ (current_sum + current_xor_sum)
    //                = current_sum + current_xor_sum
    //
    // We need S' = 2 * X'.
    // Is (2 * current_sum + 2 * current_xor_sum) == 2 * (current_sum + current_xor_sum)?
    // Yes, this is always true.
    //
    // The problem states we can append at most 3 elements.
    // This strategy uses 2 elements.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
    // The problem statement says b_i can be up to 10^18, so this is fine.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' will eventually be
            // moved past by all 'a's to its left.
            // Each 'a' to its left will effectively duplicate this 'b'
            // when it moves past it.
            // So, the number of 'a's that will eventually pass this 'b'
            // will double the number of 'b's that are effectively "available"
            // for future 'a's to pass.
            // This is equivalent to saying that each 'a' to the left of this 'b'
            // will contribute `(current_count_of_b_blocks + 1)` steps.
            // The `count_a` variable represents the number of 'a's that are
            // currently "active" and need to pass 'b's.
            // When an 'a' passes a 'b', it consumes one 'b' and creates two 'b's.
            // This means the number of 'b's available for the next 'a' effectively doubles.
            // So, if we have `count_a` 'a's, and we encounter a 'b',
            // these `count_a` 'a's will each take `count_a` steps to pass this 'b'.
            // No, this is not right.
            // Let's re-evaluate:
            // When we see a 'b', it means any 'a's to its left will eventually
            // interact with it.
            // The number of 'a's that are currently "active" (i.e., `count_a`)
            // will each need to pass this 'b'.
            // Each such 'a' passing this 'b' costs 1 step.
            // So, `count_a` steps are added to `total_steps`.
            // After these `count_a` 'a's pass this 'b', this 'b' effectively
            // turns into `2 * count_a` 'b's (one for each 'a' that passed it,
            // plus the original 'b' which is now duplicated for each 'a').
            // This means the number of 'a's that are "active" for the next 'b'
            // (to its left) effectively doubles.
            // So, `count_a` becomes `2 * count_a`.

            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' needs to pass
            // all the 'b's that are currently "active" to its right.
            // The `count_a` variable represents the number of 'a's that
            // are currently "active" and need to pass 'b's.
            // When we see a new 'a', it adds itself to this pool of active 'a's.
            // So, `count_a` increments.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the string produced by our w
    for (int i = 0; i < n; ++i) {
        // s_prime[i] is '1' if w[i-x] is '1' OR w[i+x] is '1'
        bool possible_from_left = (i - x >= 0 && w[i - x] == '1');
        bool possible_from_right = (i + x < n && w[i + x] == '1');

        if (possible_from_left || possible_from_right) {
            s_prime[i] = '1';
        }
    }

    // Step 3: Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

