#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long operations = 0;
    int consecutive_in_place = 0; // Counts how many dolls form a consecutive sequence 1, 2, 3, ...
                                  // that are already correctly nested.

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Check if this chain starts with '1' and continues consecutively
        if (m > 0 && chain[0] == 1) {
            int current_val = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_val) {
                    consecutive_in_place++;
                    current_val++;
                } else {
                    // The consecutive sequence 1, 2, ... is broken in this chain
                    // Any further elements in this chain or other chains won't extend it.
                    break;
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all existing chains that are not part of the 1->2->...->consecutive_in_place sequence.
    //    Each doll not part of this sequence needs to be taken out of its container.
    //    The number of dolls that are NOT part of the 1->2->...->consecutive_in_place sequence is n - consecutive_in_place.
    //    Each of these n - consecutive_in_place dolls needs to be "freed" from its current nesting.
    //    Consider the total number of existing nestings: n - k.
    //    The number of "correct" nestings (i.e., i in i+1) that are part of the 1->2->...->consecutive_in_place sequence is consecutive_in_place - 1.
    //    So, the number of nestings that need to be undone is (n - k) - (consecutive_in_place - 1).
    //    This simplifies to n - k - consecutive_in_place + 1.
    //    However, a simpler way to think about it:
    //    We have 'k' chains. To get 'n' individual dolls, we need to perform 'n - k' un-nesting operations.
    //    For example, 1->2->3 is 1 chain, 3 dolls, 2 nestings. To get 3 individual dolls, we need 2 un-nestings.
    //    So, total un-nesting operations to get all dolls free: n - k.
    //    But we don't need to un-nest the `consecutive_in_place - 1` correct nestings (1 in 2, 2 in 3, ...).
    //    So, operations to disassemble: (n - k) - (consecutive_in_place - 1).
    //    This is (n - k - consecutive_in_place + 1).

    // 2. Assemble the final chain 1->2->...->n.
    //    This requires n - 1 nesting operations.
    //    However, `consecutive_in_place - 1` of these are already done.
    //    So, operations to assemble: (n - 1) - (consecutive_in_place - 1).
    //    This is (n - consecutive_in_place).

    // Total operations = (disassemble operations) + (assemble operations)
    // Total operations = (n - k - consecutive_in_place + 1) + (n - consecutive_in_place)
    // Total operations = 2 * n - k - 2 * consecutive_in_place + 1

    // Let's re-evaluate.
    // The number of dolls that are NOT part of the 1->2->...->consecutive_in_place sequence is n - consecutive_in_place.
    // Each of these dolls must be "freed" from its current nesting (if any) and then re-nested.
    // Each doll that is not 1, 2, ..., consecutive_in_place must be taken out of its current container (1 operation)
    // and then put into its new container (1 operation).
    // So, for each of the (n - consecutive_in_place) dolls, it costs 2 operations.
    // Total: 2 * (n - consecutive_in_place).

    // What about the chains themselves?
    // We have 'k' chains. We want to end up with 1 chain.
    // This means we need to "merge" k-1 chains.
    // Each merge operation involves taking the first doll of one chain and putting it into the last doll of another chain.
    // This is effectively one "put" operation.
    // So, k-1 operations to merge the chains.

    // Let's use the example: 7 3, chains: 1 3 7, 2 5, 4 6
    // n=7, k=3
    // consecutive_in_place = 1 (only doll 1 is correct)
    //
    // Disassemble:
    // Total existing nestings: n - k = 7 - 3 = 4.
    // Correct nestings (1 in 2, 2 in 3, ...): consecutive_in_place - 1 = 1 - 1 = 0.
    // Nestings to undo: 4 - 0 = 4.
    //
    // Assemble:
    // Total required nestings: n - 1 = 7 - 1 = 6.
    // Already correct: 0.
    // Nestings to perform: 6 - 0 = 6.
    //
    // Total = 4 + 6 = 10. This matches the example.

    // Let's use the first example: 3 2, chains: 1 2, 3
    // n=3, k=2
    // consecutive_in_place = 2 (dolls 1 and 2 are correct: 1 in 2)
    //
    // Disassemble:
    // Total existing nestings: n - k = 3 - 2 = 1 (1 in 2).
    // Correct nestings (1 in 2, 2 in 3, ...): consecutive_in_place - 1 = 2 - 1 = 1 (1 in 2).
    // Nestings to undo: 1 - 1 = 0.
    //
    // Assemble:
    // Total required nestings: n - 1 = 3 - 1 = 2 (1 in 2, 2 in 3).
    // Already correct: 1 (1 in 2).
    // Nestings to perform: 2 - 1 = 1 (2 in 3).
    //
    // Total = 0 + 1 = 1. This matches the example.

    // The formula seems to be:
    // (n - k - (consecutive_in_place - 1)) + (n - 1 - (consecutive_in_place - 1))
    // = (n - k - consecutive_in_place + 1) + (n - consecutive_in_place)
    // = 2 * n - k - 2 * consecutive_in_place + 1

    operations = (long long)(n - k - (consecutive_in_place - 1)) + (long long)(n - 1 - (consecutive_in_place - 1));

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for 'x', 'y', 'z' counts
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The algorithm terminates if all 3-character substrings are permutations of "xyz".
        // This means the counts of 'x', 'y', 'z' in the substring must be "balanced" enough
        // such that we can form a string where all 3-char substrings are "xyz" permutations.
        // The most balanced state is when counts are as close as possible.
        // For example, if counts are (c_x, c_y, c_z), then max(c_x, c_y, c_z) - min(c_x, c_y, c_z) <= 1.
        // If this condition holds, we can always rearrange the entire substring to form a string
        // where all 3-char substrings are "xyz" permutations (e.g., "xyzxyz...").
        // In such a string, all 3-char substrings are "zyx", "xzy", or "yxz", and the algorithm terminates.
        // If this condition does not hold, it means there's a significant imbalance.
        // For example, if count_x = 5, count_y = 1, count_z = 1.
        // We can form "xyzzxxx". The substring "xxx" is not "zyx", "xzy", or "yxz".
        // We can pick "xxx", rearrange it (it remains "xxx"), and the algorithm continues indefinitely.
        // The only way to guarantee termination is if we can reach a state where all 3-char substrings
        // are permutations of 'x', 'y', 'z'. This is possible if and only if the counts of 'x', 'y', 'z'
        // in the *entire* substring are "balanced" enough.
        // Specifically, the difference between the maximum and minimum count of any character
        // must be at most 1.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

