    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long val_L = 1;

        while (!dq_L.empty() && dq_L.back().first >= current_h) {
            dq_L.pop_back();
        }

        if (!dq_L.empty()) {
            val_L = std::max(val_L, dq_L.back().first + (i - dq_L.back().second));
        }

        L[i] = val_L;
        dq_L.push_back({current_h, i});
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_h = h[i];
        long long val_R = 1;

        while (!dq_R.empty() && dq_R.back().first >= current_h) {
            dq_R.pop_back();
        }

        if (!dq_R.empty()) {
            val_R = std::max(val_R, dq_R.back().first + (dq_R.back().second - i));
        }

        R[i] = val_R;
        dq_R.push_back({current_h, i});
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min({h[i], L[i], R[i]}));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

