    // `left_map[balance]` stores the minimum number of jars removed from the left
    // to achieve that `balance`.
    // `left_map[left_prefix_balance[i]] = i` means removing `i` jars from the left
    // (jars `0` to `i-1`) leaves jars `i` to `n-1` with balance `left_prefix_balance[i]`.
    // This is not quite right.
    // Let's define `left_map[balance]` as the minimum number of jars *kept* on the left
    // to achieve that balance.
    // If we remove `i` jars from the left (jars `0` to `i-1`), we keep `n-i` jars.
    // The balance of these `n-i` jars is `left_prefix_balance[n] - left_prefix_balance[i]`.
    // The number of jars removed is `i`.
    // We want to find `left_map[balance_of_kept_left_part] = num_removed_from_left`.
    // `left_map[left_prefix_balance[n] - left_prefix_balance[i]] = i`
    // This means if we remove `i` jars from the left, the remaining `n-i` jars have balance `left_prefix_balance[n] - left_prefix_balance[i]`.
    // The number of jars removed is `i`.
    std::map<int, int> left_removed_count; // map: balance_of_remaining_left_part -> num_removed_from_left
    // Case 1: Remove `i` jars from the left (jars 0 to i-1).
    // Remaining left part is jars `i` to `n-1`.
    // Its balance is `left_prefix_balance[n] - left_prefix_balance[i]`.
    // Number of removed jars is `i`.
    for (int i = 0; i <= n; ++i) { // `i` is the count of jars removed from the left (0 to n)
        int current_left_balance = left_prefix_balance[n] - left_prefix_balance[i];
        if (left_removed_count.find(current_left_balance) == left_removed_count.end()) {
            left_removed_count[current_left_balance] = i;
        } else {
            left_removed_count[current_left_balance] = std::min(left_removed_count[current_left_balance], i);
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible removals from the right side
    // `j` is the count of jars removed from the right (0 to n)
    // If we remove `j` jars from the right (jars `2n-j` to `2n-1`),
    // the remaining right part is jars `n` to `2n-j-1`.
    // Its balance is `right_suffix_balance[n] - right_suffix_balance[2n-j]`.
    for (int j = 0; j <= n; ++j) {
        int current_right_balance = right_suffix_balance[n] - right_suffix_balance[2 * n - j];

        // We want the final total balance to be 0.
        // `(initial_balance - balance_of_removed_left - balance_of_removed_right) = 0`
        // `balance_of_remaining_left + balance_of_remaining_right = 0`
        // `balance_of_remaining_left = -balance_of_remaining_right`

        // The balance of the remaining part of the whole array is:
        // `(left_prefix_balance[n] - left_prefix_balance[i]) + (right_suffix_balance[n] - right_suffix_balance[2n-j])`
        // We need this to be 0.
        // So, `balance_of_remaining_left = -current_right_balance`.

        int target_left_balance = -current_right_balance;

        if (left_removed_count.count(target_left_balance)) {
            int removed_from_left = left_removed_count[target_left_balance];
            min_removed = std::min(min_removed, removed_from_left + j);
        }
    }

    std::cout << min_removed << std::endl;
}

