#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the m+1 potential blocks
        // created by the m ones (or m-1 ones if we consider ones as separators).
        // The optimal configuration places ones such that the blocks of zeros are as short as possible.
        // This means distributing the 'num_zeros' zeros into 'm+1' potential segments.
        // However, the 'm' ones act as separators. If we have 'm' ones, they divide the string into 'm+1'
        // possible segments where zeros can be placed.
        // For example, 10101 has 3 ones and 2 zeros. The zeros are in 2 segments.
        // 01010 has 2 ones and 3 zeros. The zeros are in 3 segments.
        // The key insight is that to minimize zero-only substrings, we want to make the blocks of zeros
        // as small as possible. This means distributing the 'num_zeros' zeros as evenly as possible
        // into 'm+1' segments (before the first '1', between '1's, and after the last '1').
        // The 'm' ones effectively create 'm+1' "slots" for zeros.
        // For example, _ 1 _ 1 _ ... _ 1 _
        // The number of zeros is `num_zeros`.
        // We distribute these `num_zeros` into `m+1` slots.
        // This is equivalent to distributing `num_zeros` items into `m+1` bins.
        // Some bins will have `k` zeros, and some will have `k+1` zeros.
        // Let `k = num_zeros / (m + 1)` be the base number of zeros in each segment.
        // Let `r = num_zeros % (m + 1)` be the number of segments that get an additional zero.
        // So, `r` segments will have `k+1` zeros, and `(m+1) - r` segments will have `k` zeros.

        // However, this is not quite right. The problem is about minimizing the number of zero-only substrings.
        // This is achieved by making the blocks of zeros as short as possible.
        // The 'm' ones divide the 'n' positions into 'm' ones and 'n-m' zeros.
        // The 'm' ones effectively create 'm-1' internal gaps and 2 external gaps (before first '1', after last '1').
        // The total number of '0's is `num_zeros`.
        // We want to distribute these `num_zeros` into `m+1` "slots" (before the first '1', between any two '1's, after the last '1').
        // The number of '0's in each slot should be as equal as possible.
        // Let `q = num_zeros / (m + 1)` be the quotient.
        // Let `rem = num_zeros % (m + 1)` be the remainder.
        // So, `rem` slots will have `q + 1` zeros, and `(m + 1) - rem` slots will have `q` zeros.

        // The number of substrings consisting only of zeros from a block of `k` zeros is `k * (k + 1) / 2`.
        // So, the total number of zero-only substrings is:
        // `rem * ((q + 1) * (q + 2) / 2)`  (for segments with q+1 zeros)
        // `+ ((m + 1) - rem) * (q * (q + 1) / 2)` (for segments with q zeros)

        // This is the correct approach for minimizing zero-only substrings.
        // Let `k` be the number of blocks of zeros.
        // If `m > 0`, the `m` ones divide the string into at most `m+1` blocks of zeros.
        // For example, "01010" (n=5, m=2). Zeros: 3. Blocks: 3. (0, 0, 0).
        // q = 3 / (2+1) = 1. rem = 0. All 3 blocks have 1 zero.
        // 3 * (1 * 2 / 2) = 3.
        // Total substrings = 5*6/2 = 15. f(s) = 15 - 3 = 12. Matches example.

        // Example: n=3, m=1. Zeros: 2. Blocks: 1+1=2.
        // q = 2 / 2 = 1. rem = 0. All 2 blocks have 1 zero.
        // 2 * (1 * 2 / 2) = 2.
        // Total substrings = 3*4/2 = 6. f(s) = 6 - 2 = 4. Matches example.

        // Example: n=3, m=2. Zeros: 1. Blocks: 2+1=3.
        // q = 1 / 3 = 0. rem = 1.
        // 1 block has 1 zero. 2 blocks have 0 zeros.
        // 1 * (1 * 2 / 2) + 2 * (0 * 1 / 2) = 1.
        // Total substrings = 3*4/2 = 6. f(s) = 6 - 1 = 5. Matches example.

        long long q = num_zeros / (m + 1);
        long long rem = num_zeros % (m + 1);

        long long zero_substrings_count = 0;
        // Segments with q+1 zeros
        zero_substrings_count += rem * ((q + 1) * (q + 2) / 2);
        // Segments with q zeros
        zero_substrings_count += ((m + 1) - rem) * (q * (q + 1) / 2);

        long long max_f_s = total_substrings - zero_substrings_count;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

