    std::vector<int> right_ones(n, 0);

    // Calculate left_ones: distance to the nearest 1 on the left (inclusive)
    // If a[i] is 1, left_ones[i] = 0. If a[i] is 0, left_ones[i] = left_ones[i-1] + 1.
    // If no 1 on left, it's effectively infinity.
