        // dist[0][0] = min(0, dist[0][0]+dist[0][0]) = min(0, 0+0) = 0
        // dist[0][1] = min(5, dist[0][0]+dist[0][1]) = min(5, 0+5) = 5
        // dist[1][0] = min(4, dist[1][0]+dist[0][0]) = min(4, 4+0) = 4
        // dist[1][1] = min(0, dist[1][0]+dist[0][1]) = min(0, 4+5) = 0 (This is the problem. dist[1][1] should be 0, not 9)
        //
        // The issue is that `dist[i][k] + dist[k][j]` is used.
        // If `i=1, k=0, j=1`, then `dist[1][0] + dist[0][1]` is `4+5=9`.
        // `dist[1][1]` is `0`. `min(0, 9)` is `0`. This is correct for `dist[i][i]`.
        //
        // The example output for n=2 is `9 0`.
        // Before removing 1 (vertex 0): active {0,1}. d(0,1)=5, d(1,0)=4. Sum = 5+4=9.
        // Before removing 2 (vertex 1): active {1}. Sum = 0.
        //
        // My trace for k_idx=0 (adding vertex 0):
        // After adding vertex 1 (k=1), active_vertices = [F, T]. Sum = 0. results = [0]
        //
        // Now add vertex 0 (k=0). active_vertices = [T, T].
        //
        // Floyd-Warshall step with k=0:
        // dist[i][j] = min(dist[i][j], dist[i][0] + dist[0][j])
        //
        // dist[0][0] = min(dist[0][0], dist[0][0]+dist[0][0]) = min(0, 0+0) = 0
        // dist[0][1] = min(dist[0][1], dist[0][0]+dist[0][1]) = min(5, 0+5) = 5
        // dist[1][0] = min(dist[1][0], dist[1][0]+dist[0][0]) = min(4, 4+0) = 4
        // dist[1][1] = min(dist[1][1], dist[1][0]+dist[0][1]) = min(0, 4+5) = 0
        //
        // The dist matrix is still [[0,5],[4,0]].
        //
        // Calculate sum for active vertices: {0,1}
        // Sum = dist[0][1] + dist[1][0] = 5 + 4 = 9.
        // results.push_back(9)
        //
        // This matches the example output `9 0` if I reverse `results`.
        //
        // The logic seems correct. The `dist` matrix always stores the shortest paths
        // considering *all* vertices that have been processed as `k` in the outer loop.
        // When we iterate `k_idx` from `n-1` down to `0`, the `k = x[k_idx]` vertex
        // is effectively the `k` in the Floyd-Warshall algorithm.
        //
        // The `dist` matrix at any point `k_idx` will contain shortest paths between
        // *any* two vertices `i, j` using intermediate vertices from the set
        // `{x[k_idx], x[k_idx+1], ..., x[n-1]}`.
        //
        // So, after the Floyd-Warshall step for `k = x[k_idx]`, the `dist` matrix
        // is updated. Then, we sum `dist[i][j]` for all `i, j` where `active_vertices[i]`
        // and `active_vertices[j]` are true. This is exactly what's needed.

        // The Floyd-Warshall update for the current k
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Output results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a with a very large value.
    // This is because a[i] = initial_a[i] + current_add[i].
    // For a type 2 query max(a[j]) = m, it means initial_a[j] + current_add[j] <= m for all j in [l, r].
    // So, initial_a[j] <= m - current_add[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // The maximum possible value for initial_a[j] is the minimum of all (m - current_add[j]) constraints.
    // If no constraints apply, it can be 10^9.
    std::vector<long long> initial_a(n, 1000000000LL); // Max allowed initial value

    // Calculate the total 'd' applied to each element up to each operation.
    // This is needed to determine the constraints on initial_a.
    // current_add[j] stores the sum of d's applied to a[j] *before* the current operation.
    std::vector<long long> current_add(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d.
            // This operation affects future type 2 queries.
            // We don't update initial_a here, but we update current_add.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_add[j] += ops[i].val;
            }
        } else {
            // Type 2: Max of a[j] in [l, r] must be m.
            // This means for all j in [l, r], a[j] <= m.
            // Since a[j] = initial_a[j] + current_add[j],
            // we have initial_a[j] + current_add[j] <= m.
            // So, initial_a[j] <= m - current_add[j].
            // We update initial_a[j] to be the minimum of its current value and (m - current_add[j]).
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_add[j]);
            }
        }
    }

    // Now we have a candidate initial_a array.
    // We need to verify if it satisfies all type 2 queries.
    // Simulate the operations with this initial_a.
    std::vector<long long> simulated_a = initial_a;
    std::fill(current_add.begin(), current_add.end(), 0); // Reset current_add for simulation

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                simulated_a[j] += ops[i].val;
                current_add[j] += ops[i].val; // Keep track of total d applied for verification
            }
        } else {
            // Type 2: Max of a[j] in [l, r] must be m.
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, simulated_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
