struct Child {
    long long v;
    long long d;
    long long p;
    int original_index;
    bool is_removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].is_removed = false;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].is_removed) {
            continue;
        }

        // Child i goes to the doctor
        treated_children_indices.push_back(children[i].original_index);
        children[i].is_removed = true;

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0; // Accumulates d_j from children crying in the hall

        for (int j = i + 1; j < n; ++j) {
            if (children[j].is_removed) {
                continue;
            }

            // Apply accumulated d_cry from previous children who ran away
            children[j].p -= accumulated_d_cry;

            // Apply v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].is_removed = true;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

